(6152, 791, 906, 'حسابدار', NULL, 'فنی مهندسی آتیه الکترونیک فولاد ایرانیان', NULL, NULL, NULL, NULL, '09193540678', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '30 تا 40 میلیون تومان', NULL, 'بیمه,بیمه تکمیلی,پاداش و هدایا,وام سازمانی', NULL, '<p>حداقل مدرک کارشناسی حسابداری<br>حداقل 5 سال سابقه کار<br>تسلط به حسابداری مالی&nbsp;<br>تسلط به نرم‌افزارهای حسابداری سپیدار Word، Excel<br>انجام کلیه امور حسابداری<br>تسلط به محاسبات حقوق و دستمزد و تهیه لیست بیمه و مالیات بر حقوق<br>تسلط به سامانه مودیان و انجام امور مربوطه<br><br><br><br>&nbsp;</p><p>&nbsp;</p><p><strong>تسهیلات و مزایا</strong><br><br>بیمه<br>&nbsp;بیمه تکمیلی&nbsp;<br>حقوق ثابت<br><br><strong>محل کار</strong><br>تهران، منطقه ۶، فاطمی<br><br>*<strong>متولدین سال 1369 الی 1375</strong><br><br>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 تا 5 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'سپیدار', 'خوب', 'خوب', 'خوب', 'نیاز نیست', NULL, NULL, NULL, NULL, NULL, NULL, 1, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-15 11:02:33', '2025-11-16 00:00:02'),
(6181, 823, 908, 'حسابدار', NULL, 'مجموعه خدماتی', NULL, NULL, NULL, NULL, '09360478767', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'قانون کار', NULL, 'بیمه,پاداش و هدایا', NULL, '<p>استخدام نیروی حسابدار</p><p>&nbsp;با تسلط به نرم‌افزار حسابداری محک&nbsp;</p><p>ساعت کاری: 8 تا 15&nbsp;</p><p>سابقه کار: حداقل 2 سال</p><p>سن : حداکثر 35 سال</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'محک', 'متوسط', 'کم', 'کم', 'کم', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-15 11:07:10', '2025-11-18 00:00:01'),
(6315, 870, 933, 'حسابدار', NULL, 'شرکت فولادسازان معدن یار آروین', NULL, NULL, NULL, NULL, '09152359802', NULL, '167', 'چناران', '11', 'خراسان رضوی', 'تمام وقت', 'قانون کار', 0, 'سرویس رفت و برگشت,پاداش و هدایا,وام سازمانی', NULL, '<p>استخدام حسابدار در کارخانه ریخته گری</p><p>📌 ما به یک حسابدار خانم برای پیوستن به تیم خود نیازمندیم:</p><p>✅ شرایط احراز:</p><p>• تسلط کامل به ماهیت حسابها<br>.دارای حداقل ۲سال سابقه کار حسابداری&nbsp;<br>• سن: ۲۲ تا ۳۵ سال</p><p>• ساعات کاری: &nbsp;۷ الی ۱۵</p><p>• متعهد، منظم و دقیق</p><p>💼 مزایا:<br>• حقوق طبق قانون کار و به‌موقع<br>• محیط کاری پویا و حرفه‌ای<br>• امنیت شغلی بالا<br>.بسته های معیشتی بابت مناسبتها<br>.سرویس ایاب ذهاب از گلبهار و چناران<br>.وام پرسنلی</p><p>📍 موقعیت مکانی: شهرک صنعتی چناران ابتدای بلوار نوآوری</p><p>📲 لطفاً جهت هماهنگی برای مصاحبه حضوری، رزومه خود را به پی‌وی ارسال کنید</p><p><br>09152359802</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'خانم', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-05 09:11:50', '2025-11-05 00:00:01'),
(6325, 880, 935, 'حسابدار', NULL, 'زرین ستاره مسما', NULL, NULL, NULL, NULL, '09155076897', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'قانون کار', 0, 'بیمه,سرویس رفت و برگشت', NULL, '<p>آشنایی با نرم‌افزارهای حسابداری<br>آشنایی با اصول و استانداردهای حسابداری<br>مهارت در تهیه گزارش‌های مالی<br>آشنایی با قوانین مالیاتی و آشنایی با سامانه جامع و مودیان</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 سال و کمتر', NULL, 'خانم', NULL, NULL, 'پایا', 'خیلی خوب', 'خوب', 'خوب', 'نیاز نیست', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-05 11:33:12', '2025-11-05 00:00:01'),
(6334, 883, 936, 'حسابدار', NULL, 'پیشگامان پلاستیک خراسان', NULL, NULL, NULL, NULL, '09155116106', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', '15 تا 20 میلیون تومان', 4, 'بیمه,بیمه تکمیلی,وام سازمانی', NULL, '<p>ساعت کار 8 تا 15:30</p><p>پرداخت منظم و بموقع</p><p>بیمه از روز اول</p><p>بیمه تکمیلی</p><p>فضای کار مناسب</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'سپیدار', 'متوسط', 'کم', 'کم', 'نیاز نیست', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-06 14:49:50', '2025-11-06 00:00:01'),
(6336, 877, 938, 'حسابدار', NULL, 'کشت و صنعت کاریزان کیا', NULL, NULL, NULL, NULL, '09359454421', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '15 تا 20 میلیون تومان', 4, 'بیمه', NULL, '<p>دارای مدرک تحصیلی مرتبط</p><p>دارای حداقل 1 سال سابقه کار</p><p>آشنایی با نرم افزار سپیدار</p><p>ثبت اسناد حسابداری</p><p>ورود اطلاعات در سامانه جامع تجارت، سامانه جامع انبارها، سامانه مودیان</p><p>دارای دقت و پشتکار بالا در پیگیری امور</p><p>دارای دقت بالا در امور بایگانی</p><p>منظم، متعهد و مسئولیت پذیر</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 سال و کمتر', NULL, NULL, NULL, NULL, 'سپیدار', 'متوسط', 'نیاز نیست', 'نیاز نیست', 'نیاز نیست', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-07 08:20:40', '2025-11-07 00:00:01'),
(6338, 884, 939, 'حسابدار', NULL, 'پیشرو حمل کالا', NULL, NULL, NULL, NULL, '09127777610', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', 1, 'بیمه,بیمه تکمیلی,وام سازمانی', NULL, '<ol><li>&nbsp;ثبت اسناد روزانه&nbsp;</li><li>&nbsp;تهیه گزارش</li><li>&nbsp;آماده کردن ارزش افزوده&nbsp;</li><li>معاملات فصلی و ….</li><li>&nbsp;متعهد و موظف</li></ol>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '1 سال', NULL, 'خانم', 'کاردانی', NULL, 'سپیدار', 'متوسط', 'متوسط', 'کم', 'کم', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-07 10:07:10', '2025-11-07 00:00:01'),
(6346, 887, 940, 'حسابدار', NULL, 'مجتمع فولاد کاویان', NULL, NULL, NULL, NULL, '09153065105', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', 1, 'بیمه,سرویس رفت و برگشت,ناهار', NULL, '<p>حسابدار تولید&nbsp;</p><p>آشنا به سامانه مودیان ، بیمه ، حقوق و دستمزد و مالیات</p><p>ساعت کاری: 8 تا 16</p><p>آدرس: شهرک صنعتی کاویان</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'حداقل 5 سال', NULL, 'آقا', 'کارشناسی', NULL, NULL, NULL, 'عالی', 'عالی', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-07 10:55:23', '2025-11-07 00:00:01'),
(6347, 888, 941, 'حسابدار', NULL, 'مجتمع سینمایی اطلس', NULL, NULL, NULL, NULL, '09152005105', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'قانون کار', 0, '', NULL, '<p>آشنا به سامانه مودیان ، بیمه ، حقوق و دستمزد ، مالیات</p><p>ترجیحا مسلط به نرم افزار تدبیر</p><p>محیط کار مناسب خانم ها</p><p>ساعت کاری: 8 الی 14</p><p>آدرس: مجتمع سینمایی اطلس</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'خانم', 'کارشناسی', NULL, 'تدبیر', NULL, 'عالی', 'عالی', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-07 12:30:46', '2025-11-09 00:00:02'),
(6364, 894, 944, 'حسابدار', NULL, 'فراز فنون مرکزی', NULL, NULL, NULL, NULL, '09188488253', NULL, '117', 'تهران', '8', 'تهران', 'پاره وقت', 'توافقی', 1, 'بیمه,ناهار,پاداش و هدایا', NULL, '<p>شرکت فراز فنون مرکزی جهت تکمیل کادر خود در واحد حسابداری از افراد واجد شرایط زیر دعوت به همکاری می‌نماید.</p><ul><li>جنسیت: خانم</li><li>حداکثر سن 40 سال</li><li>دارای حداقل مدرک تحصیلی کارشناسی حسابداری</li><li>دارای حداقل دو سال سابقه کار مرتبط</li><li>آشنایی کامل با نرم‌افزار مالی سپیدار یا همکاران سیستم</li><li>آشنایی کامل با قوانین و بخشنامه‌های مالیاتی و بیمه</li><li>آشنایی کامل با سامانه‌ها و سایت‌های مرتبط با مالیات و بیمه</li><li>آشنایی کامل با سامانه مودیان</li><li>آشنایی با تحریر دفاتر فیزیکی و الکترونیک</li><li>آشنایی کامل با نرم‌افزارهای آفیس (به ویژه Word و Excel)</li><li>دارای هوش و دقت و تمرکز بسیار بالا</li><li>دارای ذهن و روحیه خلاق</li><li>دارای روابط عمومی بالا</li><li>مهارت در تهیه گزارش‌های مالی</li><li>توانایی تحلیل و تفسیر داده‌های مالی</li></ul>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'خانم', 'کارشناسی', NULL, 'سپیدار', 'خوب', 'خیلی خوب', 'خیلی خوب', 'خوب', NULL, NULL, NULL, NULL, NULL, NULL, 1, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-05 12:53:51', '2025-11-25 14:55:59'),
