(6377, 900, 948, 'حسابدار', NULL, 'سپهر تجارت اتحاد البرز', NULL, NULL, NULL, NULL, '09014650035', NULL, '283', 'کرج', '5', 'البرز', 'تمام وقت', 'توافقی', 1, 'بیمه', NULL, '<p>شرکت سپهر تجارت اتحاد البرز به عنوان یکی از مجموعه های فعال در حوزه &nbsp;بازرگانی (واردات و صادرات) با هدف تکمیل کادر مالی خود از افراد برای همکاری دعوت به عمل می آورد.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 تا 5 سال', NULL, 'خانم', NULL, NULL, 'هلو', 'خوب', 'خوب', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-11 13:08:25', '2025-11-11 00:00:02'),
