(6388, 903, 951, 'حسابدار', NULL, 'مدیریت سرمایه گذاری کوثر بهمن', NULL, NULL, NULL, NULL, '09115962977', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '45 تا 50 میلیون تومان', 10, 'بیمه,بیمه تکمیلی,پاداش و هدایا,وام سازمانی,پزشک سازمانی', NULL, '<p>1-آشنایی و تسلط کامل بر نرم افزار های مالی، جبران خدمات، دفتر کل، مدیریت دارایی، دریافت و پرداخت همکاران سیستم (راهکاران )</p><p>2-آشنایی و تسلط کامل به قوانین مالیاتی، کار و تامین اجتماعی</p><p>3-دارای تجربه در تهیه گزارش های حسابداری&nbsp;</p><p>ساعت کاری : شنبه تا چهارشنبه 7:45 لغایت 16:15</p><p>آدرس محل کار : خیابان مطهری ،خیابان میرعماد بن بسته نهم پلاک1</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 تا 5 سال', NULL, 'مهم نیست', 'کارشناسی ارشد', NULL, 'همکاران سیستم', 'عالی', 'عالی', 'عالی', 'عالی', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-12 14:01:42', '2025-12-10 00:00:02'),
(6389, 904, 952, 'رییس حسابداری', NULL, 'آرام گستران آوای جاوید', NULL, NULL, NULL, NULL, '09055301656', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', '25 تا 30 میلیون تومان', 6, 'بیمه,صبحانه', NULL, '<p>رییس حسابداری ،مسلط به حسابداری پیمانکاری ، امور مالیاتی (سامانه مودیان ، اظهارنامه ها و …) &nbsp;، بیمه و حقوق دستمزد&nbsp;</p><p>آدرس: بلوار وکیل آباد، فارغ التحصیلان&nbsp;</p><p>ساعت کاری: 7 الی 15:30</p><p>&nbsp;</p><p>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '7 تا 10 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'سپیدار', 'خیلی خوب', 'خیلی خوب', 'خیلی خوب', 'نیاز نیست', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-12 14:19:36', '2025-11-12 00:00:01'),
(6392, 905, 955, 'کمک حسابدار', NULL, 'ژیک پارسیان الکترونیک', NULL, NULL, NULL, NULL, '09127953298', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '15 تا 20 میلیون تومان', 4, 'بیمه,پاداش و هدایا', NULL, '<p>استخدام کمک حسابدار خانم مسلط به نرم افزار هوفر و شماران سیستم&nbsp;</p><p>حقوق ثابت ۱۷ + ۱ تومان پاداش +پاداش عملکرد کارکنان</p><p>با مدرک تحصیلی کاردانی حسابداری</p><p>مزایای سازمانی: بیمه ، پاداش و هدایا</p><p>ساعت کاری:۸٫۳۰ الی ۱۸ روزهای پنج شنبه و جمعه تعطیل و تعطیلات رسمی هم تعطیل</p><p>آدرس: خیابان جمهوری بعد از پل حافظ به سمت بهارستان بعد از سی تیر کوچه نوبهار ساختمان طوبی طبقه ۳واحد۷</p><p>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'نیاز نیست', NULL, 'خانم', 'کاردانی', NULL, 'هوفر', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-12 14:37:17', '2025-11-12 00:00:01'),
(6395, 906, 956, 'حسابدار', NULL, 'سهر نیرا نور', NULL, NULL, NULL, NULL, '09382020043', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', 1, 'بیمه,سرویس رفت و برگشت,پاداش و هدایا', NULL, '<h4>شرح وظایف و مسئولیت‌ها:</h4><p>صدور و ثبت فاکتورهای فروش در سیستم</p><p>کنترل و تطبیق اسناد مالی و ثبت‌های روزانه</p><p>تهیه، ثبت و بایگانی اسناد حسابداری</p><p>ثبت هزینه‌ها، دریافت‌ها و پرداخت‌ها</p><p>پیگیری امور مالی مرتبط با بخش فروش و انبار</p><p>تهیه گزارشات مورد نیاز سرپرست حسابداری</p><h4>مهارت‌ها:</h4><p>حداقل ۱ تا ۳ سال سابقه کار مرتبط در واحد مالی یا حسابداری</p><p>آشنایی با نرم‌افزارهای حسابداری (ترجیحاً اوراش)</p><p>تسلط نسبی به اِکسل و Office</p><p>آشنایی با مفاهیم پایه مالیات و بیمه</p><p>دقت بالا، مسئولیت‌پذیری، نظم در انجام امور و توانایی کار تیمی</p><h4>مزایا و محیط کاری:</h4><p>محیط کاری پویا، حرفه‌ای و صمیمی</p><p>امکان رشد شغلی و یادگیری تخصصی</p><p>همکاری نزدیک با تیم‌های طراحی، تولید و مدیریت در فضایی خلاق و ساختارمند<br><br><strong>محل کار :</strong><br>کیلومتر 16 جاده کلات 500 متر بالاتر از روستاي پاژ نرسیده به کمربند سبز سمت چپ<br><br><strong>ساعت کاری:</strong><br>&nbsp;7:00 الی 17:00</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '7 تا 10 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'اوراش(آرمون)', 'عالی', 'عالی', 'عالی', 'عالی', NULL, NULL, NULL, NULL, NULL, NULL, 1, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-13 10:05:56', '2025-12-13 00:00:01'),
(6406, 909, 957, 'حسابدار', NULL, 'آرتا پیوند اکسیر', NULL, NULL, NULL, NULL, '09126383152', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '30 تا 35 میلیون تومان', 7, 'بیمه,پاداش و هدایا', NULL, '<p>شرکت ما برای تکمیل کادر خود ، از فردی مسئول، علاقمند به یادگیری و انجام کارهای گروهی و فعالیت در محیطی سالم و صمیمی، با شرایط زیر دعوت به همکاری میکند:</p><p>حسابداری مسلط به قوانین روز</p><p>سامانه مودیان</p><p>حسابداری فروش و انبار</p><p>آشنا به بیمه و مالیات حقوق و دستمزد</p><p>حداقل سه سال سابقه ی کار</p><p>فعال و پویا<br><br>محل کار:&nbsp;<br>تهران ،منطقه22 ، بین میدان موج &nbsp;و ساحل ، بلوار علامه قزوینی ، برج اداری کنتراست ، طبقه 6 ، واحد 8</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 تا 5 سال', NULL, NULL, 'کارشناسی', NULL, 'سپیدار', 'خوب', 'عالی', 'خوب', 'متوسط', NULL, NULL, NULL, NULL, NULL, NULL, 1, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-14 14:17:45', '2025-11-21 00:00:01'),
(6423, 914, 960, 'حسابدار', NULL, 'پتروپالایش فردیس شیمی', NULL, NULL, NULL, NULL, '09309651165', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', '35 تا 40 میلیون تومان', 8, 'بیمه,سرویس رفت و برگشت,ناهار,وام سازمانی', NULL, '<p>شرایط احراز :<br>جهت کار در کارخانه تولیدی صنایع شیمیایی و نفتی در شهرک صنعتی کاویان (45 کیلومتری فریمان )&nbsp;<br>با سرویس و ایاب و ذهاب و ناهار و تعطیلی در پنج شنبه ها&nbsp;<br>آشنا با نرم افزار حسابداری سپیدار&nbsp;<br>جهت انجام امور مالیاتی&nbsp;<i> حقوق دستمزد&nbsp;</i> _ لیست تامین اجتماعی و …<br>&nbsp;ساعت کاری :<br>8 صبح الی 16:30 به صورت ثابت&nbsp;<br>&nbsp;حقوق : حداقل 25 میلیون &nbsp;تومان و حداکثر بسته به توانایی 40 میلیون تومان&nbsp;<br>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '1 سال', NULL, 'آقا', NULL, NULL, 'سپیدار', 'متوسط', 'متوسط', 'متوسط', 'متوسط', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-18 15:53:11', '2025-11-21 00:00:01'),
(6432, 917, 961, 'حسابدار', NULL, 'داناراهبرد به روش مانا', NULL, NULL, NULL, NULL, '09397598020', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '20 تا 25 میلیون تومان', 5, 'بیمه', NULL, '<p>حسابداری با حداقل 3 سال سابقه کار<br>مسلط به نرم افزار حسابداری<br>اکسل<br>سامانه مودیان<br>خرید و فروش فصلی<br>ارزش افزوده<br>لیست بیمه مالیات حقوق<br>بیمه -اضافه کار<br>امکان پیشرفت در کار و امور مالیاتی</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'صدگان', 'خوب', 'خوب', 'خوب', 'خوب', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-20 16:18:06', '2025-11-20 00:00:02'),
(6435, 921, 962, 'کمک حسابدار', NULL, 'بازرگانی مواد غذایی', NULL, NULL, NULL, NULL, '09125100685', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', '15 تا 20 میلیون تومان', 4, '', NULL, '<p><br>حداقل دو سال سابقه کار&nbsp;<br><br>مسلط به نرم افزار محک و اکسل&nbsp;<br><br>حقوق توافقی با توجه به تسلط ایشان به کار&nbsp;<br>روابط عمومی بالا<br>و روحیه کار تیمی&nbsp;&nbsp;<br><br>ساعت کاری: از ۸ صبح تا ۵ بعدازظهر&nbsp;<br><br>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'خانم', 'دیپلم', NULL, 'محک', 'خیلی خوب', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-22 12:22:52', '2025-11-25 12:23:25'),
(6438, 922, 963, 'کمک حسابدار', NULL, 'پخش سراسری طناز طلایی جنوب', NULL, NULL, NULL, NULL, '09151599455', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', '20 تا 25 میلیون تومان', 5, '', NULL, '<p>شرایط احراز:<br>کمک حسابدار پخش<br>تمام وقت<br>سابقه کار: حداقل دو سال پخش<br>جنسیت: مهم نیست<br>حداقل حقوق: ۲۰ م ت&nbsp;<br>مدرک تحصیلی: لیسانس<br>مزایای سازمان: حقوق و دستمزد عیدی و سنوات بالاتر از حد معمول<br>سابقه پخش تسلط به سرفصل های حسابداری آشنایی با سامانه مودیان و جامع تجارت<br>نرم افزار حسابداری مورد نیاز: ورانگر</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, NULL, 'کارشناسی', NULL, 'ورانگر', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-22 13:58:57', '2025-11-22 00:00:02'),
(6439, 923, 964, 'حسابدار', NULL, 'مدرن بتن پاژ', NULL, NULL, NULL, NULL, '09153161909', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', 1, 'بیمه', NULL, '<p>مسلط به حسابداری پیمانکاری&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'حسابان', 'متوسط', 'متوسط', 'متوسط', 'نیاز نیست', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-22 15:50:28', '2025-11-22 00:00:02'),
(6440, 924, 965, 'حسابرس', NULL, 'کارگزاری شعبه ۲', NULL, NULL, NULL, NULL, '09106967258', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', 1, 'بیمه,ناهار', NULL, '<p>نوع قرارداد: تمام وقت<br>سابقه کار: برای کسانی که کار حسابرسی بیمه ای انجام دادند الزامی و برای فارغ التحصیل رشته حسابداری و حسابرسی جویای کار مهم نیست<br>ساعات کاری :۸صبح تا۱۷&nbsp;<br>روزهای شنبه تا چهارشنبه<br>محل کار :نقاط مختلف تهران</p><p>شرایط احراز:<br>داشتن مدرک کارشناسی حسابداری یا حسابرسی&nbsp;</p><p>کارجویان تازه فارغ التحصیل رشته حسابداری و حسابرسی در الویت هستند</p><p>رده سنی ۲۲الی ۳۰سال<br>آشنایی با اکسل مقدماتی<br>اخلاق حرفه‌ای بالا<br>توانایی کار به صورت تیمی<br>دقت و توجه به جزئیات<br>کارآموزی همراه با آموزش حداقل سه ماه</p><p><br>تسهیلات و مزایا بعد دوره کارآموزی:<br>بیمه<br>حقوق ثابت</p><p>متقاضیان رزومه خود را به آیدی تلگرام@Hesabrasi404 ارسال کنند</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'نیاز نیست', NULL, 'خانم', NULL, NULL, NULL, 'متوسط', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-23 09:41:24', '2025-11-25 00:00:01'),
(6441, 925, 966, 'حسابدار', NULL, 'روبین', NULL, NULL, NULL, NULL, '09154157565', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', '20 تا 25 میلیون تومان', 5, 'بیمه', NULL, '<p>مسلط به حسابداری و سودو زیان و حواله حسابداری و کنترل فاکتورهای خرید و فروش<br>آدرس: تعبدی ۱۰ پلاک ۵/۲<br>حداقل حقوق: ۲۰م<br>ساعت کاری: ۸ الی ۱۶<br>نرم افزار حسابداری مورد نیاز: محک<br>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'نیاز نیست', NULL, 'مهم نیست', NULL, NULL, 'محک', 'خیلی خوب', 'خوب', 'خیلی خوب', 'خیلی خوب', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-24 12:00:53', '2025-11-24 00:00:02'),
(6442, 927, 967, 'مشاور مالی', NULL, 'گالری طلا و جواهر ارفعی', NULL, NULL, NULL, NULL, '09154124016', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'پاره وقت', 'توافقی', 1, '', NULL, '<p>گالری طلا و جواهر کاوه (ارفعی)</p><p>دعوت به همکاری از مشاورین مالی</p><p>آدرس: مشهد، خیابان مدرس، پاساژ کاوه، پلاک ۲ و ۶</p><p>نوع همکاری :پاره وقت&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'نیاز نیست', NULL, 'آقا', 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-25 14:27:46', '2025-11-25 00:00:01'),
(6451, 129, 972, 'کمک حسابدار', NULL, 'ثامن یدک', NULL, NULL, NULL, NULL, '09153109789', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'قانون کار', 0, 'صبحانه,وام سازمانی', NULL, '<p>کمک حسابدار :دقیق و منظم ، دارای توانایی کار تیمی و با اخلاق .</p><p>وظایف: ثبت فاکتور خرید و فروش، پیگیری مطالبات، بررسی مغایرات اشخاص و انبار.</p><p>مجموعه ما در شهرک صنعتی طرق مشهد واقع است و در زمینه ی قطعات خودروهای سنگین فعالیت داریم.</p><p>ساعت کاری 9 صبح الی 7 عصر.&nbsp;</p><p>امکان دریافت مزایا و همکاری طولانی مدت در صورت توافق طرفین موجود است.</p><p>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'آقا', 'کارشناسی', NULL, 'سیبا', 'متوسط', 'متوسط', 'متوسط', 'خوب', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 0, 0, 1, 1, 1, NULL, NULL, '2025-10-26 15:45:28', '2025-11-26 00:00:01'),
(6452, 129, 973, 'کمک حسابدار', NULL, 'ثامن یدک', NULL, NULL, NULL, NULL, '09153109789', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'قانون کار', 0, 'صبحانه,پاداش و هدایا', NULL, '<p>به کمک حسابدار منظم و دقیق، بااخلاق و دارای روحیه ی کار تیمی نیازمندیم.</p><p>وظایف: ثبت فاکتورهای خرید و فروش، بررسی مغایرات اجناس و اشخاص، پیگیری مطالبات.</p><p>پایه ی حقوق بر اساس قانون کار که باتوجه به توانایی شخص بیشتر خواهد شد.</p><p>امکان همکاری طولانی مدت همراه با مزایا درصورت توافق.</p><p>مجوعه ما در شهرک صنعتی طرق مشهد واقع است.</p><p>زمینه فعالیت ما فروش قطعات خودروهای سنگین است.</p><p>ساعت کاری 9 صبح الی 7 عصر، پنج شنبه ها تا ظهر.&nbsp;</p><p>شماره ی تماس: 09153109789 - درودی هستم.</p><p>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'آقا', 'کارشناسی', NULL, 'سیبا', 'متوسط', 'خوب', 'خوب', 'خوب', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 0, 0, 1, 1, 1, NULL, NULL, '2025-10-26 18:29:07', '2025-11-27 00:00:01'),
(6457, 929, 974, 'حسابدار', NULL, 'محاسب پرواز ماندگار', NULL, NULL, NULL, NULL, '09059902967', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', 1, '', NULL, '<p>آموزش تخصصی مالیات آژانس‌های هواپیمایی</p><p>حقوق منصفانه</p><p>امکان رشد سریع در محیط کاری حرفه‌ای</p><p>دقت و مسئولیت‌پذیری</p><p>علاقه به یادگیری و توسعه مهارت‌ها</p><p>روحیه کار تیمی</p><p><strong>شرایط احراز:</strong></p><p><strong>سابقه کار: حداقل ۱ سال</strong></p><p>مدرک تحصیلی: کارشناسی یا کاردانی حسابداری</p><p>بازه سنی: ۲۰ تا ۳۰ سال</p><p><strong>ساعات و محل کار:</strong></p><p>ساعت کاری: ۹:۰۰ الی ۱۷:۰۰</p><p>آدرس: سجاد ۲۴، پلاک ۴۴۲</p><p>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '1 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'تدبیر', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-27 11:48:49', '2025-11-29 00:00:01'),
(6460, 930, 975, 'حسابدار', NULL, 'همسفران مشهد', NULL, NULL, NULL, NULL, '09153903621', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', 1, '', NULL, '<p>آژانس هواپیمایی معتبر از یک حسابدار با دقت، علاقه به یادگیری و روحیه کار تیمی دعوت به همکاری می‌کند.<br>امکان آموزش تخصصی و عملی<strong> </strong>حسابداری و مالیات در کنار فعالیت شغلی فراهم است و حضور مدیر مالی، فرصت رشد حرفه‌ای را برای شما تضمین می‌کند.</p><p><strong>سابقه کار: حداقل ۱ سال</strong></p><p>مدرک تحصیلی: کارشناسی یا کاردانی حسابداری</p><p>ساعات و محل کار:</p><p>ساعت کاری: ۸:۰۰ تا ۱۶:۰۰</p><p>تعطیلات: جمعه‌ها و ایام شهادت / اعیاد به‌صورت شیفتی</p><p>آدرس: &nbsp;فلسطین ۱۸</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '1 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'تدبیر', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-27 11:58:05', '2025-12-02 00:00:02'),
(6461, 915, 976, 'حسابرس', NULL, 'نیوان مشاور اورامان', NULL, NULL, NULL, NULL, '09302127029', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', 1, 'بیمه', NULL, '<p>متعهد، دقیق و منظم در انجام وظایف، دارای حس مسئولیت بالا و رفتار محترمانه در محیط کار.</p><p>محیط حرفه ای و آموزش حرفه ای</p><p>ساعت کاری: 8 الی 16</p><p>آدرس: دندانپزشکان 13</p><p>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'نیاز نیست', NULL, 'مهم نیست', 'کارشناسی', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-27 14:50:04', '2025-11-27 00:00:01'),
(6462, 928, 977, 'حسابدار', NULL, 'تولیدی آهن پوش', NULL, NULL, NULL, NULL, '09122585405', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '25 تا 30 میلیون تومان', 6, 'بیمه,بیمه تکمیلی,ناهار,پاداش و هدایا,وام سازمانی', NULL, '<p>استخدام کمک حسابدار<br>&nbsp;مسلط به اکسل ، سیستم سپیدار&nbsp;<br>&nbsp;آشنا به سامانه جامع تجارت ، مودیان و امور حسابداری.<br>&nbsp;آدرس: حکیمیه خیابان باباییان کوچه دوم غربی پلاک ۱۶<br>ساعت کاری: &nbsp;۸ الی ۱۶/۳۰ &nbsp; &nbsp; محدوده شرق تهران</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 سال و کمتر', NULL, 'خانم', 'دیپلم', NULL, 'سپیدار', 'متوسط', 'متوسط', 'متوسط', 'متوسط', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-28 12:43:52', '2025-12-17 00:00:02'),
(6471, 932, 979, 'حسابدار', NULL, 'Gallent', NULL, NULL, NULL, NULL, '09027065714', NULL, '133', 'باقرشهر', '8', 'تهران', 'تمام وقت', 'توافقی', 1, 'بیمه,پاداش و هدایا', NULL, '<p>&nbsp;استخدام حسابدار در کارخانه پوشاک (باقرشهر – شهر ری)<br>یک کارخانه پوشاک معتبر در محدوده باقرشهر (شهر ری) به یک حسابدار باتجربه و دقیق نیاز دارد.</p><p>شرح وظایف و مهارت‌ها:<br>تسلط کامل به حقوق و دستمزد<br>&nbsp;قوانین کار و بیمه<br>&nbsp;توانایی تهیه صورت‌های مالی<br>گزارش‌های مدیریتی و بهای تمام‌شده<br>&nbsp;آشنایی با مباحث نقدینگی و کنترل هزینه‌ها<br>&nbsp;تسلط بر بستن حساب‌های سالانه و گزارشات سود و زیان<br>&nbsp;تسلط کامل به Excel و Word مخصوص حسابداری آشنایی با اصول دریافت و پرداخت<br>&nbsp;صدور چک و ثبت اسناد حسابداری&nbsp;<br>توانایی تهیه گزارش نقدینگی روزانه و چک‌لیست حساب‌ها&nbsp;<br><br>ویژگی‌های فردی:&nbsp;<br>دقیق، پیگیر و خوش‌برخورد دارای روحیه یادگیری و کار تیمی</p><p>ساعت کاری:&nbsp;<br>شنبه تا چهارشنبه: ۸:۳۰ تا ۱۸<br>پنج‌شنبه‌ها: ۸:۳۰ تا ۱۵&nbsp;<br><br>محل کار:<br>&nbsp;باقرشهر (شهر ری)</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'هلو', 'خیلی خوب', 'خیلی خوب', 'خیلی خوب', 'خیلی خوب', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-29 13:05:00', '2025-11-29 00:00:01'),
(6472, 931, 980, 'سرپرست حسابداری', NULL, 'شرکت مالی و مالیاتی مالی گستر', NULL, NULL, NULL, NULL, '09370855455', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '25 تا 30 میلیون تومان', 6, 'بیمه,پاداش و هدایا,وام سازمانی,سرانه آموزشی', NULL, '<p>استخدام حسابدار / سرپرست حسابداری در چند رده شغلی در شرکت خدمات مالی و مالیاتی مالی گستر:</p><p>&nbsp;مسلط به نرم افزار قیاس و هلو&nbsp;</p><p>حداقل نیازمند 2 سال سابقه کار</p><p>اشنایی به قوانین مالیاتی و بیمه&nbsp;</p><p>مسلط به جمع اوری رسیدگی و جمع بندی سیستم های مالی و مالیاتی</p><p>حقوق بنا بستگی به میزان تسلط شما از 25 میلیون به بالا</p><p>با حقوق و مزایا مناسب / بیمه / محل کار نزدیک به مترو و بی ار تی / محیط مناسب / پاداش / ترفیع و پیشرفت شغلی / آموزش و …</p><p>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'مهم نیست', NULL, NULL, 'قیاس', 'متوسط', 'متوسط', 'کم', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-29 13:40:46', '2025-11-29 00:00:01'),
(6492, 935, 1000, 'حسابدار', NULL, 'جلگه قلب باغستان', NULL, NULL, NULL, NULL, '09127647758', NULL, '134', 'شهریار', '8', 'تهران', 'تمام وقت', '20 تا 25 میلیون تومان', 5, 'بیمه', NULL, '<p>شرایط احراز:<br>جهت تکمیل کادر مالی خود به <strong>یک حسابدار خانم</strong> با شرایط زیر نیازمندیم<br>تسلط کامل به امور مالی، حسابداری و مالیاتی<br>نرم افزار مورد نیاز حسابداری: هلو و مودیان<br>سابقه کاری: 2 سال<br>ساعت کاری: 8 الی 17 &nbsp;پنجشنبه ها تا 14<br>آدرس: شهریار ، شهرک صنعتی بابا سلمان&nbsp;</p><p>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'خانم', 'کاردانی', NULL, 'هلو', 'خوب', 'خیلی خوب', 'خوب', 'خیلی خوب', NULL, NULL, NULL, NULL, NULL, NULL, 1, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-10-30 13:03:50', '2025-12-02 00:00:02'),
(6496, 938, 1004, 'حسابدار', NULL, 'زمزمه سفرطوس', NULL, NULL, NULL, NULL, '09374486016', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', 1, 'بیمه', NULL, '<p>کاربری این شرکت خدمات گردشگری و مسافرتی بلیت قطار هواپیما تور داخلی و خارجی میباشد.<br>نرم افزار حسابداری مورد نیاز:قصر رایانه و حسابداری اژانسی<br>آدرس: خیابان کاشانی بین کاشانی 4و6پلاک 80<br>ساعت کاری: 8 الی16<br>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'حداقل 5 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, NULL, 'خوب', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-01 14:16:49', '2025-12-09 00:00:02'),
(6498, 940, 1006, 'ناظر مالیاتی', NULL, 'مجتمع خدماتی رفاهی گردشگری هشت بهشت', NULL, NULL, NULL, NULL, '09151262711', NULL, '161', 'تربت جام', '11', 'خراسان رضوی', 'پاره وقت', 'توافقی', 1, '', NULL, '<p>شرایط احراز :<br>مشاوره مالیاتی ارزش افزوده و عملکرد مربوط &nbsp;<br>نوع همکاری : پاره وقت&nbsp;<br>آدرس :تربت جام ، کیلومتر 3 محور تربت جام و فریمان مجتمع خدماتی رفاهی گردشگری هشت بهشت&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '1 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, NULL, 'متوسط', 'خیلی خوب', 'متوسط', 'خوب', NULL, NULL, NULL, NULL, NULL, NULL, 1, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-02 07:48:59', '2025-12-09 00:00:02'),
(6499, 798, 1007, 'حسابدار', NULL, 'آرین راد شمال', NULL, NULL, NULL, NULL, '09113551499', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '25 تا 30 میلیون تومان', 6, 'بیمه,صبحانه', NULL, '<p>&nbsp;شرایط احراز :<br>حسابداری فروش، ثبت پیش فاکتور و فاکتور و مغایرت گیری با مشتریان و تامین کنندگان. مسلط به اکسل در حد مغایرت گیری در اکسل.</p><p>پنجشنبه ها تعطیل.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'مهم نیست', 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-02 07:55:22', '2025-11-30 07:42:24'),
(6500, 941, 1008, 'حسابدار', NULL, 'ماداستیل آسیا', NULL, NULL, NULL, NULL, '09152222770', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', 1, 'بیمه,سرویس رفت و برگشت,صبحانه', NULL, '<p>شرایط احراز :<br>مسلط به حسابداری و ثبت اسناد حسابداری زیر سیستم فروش ، نقد و بانک ،انبار ، حقوق و دستمزد و ارسال لیست بیمه&nbsp;<br>نرم افزار حسابداری : اوراش&nbsp;<br>ساعت کاری : 8 الی 16<br>محل کار : مشهد . سه کیلومتر بعد از شهرک صنعتی مشهد . بعد از تقاطع کمربندی سبز و جاده کلات . سمت راست مجتمع صنعتی صدف . کارخانه شرکت ماد استیل<br>مزایا : بیمه ، سرویس رفت و برگشت ، صبحانه&nbsp;<br>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 سال و کمتر', NULL, NULL, NULL, NULL, 'اوراش(آرمون)', 'متوسط', 'کم', 'خوب', 'نیاز نیست', NULL, NULL, NULL, NULL, NULL, NULL, 1, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-02 10:28:50', '2025-12-09 00:00:02'),
(6514, 944, 1009, 'حسابدار', NULL, 'وستا تجهیز پارت', NULL, NULL, NULL, NULL, '09121443155', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '20 تا 25 میلیون تومان', 5, 'بیمه,بیمه تکمیلی,پاداش و هدایا,وام سازمانی,پزشک سازمانی,سرانه آموزشی', NULL, '<p>شرایط احراز:<br>1. حداقل 2سال سابقه کار مرتبط ومفید<br>2. اشنایی نسبی به نرم افزار سپیدار<br>3. آشنا به حسابداری فروش، بازرگانی و ثبت هزینه ها،<br>4. آشنا به انجام تکالیف قانونی نظیر (اظهارنامه ارزش افزوده، معاملات فصلی و...)<br>5. حداکثر سن 30 سال<br>6. روابط عمومی بالا و فن بیان قوی<br>7. متعهد، منظم و پایبند به اصول رفتار سازمانی<br>8. دارای روحیه همکاری تیمی<br>&nbsp;آدرس محل کار : &nbsp;منطقه 3 ،جردن، ناهید غربی ، روبروی بانک کار آفرین پلاک 57 هلدینگ وستا&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'خانم', NULL, NULL, 'سپیدار', 'متوسط', 'متوسط', 'متوسط', 'متوسط', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-07 13:48:24', '2025-12-12 00:00:01'),
(6515, 947, 1010, 'حسابدار', NULL, 'صنایع غذایی تژین', NULL, NULL, NULL, NULL, '09021818546', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '30 تا 35 میلیون تومان', 7, 'بیمه', NULL, '<p><strong>شرایط احراز:</strong><br>مسلط به حسابداری و ثبت اسناد حسابداری و ارسال لیست بیمه و بهای تمام شده و مالیات&nbsp;<br>نرم افزار حسابداری : سپیدار&nbsp;<br>جنسیت :خانم<br>سابقه : 5 سال&nbsp;<br>مدرک تحصیلی : کارشناسی&nbsp;<br>محل کار: تهران ، شهرک غرب&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'حداقل 5 سال', NULL, 'خانم', 'کارشناسی', NULL, 'سپیدار', 'خیلی خوب', 'خوب', 'خیلی خوب', 'خوب', NULL, NULL, NULL, NULL, NULL, NULL, 1, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-08 11:21:28', '2025-12-23 00:00:02'),
(6523, 951, 1011, 'حسابدار', NULL, 'آتالان تک', NULL, NULL, NULL, NULL, '09393164064', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', '20 تا 25 میلیون تومان', 5, 'بیمه,سرویس رفت و برگشت', NULL, '<p>شرایط احراز:<br><br>-توانایی کار با نرم افزارهای مالی و ورد و اکسل</p><p>-امور سامانه مودیان و ارسال گزارشات مالیاتی</p><p>-محاسبه حقوق و دستمزد و بیمه</p><p>-دقت بالا،منظم،مسئولیت پذیر و داشتن تعهد اخلاقی<br><br>محل کار:<br>شهرک صنعتی ماشین سازی و فناوری برتر-صنعت۵-پلاک ۱۸۶A<br><br>ساعت کاری :<br>&nbsp;۷ تا ۱۶</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'سیبا', 'خوب', 'خوب', 'خوب', 'خیلی خوب', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-09 15:10:08', '2025-12-10 00:00:02'),
(6543, 958, 1012, 'کمک حسابدار', NULL, 'پیشتاز صنعت', NULL, NULL, NULL, NULL, '09354679378', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '15 تا 20 میلیون تومان', 4, 'بیمه', NULL, '<p><strong>شرایط احراز :</strong><br>تسلط بر یک نرم افزار حسابداری&nbsp; مربوط به مالیات و قوانین مالی&nbsp;<br>دقت و توجه به&nbsp;مهارت های تحلیل&nbsp;<br>مدیریت مالی زمان و کار تحت فشار مدیریت نرم افزارهای مرتبط با اسناد و مدارک و پرونده های کارآمد و تحقیقات اسنادی&nbsp;است<br>مدارک تحصیلی :فوق دیپلم یا لیسانس حسابداری<br>سابقه :1 سال&nbsp;<br><strong>ساعت کاری :</strong><br>از ساعت 8 الی 16:30 پنج شنبه از ساعت 8 الی 12&nbsp;<br><strong>مزایا:</strong><br>امکان اعمال حقوق توافقی<br>&nbsp;بیمه تامین اجتماعی&nbsp;<br><strong>محل کار :</strong><br>تهران ، روبه روی خیابان دکتر شریعتی ، کوچه آهور</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 سال و کمتر', NULL, 'خانم', 'کارشناسی', NULL, 'حسابان', 'خوب', 'خوب', 'خوب', 'خوب', NULL, NULL, NULL, NULL, NULL, NULL, 1, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-12 15:25:53', '2025-12-23 00:00:02'),
(6544, 959, 1013, 'حسابدار', NULL, 'بنیاد سلامت', NULL, NULL, NULL, NULL, '09058615402', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', 1, 'بیمه', NULL, '<p><strong>شرایط احراز:</strong><br>&nbsp;دقیق . مسئولیت پذیر&nbsp;<br>&nbsp;مسلط به حقوق و دستمز . بیمه . اکسل و….<br>جنسیت :خانم&nbsp;<br><strong>&nbsp;ساعت کاری :</strong><br>&nbsp;9 الی 17&nbsp;<br><strong>محل کار :</strong><br>مشهد ،ملک آباد 9، نسترن7 پلاک 40</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 تا 5 سال', NULL, 'خانم', 'کارشناسی', NULL, 'راهکاران', 'خیلی خوب', 'کم', 'خوب', 'نیاز نیست', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-12 17:17:47', '2025-12-14 00:00:01'),
(6551, 963, 1014, 'کمک حسابدار', NULL, 'دفتر مرکزی اسپورتلند', NULL, NULL, NULL, NULL, '09335367053', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '20 تا 25 میلیون تومان', 5, 'بیمه,پاداش و هدایا', NULL, '<p>دفتر مرکزی اسپورتلند جهت تکمیل تیم مالی خود از خانم‌های جوان و باانگیزه دعوت به همکاری می‌نماید.</p><p>عنوان شغلی: کمک حسابدار (خانم)<br>نوع همکاری: تمام‌وقت<br>محل کار: تهران – منطقه ۲<br>عنوان شغلی: کمک حسابدار (خانم)<br>نوع همکاری: تمام‌وقت<br>محل کار: تهران – منطقه ۲</p><p>شرایط احراز:<br>• حداکثر سن: ۳۰ سال<br>• حداقل مدرک کارشناسی حسابداری یا رشته‌های مرتبط<br>• دقت بالا و توجه به جزئیات<br>• توانایی کار تیمی</p><p>مهارت‌ها و توانایی‌ها:<br>• تسلط بر نرم‌افزارهای حسابداری و Excel<br>• آشنایی با Word و سیستم‌های مالی<br>• دانش پایه حسابداری و ثبت تراکنش‌های مالی<br>• توانایی انجام تحلیل‌های مالی پایه</p><p>شرح وظایف:<br>• ثبت و پیگیری تراکنش‌های مالی<br>• بایگانی و نگهداری اسناد مالی<br>• کمک به حسابداران ارشد و مدیر مالی<br>• تهیه گزارش‌های مالی و محاسبات حقوق و دستمزد<br>• پیگیری امور بیمه تامین اجتماعی</p><p>مزایا:<br>• بیمه<br>• محیط کاری پویا و حرفه‌ای</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '1 سال', NULL, 'خانم', 'کارشناسی', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 0, 0, 1, 1, 1, NULL, NULL, '2025-11-15 10:39:08', '2025-12-16 00:00:02'),
