(6556, 964, 1019, 'حسابدار', NULL, 'پیشروتجهیزالماس', NULL, NULL, NULL, NULL, '09011496229', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', 1, 'بیمه,پاداش و هدایا,وام سازمانی,سرانه آموزشی', NULL, '<p>شرایط احراز :<br>مسلط به اکسل ،حقوق و دستمزد و بیمه و…<br>مسلط به نرم افزار سپیدار</p><p>مزایا<br>• &nbsp;بیمه تأمین اجتماعی از روز اول<br>• &nbsp;پاداش‌های مناسبتی و عملکردی در طول سال<br>• &nbsp;پورسانت شفاف و منظم بر اساس شاخص‌های مالی مشخص<br>• &nbsp;ارزیابی عملکرد منصفانه و دوره‌ای برای رشد شغلی و ارتقاء<br>• &nbsp;دوره‌های آموزشی تخصصی برای ارتقاء مهارت‌های فنی و نرم<br>• &nbsp;محیط کاری حرفه‌ای، امن و با ثبات برای تمرکز و پیشرفت واقعی<br><br>محل کار :<br>سعادت آباد- علامه جنوبی</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, NULL, 'کارشناسی', NULL, 'سپیدار', 'خوب', NULL, 'خوب', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-15 14:08:10', '2025-12-16 00:00:02'),
(6560, 965, 1020, 'حسابدار', NULL, 'فنی و مهندسی سریر سازان رایکا', NULL, NULL, NULL, NULL, '09387220270', NULL, '117', 'تهران', '8', 'تهران', 'پاره وقت', 'توافقی', 1, '', NULL, '<p><strong>شرایط احراز :</strong><br><br>این شرکت به منظور تکمیل کادر فنی خود در حوزه ی حسابداری و حسابرسی پیمانکاری اقدام به جذب یک نفر می نماید:</p><p>نکته حائز اهمیت اینست که شخص متقاضی می بایست کلیه ی موارد کاربردی در صنعت پیمانکاری ساختمانی را دانسته و با علم به تخصص در این امور اقدام به ارسال رزومه نماید.<br><br>مسلط به بیمه ، مالیات ، سامانه تدارکات و مودیان ، تنظیم دفاتر بصورت الکترونیکی ، حقوق و دستمزد و ….<br><br><strong>محل کار :</strong><br>&nbsp;تهران محدوده پونک شمالی سردارجنگل جنوبی</p><p>&nbsp;</p><p>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'حداقل 5 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, NULL, 'خیلی خوب', 'خیلی خوب', 'خیلی خوب', 'خیلی خوب', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-15 15:28:05', '2025-12-16 00:00:02'),
(6566, 969, 1021, 'حسابدار', NULL, 'زیستار', NULL, NULL, NULL, NULL, '09121620406', NULL, '283', 'کرج', '5', 'البرز', 'تمام وقت', '20 تا 25 میلیون تومان', 5, 'بیمه,صبحانه,پاداش و هدایا', NULL, '<p><strong>شرایط احراز:</strong><br>مهارت در ارتباطات کتبی و شفاهی<br>آشنایی با اصول و استانداردهای حسابداری<br>آشنایی با نرم‌افزارهای حسابداری<br>توانایی کار به صورت تیمی<br>آشنایی با محاسبات حقوق و دستمزد<br>آشنایی با سیستم‌های انبار داری<br>تسلط نسبی به زبان انگلیسی<br><br><strong>ساعت کاری:</strong><br>شنبه تا چهارشنبه 8 الی 17 _ پنجشنبه 8 الی 12<br><br><strong>آدرس:</strong><br>&nbsp;فردیس بلوار فرگاز نسترن شرقی پلاک 412</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'خانم', 'کارشناسی', NULL, 'سپیدار', 'خوب', 'خوب', 'خوب', 'خوب', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-16 10:58:07', '2025-12-17 00:00:02'),
(6567, 970, 1022, 'حسابدار', NULL, 'رز دیبا فارمد', NULL, NULL, NULL, NULL, '09926525348', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '25 تا 30 میلیون تومان', 6, 'بیمه,پاداش و هدایا', NULL, '<p>شرکت رز دیبا فارمد، تولید کننده لوازم بهداشتی و آرایشی، به منظور تامین نیروی کارشناس حسابداری تولید از واجدین شرایط زیر دعوت به همکاری می‌نماید.</p><p><strong>شرایط احراز:</strong></p><ul><li>مسلط به نرم‌افزار سپیدار و اکسل</li><li>مسلط به فرایند حقوق و دستمزد</li><li>تسلط به سامانه های های مالیاتی</li><li>آشنایی با استانداردهای حسابداری</li><li>مدرک کارشناسی و بالاتر در رشته‌های حسابداری، مدیریت بازرگانی، مدیریت صنعتی و مدیریت مالی</li><li>حداقل 3 سال سابقه کاری حسابداری تولید</li><li>مدیریت زمان و زمان‌بندی</li><li>مدیریت حل مسئله</li><li>داشتن روحیه کار تیمی</li><li>آشنایی با اصول و استانداردهای حسابداری</li><li>اخلاق حرفه‌ای بالا</li></ul><p><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه 8:30 الی 16:30 و پنجشنبه‌ها 8:30 الی 12:30</p><p><strong>ادرس :&nbsp;</strong><br>شیخ بهایی جنوبی ، برج بین المللی تهران</p><p><strong>مزایا :</strong><br>حقوق ثابت ماهانه از 25 تا 35 میلیون تومان</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 تا 5 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'سپیدار', 'عالی', 'عالی', 'خوب', 'عالی', NULL, NULL, NULL, NULL, NULL, NULL, 1, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-16 14:47:55', '2025-12-20 00:00:02'),
(6576, 973, 1023, 'حسابدار', NULL, 'فرافن گاز تهران', NULL, NULL, NULL, NULL, '09108320337', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', 1, 'بیمه,بیمه تکمیلی,پاداش و هدایا,وام سازمانی,سرانه آموزشی', NULL, '<p><strong>شرایط احراز:</strong><br>شرکت فرافن گاز تهران جهت تکمیل کادر مالی خود، یک حسابدار با مشخصات زیر استخدام می‌نماید:<br>حداقل 2 سال سابقه کار در امور حسابداری<br>حداقل مدرک کارشناسی حسابداری یا رشته‌های مرتبط<br>آشنا به نرم‌افزار سپیدار و توانایی ثبت و پیگیری اسناد مالی<br>آشنا به قوانین مالیاتی و مقررات مرتبط<br><br><strong>ساعت کاری:&nbsp;</strong><br>شنبه تا چهارشنبه 8:00 الی 17:00<br>پنجشنبه 8:00 الی 13:00<br><br><strong>آدرس:</strong><br>ظفر - خیابان وحید دستگردی - پلاک 200</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 سال و کمتر', NULL, 'مهم نیست', 'کارشناسی', NULL, 'سپیدار', 'متوسط', 'خوب', 'متوسط', 'خوب', NULL, NULL, NULL, NULL, NULL, NULL, 1, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-17 13:43:41', '2025-12-20 00:00:02'),
(6580, 975, 1025, 'حسابدار', NULL, 'تکلان بیلان پارس', NULL, NULL, NULL, NULL, '09158008200', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', 1, 'بیمه,سرویس رفت و برگشت,پاداش و هدایا', NULL, '<p><strong>&nbsp;شرایط احراز:</strong><br>3 سال سابقه کار<br>مدرک تحصیلی کارشناسی</p><p><strong>ساعت کاری:</strong><br>7:00 الی 15:00<br><strong>مزایا:</strong><br>آموزش امور &nbsp;حسابداری&nbsp;<br><strong>محل کار :</strong><br>شهرک صنعتی طوس فاز 4</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 سال و کمتر', NULL, 'مهم نیست', 'کارشناسی', NULL, 'میزان', 'متوسط', 'متوسط', 'متوسط', 'متوسط', NULL, NULL, '', NULL, NULL, NULL, 1, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-17 21:07:35', '2025-12-23 00:00:02'),
(6581, 978, 1026, 'حسابدار', NULL, 'آرامیس تجارت پرداز زرین', NULL, NULL, NULL, NULL, '09123096323', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '25 تا 30 میلیون تومان', 6, 'بیمه', NULL, '<p>شرکت همراه گلد جهت تکمیل کادر مالی یک حسابدار با مشخصات مذکور میخواهد :&nbsp;</p><p>آشنایی با صنف طلا و جواهر -</p><p>&nbsp;تجربه کار با نرم افزار های حوزه طلا حداقل یکی از برنامه های ته حساب ، زرین ، زمرد ، برلیان و …</p><p>حداقل یکسال سابقه کار</p><p>ادرس:بازار بزرگ ،پاساژ شمس العماره ،طبقه منفی سه ،واحد 127</p><p>ساعت کاری:شنبه تا چهارشنبه 10-16</p><p>پنج شنبه ها نیمه وقت&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '1 سال', NULL, 'مهم نیست', 'مهم نیست', NULL, 'ته حساب', 'متوسط', NULL, NULL, 'متوسط', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-18 22:40:44', '2025-12-20 00:00:02'),
