(6589, 984, 1030, 'حسابدار', NULL, 'آفتاب عالم تاب', NULL, NULL, NULL, NULL, '09059374041', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', 1, 'بیمه,پاداش و هدایا', NULL, '<ul><li><strong>شرح شغل و وظایف:</strong></li></ul><p>تسلط به حسابداری فروش و انبار</p><p>آشنایی به سایر فرآیندهای حسابداری</p><p>آشنا به امور مالیاتی، تآمین اجتماعی و بیمه (مودیان، معاملات فصلی و اظهارنامه ارزش افزوده)</p><p>مسلط به نرم افزار سپیدار</p><p>آشنایی با اصول و استانداردهای حسابداری</p><p>آشنایی کامل و تسلط بر نرم افزارهای عمومی آفیس از جمله word، excel و غیره</p><p>تحصیلات: حداقل لیسانس حسابداری</p><ul><li>&nbsp;</li><li><strong>ویژگی ها:</strong></li></ul><p>سن: حداکثر تا 40 سال</p><p>سابقه شغلی: حداقل 3 سال سابقه کار</p><p>دقت و سرعت عمل بالا</p><p>صبور و دارای روحیه کار تیمی</p><p>مشتاق به یادگیری و آموزش</p><p>منظم و مسئولیت پذیر</p><p>روابط عمومی خوب</p><p>اخلاق حرفه‌ای بالا</p><ul><li><strong>داشتن سابقه در حوزه ی آرایشی بهداشتی امتیاز محسوب میشود.</strong><br><br><br><strong>ساعت کاری:</strong><br>شنبه تا چهارشنبه 8:00 الی 17:00<br><br><strong>آدرس:</strong><br>شهرک غرب - خیابان شریفی - کوچه بخشی - برج دوبرال<br>&nbsp;</li></ul>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 تا 5 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'سپیدار', 'خیلی خوب', 'خوب', 'خوب', 'خوب', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-21 14:41:45', '2025-12-23 00:00:02'),
(6590, 985, 1031, 'حسابدار', NULL, 'حسابگران سپاهان', NULL, NULL, NULL, NULL, '09134749587', NULL, '79', 'نجف آباد', '4', 'اصفهان', 'تمام وقت', 'قانون کار', 0, 'بیمه,وام سازمانی', NULL, '<p><strong>شرایط احراز:</strong><br><br>انجام امور مالی</p><p>خرید و فروش</p><p>خزانه داری</p><p>بیمه و مالیات حقوق<br><br><strong>ساعت کاری:</strong><br><br>شنبه تا چهارشنبه 8:00 الی 17:00<br>پنجشنبه 8:00 الی 13:00<br><br><strong>آدرس:</strong><br><br>&nbsp;نجف آباد - ویلاشهر - خیابان معلم - نبش ویلای شمالی (رو به روی پاساژ خلیج فارس) - دفتر حسابداری حسابگران سپاهان</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'نیاز نیست', NULL, 'خانم', 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-21 21:12:30', '2025-12-23 00:00:02'),
(6591, 986, 1032, 'کمک حسابدار', NULL, 'پیشگام ماشین', NULL, NULL, NULL, NULL, '09022464508', NULL, '122', 'اسلامشهر', '8', 'تهران', 'تمام وقت', 'توافقی', 1, 'بیمه,ناهار,پاداش و هدایا', NULL, '<p><strong>شرایط احراز:</strong><br><br>کمک حسابدار&nbsp;<br>مسلط به سیستم سپیدار<br>ثبت سند حسابداری و تنخواه&nbsp;<br><br><strong>ساعت کاری:</strong><br><br>شنبه تا چهارشنبه 9 الی 16<br><br><strong>آدرس:</strong><br><br>اسلام شهر- شهرک کامیونداران</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '1 سال', NULL, 'خانم', 'کاردانی', NULL, 'سپیدار', 'متوسط', 'کم', 'کم', 'نیاز نیست', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-22 10:59:55', '2025-12-23 00:00:02'),
(6592, 987, 1033, 'حسابدار', NULL, 'سیستمهای اطلاعاتی تصمیم سازان اسپانه', NULL, NULL, NULL, NULL, '09945780426', NULL, '60', 'اصفهان', '4', 'اصفهان', 'تمام وقت', 'توافقی', 1, 'بیمه,بیمه تکمیلی,صبحانه,پاداش و هدایا,وام سازمانی,سرانه آموزشی', NULL, '<p>گروه دمیس به منظور تکمیل تیم مالی خود،یک حسابدار مالیاتی باتجربه را به همکاری دعوت می‌نماید.</p><p><strong>شرایط احراز :</strong></p><p>جنسیت: آقا</p><p>سابقه : حداقل ۳ تا ۵ سال&nbsp;</p><p><strong>تسلط کامل بر:</strong></p><p>تهیه و تنظیم اظهارنامه‌های مالیاتی (عملکرد، ارزش افزوده، صورت معاملات فصلی)</p><p>قوانین مالیات‌های مستقیم و ارزش افزوده</p><p>نرم‌افزارهای مالی و آفیس (به‌ویژه Excel)</p><p>گزارش‌گیری و مستندسازی مالی</p><p>دقت بالا، مسئولیت‌پذیری و توانایی مدیریت زمان</p><p><strong>شرح وظایف:</strong></p><p>تنظیم و ارسال اظهارنامه‌ها و گزارش‌های مالیاتی</p><p>رسیدگی و پاسخگویی به امور مالیاتی و مراجع مرتبط</p><p>کنترل اسناد، ثبت عملیات مالی و تطبیق حساب‌ها</p><p>همکاری نزدیک با تیم مالی برای تهیه گزارش‌های دوره‌ای</p><p>نگهداری و بایگانی اسناد مطابق استانداردهای سازمان</p><p><br><strong>ساعت کاری :</strong><br>8الی 16:15 پنج شنبه ها 8 الی 13<br><br><strong>محل کار:</strong><br>خیابان جی ابتدای پرویس</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 تا 5 سال', NULL, 'آقا', 'کارشناسی', NULL, NULL, 'خوب', 'خیلی خوب', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-22 12:36:51', '2025-12-23 00:00:02'),
(6593, 988, 1034, 'مدیر مالی', NULL, 'Kolbeh Cleaning', NULL, NULL, NULL, NULL, '09025372783', NULL, '129', 'پاکدشت', '8', 'تهران', 'تمام وقت', 'توافقی', 1, 'بیمه,سرویس رفت و برگشت,پاداش و هدایا,سرانه آموزشی', NULL, '<p>رشد مالی در کنار هم…<br>در مجموعه کلبه برای رشدواحد مالی به دنبال همکاری هستیم که مدیریت این واحد رو به صورت تمام و کمال به عهده بگیرند.<br>&nbsp;</p><p><strong>برنامه‌ریزی مالی:</strong></p><p>تهیه بودجه</p><p>پیش‌بینی مالی</p><p>مدیریت ریسک مالی</p><p>حسابداری و گزارش‌دهی مالی</p><p>تحلیل عملکرد مالی</p><p>کنترل هزینه‌ها<br>&nbsp;</p><p><strong>تصمیم‌گیری مالی:</strong></p><p>سرمایه‌گذاری</p><p>تامین مالی</p><p>مدیریت نقدینگی<br>&nbsp;</p><p><strong>سایر وظایف:</strong></p><p>مشاوره مالی</p><p>مدیریت مالیاتی</p><p>مدیریت تیم مالی<br>&nbsp;</p><p><strong>مهارت‌های مورد نیاز:</strong></p><p>تسلط بر اصول حسابداری و مالی</p><p>مهارت‌های تحلیلی قوی</p><p>مهارت‌های ارتباطی موثر</p><p>مهارت‌های تصمیم‌گیری</p><p>آشنایی با نرم‌افزارهای مالی<br><br><br><strong>ساعت کاری:</strong><br>8:00 الی 17:00<br><br><strong>آدرس:</strong><br>پاکدشت، خاتون آباد، روبروی دوربرگردان اول، پلاک 1618/4<br><br><strong>&nbsp;اگردر صنایع تولیدی و بازرگانی تجربه خوبی دارید و مایل هستید با یک مجموعه جوان و آینده‌دار همکار باشید، لطفا رزومه خود را ارسال بفرمایید.</strong></p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'حداقل 5 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'سپیدار', 'خیلی خوب', 'عالی', 'خیلی خوب', 'عالی', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-11-23 10:12:51', '2025-12-24 00:00:01'),
