(6623, 841, 1046, 'سرپرست حسابداری', NULL, 'میراب لوله طوس', NULL, NULL, NULL, NULL, '09151155963', NULL, '167', 'چناران', '11', 'خراسان رضوی', 'تمام وقت', '20 تا 25 میلیون تومان', 5, 'بیمه,سرویس رفت و برگشت,پاداش و هدایا,سرانه آموزشی', NULL, '<p>شرایط احراز :<br>آآگاهی از قوانین و مهارت کار با سامانه های مالیاتی وتأمین اجتماعی<br>آشنایی باتهیه و تدوین اظهارنامه‌های مالیاتی اشخاص حقوقی<br>درک مفاهیم تحلیل صورت‌های مالی<br>آشنایی با حسابداری صنعتی وبهای تمام شده<br>فقط ساکنین گلبهار یا چناران</p><p>معاینات پزشکی سالیانه رایگان<br>شرکت در آموزشهای تخصصی</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 تا 5 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'انعکاس', 'خوب', 'متوسط', 'متوسط', 'خوب', NULL, NULL, '', NULL, NULL, NULL, 1, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-12-02 14:33:38', '2026-01-01 20:30:02'),
(6624, 1000, 1047, 'حسابدار', NULL, 'بسامد سازان', NULL, NULL, NULL, NULL, '09125993825', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '30 تا 35 میلیون تومان', 7, 'بیمه,ناهار', NULL, '<p>شرکت ساختمانی و عمرانی بسامد سازان با بیش از ده سال سابقه در اجرای پروژه‌های عمرانی و ساختمانی، در راستای توسعه تیم مالی خود، از واجدین شرایط زیر دعوت به همکاری می‌نماید:</p><p><strong>شرایط احراز:</strong></p><p>حداقل ۵ سال سابقه کار در حوزه حسابداری<br>تسلط کامل بر نرم‌افزارهای حسابداری و Microsoft Excel<br>آشنایی با قوانین مالیاتی، بیمه و استانداردهای حسابداری ایران<br>توانایی تهیه و تنظیم صورت‌های مالی و گزارش‌های مدیریتی<br>دقت، مسئولیت‌پذیری و توانایی کار تیمی</p><p><strong>وظایف اصلی:</strong></p><p>ثبت و کنترل اسناد حسابداری روزانه<br>تهیه گزارش‌های مالی و مدیریتی دوره‌ای<br>پیگیری امور مالیاتی و بیمه‌ای شرکت<br>همکاری نزدیک با مدیر مالی و تیم پروژه‌ها</p><p><strong>مزایا:</strong></p><p>محیط کاری پویا و حرفه‌ای<br>حقوق و مزایا مطابق با توانمندی و تجربه<br>فرصت رشد و ارتقاء شغلی در پروژه‌های بزرگ عمرانی<br><br><strong>ساعت کاری:</strong><br>8 تا 17&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 تا 5 سال', NULL, 'آقا', 'کارشناسی', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-12-03 11:32:30', '2026-01-02 20:30:02'),
(6625, 1002, 1048, 'حسابدار', NULL, 'طرح پردازان نقشینه افق', NULL, NULL, NULL, NULL, '09004302011', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', 1, 'بیمه', NULL, '<p>⚜️ استخدام کمک حسابدار خانم در مجتمع چاپ و کارتن سازی ایده<br><br>&nbsp;✅ شرایط احراز:&nbsp;<br>* سن: 25 الی 40 سال&nbsp;<br>* آشنایی با نرم افزار سپیدار الزامی است.&nbsp;<br>* سابقه کاری مرتبط الزامی (3 تا 5 سال)&nbsp;<br>* همکاری فقط به صورت تمام وقت می باشد.&nbsp;<br>* منظم، وقت شناس و مسئولیت پذیر&nbsp;<br><br>⏰ ساعات کاری:&nbsp;<br>* شنبه تا چهارشنبه: 9:00 الی 17:00&nbsp;<br>* پنجشنبه ها: 9:00 الی 13:00&nbsp;<br><br>مزایای شغلی:&nbsp;<br>* محیط امن و بی حاشیه<br>* حقوق توافقی و مناسب&nbsp;<br>* بیمه تامین اجتماعی&nbsp;<br><br>آدرس: شادآباد، بلوار الغدیر، بن بست سپیدرود&nbsp;<br><br><br>⭐️همکاری فقط به صورت تمام وقت می باشد. پذیرش افراد دانشجو، پاره وقت و دورکار نداریم. لطفا فقط طبق شرایط آگهی رزومه ارسال فرمایید.⭐️</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 تا 5 سال', NULL, 'مهم نیست', NULL, NULL, 'سپیدار', 'متوسط', 'متوسط', 'متوسط', 'متوسط', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 0, 0, 1, 1, 1, NULL, NULL, '2025-12-03 15:05:41', '2026-01-02 20:30:02'),
