(6683, 1003, 1106, 'حسابدار', NULL, 'شیشه ایمنی خراسان', NULL, NULL, NULL, NULL, '09021177280', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', 1, 'بیمه,سرویس رفت و برگشت,پاداش و هدایا,وام سازمانی', NULL, '<p><strong>شرایط احراز:</strong></p><ul><li>یک شرکت معتبر جهت تکمیل کادر خود در استان‌ خراسان رضوی از افراد واجد شرایط زیر دعوت به همکاری می‌نماید.</li><li>جنسیت: آقا، خانم</li><li>ساعت کاری: 07:30 تا 15:05</li><li>سابقه کار: دارای سابقه کار مفید</li><li>نوع همکاری: تمام وقت</li><li>دارای مدرک کارشناسی حسابداری یا بالاتر</li><li>سن: حداکثر 30 سال</li><li>دارای حداقل 2 سال سابقه مرتبط و مفید</li><li>دقیق و منظم</li><li>آشنا به مفاهیم مالی و مالیاتی</li><li>دارای روحیه کار تیمی</li></ul><p><strong>سایر مزایا:</strong></p><ul><li>سرویس رفت و برگشت</li><li>وام پرسنلی</li><li>بیمه از روز اول</li><li>پرداخت به موقع حقوق</li></ul>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, NULL, 'متوسط', 'متوسط', 'متوسط', 'متوسط', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-12-06 18:05:20', '2026-01-05 20:30:01'),
(6684, 1006, 1107, 'حسابدار', NULL, 'زرین جام مانا', NULL, NULL, NULL, NULL, '09155500960', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', '15 تا 20 میلیون تومان', 4, 'بیمه,ناهار', NULL, '<p>قابل توجه حسابدارانی که &nbsp;دنبال <strong>پیشرفت و یادگیری و کار در محیط پویا </strong>هستند:&nbsp;</p><p>ما در زرین جام مانا یک فرصت شغلی با مشخصات زیر داریم:</p><h3>توانمندی های عمومی :&nbsp;</h3><p>دارای روحیه کار تیمی&nbsp;</p><p>دارای روابط عمومی بالا</p><p>داری حس مسئولیت پذیری و تعهد به کار بالا</p><p>آشنایی با نرم افزار اکسل در حد وظایف حسابداری</p><h3>شرح مسئولیت ها</h3><p>ثبت فاکتور هایدر سامانه مودیان</p><p>ثبت اسناد حسابداری و ارائه گزارش های مالی</p><p>مغایرت گیری حساب های مشتریان</p><p>مغایرت گیری حساب های بانکی</p><p>&nbsp;</p><h3>میزان حقوق پرداختی&nbsp;</h3><p>&nbsp;</p><p>میزان حقوق با توجه به سوابق و توانمندیها در جلسه مصاحبه تعیین می شود.&nbsp;<br>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'خانم', 'کارشناسی', NULL, NULL, 'خوب', 'خوب', 'متوسط', NULL, NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 0, 0, 1, 1, 1, NULL, NULL, '2025-12-06 19:36:18', '2026-01-05 20:30:01'),
