(6689, 1007, 1112, 'حسابدار', NULL, 'لوازم یدکی رشیدیان', NULL, NULL, NULL, NULL, '09158946889', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', '15 تا 20 میلیون تومان', 4, 'صبحانه,ناهار,پاداش و هدایا', NULL, '<p><strong>شرایط احراز:</strong><br>به یک حسابدار جهت فعالیت در فروشگاه رشیدیان با شرایط زیر نیازمندیم :<br>متعهد و امانت دار&nbsp;<br>توانایی فعالیت گروهی&nbsp;<br>مسلط به نرم افزار حسابداری محک&nbsp;<br>مسلط به افیس&nbsp;<br>شرکت در کلاس های آموزشی مورد تایید مجموعه&nbsp;<br>خلاق و پویا بودن&nbsp;<br>پایه حقوق 15 میلیون تومان که باتوجه به تسلط و توانایی قابل افزایش است&nbsp;<br><br><strong>ساعت کاری:</strong><br>شنبه تا چهارشنبه از 8 الی 18 وپنج شنبه ها 8 الی 15<br><br><strong>آدرس محل کار:</strong><br>خیابان امام رضا (علیه اسلام) 38، چهارراه اول سمت چپ، فروشگاه رشیدیان<br>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '1 سال', NULL, 'آقا', NULL, NULL, 'محک', 'متوسط', 'متوسط', 'متوسط', 'متوسط', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-12-07 13:56:00', '2026-01-06 20:30:02'),
(6694, 1012, 1117, 'حسابدار', NULL, 'نیمه دولتی', NULL, NULL, NULL, NULL, '09399940612', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '35 تا 40 میلیون تومان', 8, 'بیمه,بیمه تکمیلی,ناهار,وام سازمانی,پزشک سازمانی,سرانه آموزشی', NULL, '<p>🗓 ١۴٠۴/٠۹/۱۶<br><br><br><br>یک شرکت معتبر تولیدی و &nbsp;جهت تکمیل کادر مالی خود از افراد واجد شرایط زیر در تهران دعوت به همکاری می‌نماید.<br><br>جنسیت :آقا<br>نوع همکاری: تمام وقت<br><br>آشنایی با اصول حسابداری و توانایی ثبت اسناد روزانه<br>توانایی تهیه و ارسال گزارشات فصلی<br>تسلط به نرم‌افزارهای office&nbsp;<br>دارای سابقه کار مرتبط (اولویت محسوب می‌شود)<br><br>دارای ویژگی‌های شخصیتی: دقیق، منضبط، مسئولیت‌پذیر، علاقه‌مند به یادگیری و پیشرفت و &nbsp;و بدون حاشیه<br><br>ساعات کاری شنبه تا چهارشنبه 7 الی 17 - پنجشنبه‌ها همیشگی نیست در صورت نیاز به صورت اضافه کار&nbsp;<br><br>محیط کاری پویا و حرفه‌ای<br>امنیت شغلی<br>شماره تماس : 09399940612</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'نیاز نیست', NULL, 'آقا', 'کارشناسی', NULL, 'راهکاران', 'خیلی خوب', 'متوسط', 'متوسط', 'متوسط', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 0, 0, 1, 1, 1, NULL, NULL, '2025-12-08 17:16:52', '2026-01-07 20:30:02'),
(6695, 1012, 1118, 'حسابدار', NULL, 'نیمه دولتی', NULL, NULL, NULL, NULL, '09399940612', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '35 تا 40 میلیون تومان', 8, 'بیمه,بیمه تکمیلی,ناهار,وام سازمانی,پزشک سازمانی,سرانه آموزشی', NULL, '<p><strong>شرایط &nbsp;احراز:</strong><br>یک شرکت معتبر تولیدی و &nbsp;جهت تکمیل کادر مالی خود از افراد واجد شرایط زیر در تهران دعوت به همکاری می‌نماید.<br>آشنایی با اصول حسابداری و توانایی ثبت اسناد روزانه<br>توانایی تهیه و ارسال گزارشات فصلی<br>تسلط به نرم‌افزارهای office&nbsp;<br>دارای سابقه کار مرتبط (اولویت محسوب می‌شود)<br>دارای ویژگی‌های شخصیتی: دقیق، منضبط، مسئولیت‌پذیر، علاقه‌مند به یادگیری و پیشرفت و &nbsp;و بدون حاشیه<br>جنسیت :آقا<br>نوع همکاری: تمام وقت<br>ساعات کاری :<br>شنبه تا چهارشنبه 7 الی 17 - پنجشنبه‌ها همیشگی نیست در صورت نیاز به صورت اضافه کار&nbsp;<br>محیط کاری پویا و حرفه‌ای<br>امنیت شغلی<br>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'نیاز نیست', NULL, 'آقا', 'کارشناسی', NULL, 'راهکاران', 'خیلی خوب', 'متوسط', 'متوسط', 'متوسط', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-12-08 17:22:00', '2026-01-07 20:30:02'),
(6707, 1015, 1120, 'رییس حسابداری', NULL, 'آبتین تجارت فولاد ونداد', NULL, NULL, NULL, NULL, '09121541161', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', '45 تا 50 میلیون تومان', 10, 'بیمه', NULL, '<p><strong>شرایط احراز :</strong></p><ol><li>نظارت بر فعالیت‌های روزانه حسابداری: کنترل ثبت اسناد مالی، بررسی صحت دفاتر و اطمینان از رعایت استانداردهای حسابداری&nbsp;</li><li>&nbsp;</li><li>تهیه و ارائه گزارش‌های مالی: تدوین صورت‌های مالی، گزارش سود و زیان، ترازنامه و ارائه آن به مدیر مالی یا مدیرعامل&nbsp;</li><li>&nbsp;</li><li>اجرای سیاست‌ها و کنترل‌های داخلی: پیاده‌سازی سیستم‌های جدید حسابداری، به‌روزرسانی کنترل‌های داخلی و پایش هزینه‌ها&nbsp;</li><li>&nbsp;</li><li>تحلیل و بررسی داده‌های مالی: انجام تحلیل‌های مالی برای تصمیم‌گیری‌های مدیریتی و ارائه پیشنهادهای بهبود روند کار&nbsp;</li><li>&nbsp;</li><li>مدیریت تیم حسابداری: هدایت، آموزش و ارزیابی عملکرد کارکنان حسابداری و تقسیم وظایف بین اعضای تیم&nbsp;</li><li>&nbsp;</li><li>همکاری با سایر بخش‌ها: ارتباط با واحدهای فروش، تولید یا پیمانکاری برای هماهنگی امور مالی و حسابداری&nbsp;</li><li>&nbsp;</li><li>اطمینان از رعایت قوانین و مقررات مالیاتی: بررسی و کنترل اظهارنامه‌های مالیاتی و تطابق با قوانین جاری&nbsp;</li><li><strong>&nbsp;</strong><br><strong>مهارت‌های مورد نیاز :</strong><br>تسلط بر نرم‌افزارهای حسابداری (سپیدار، هلو، راهکاران)<br>دانش قوانین مالیاتی و بیمه‌ای<br>توانایی مدیریت تیم و مهارت‌های رهبری<br>دقت بالا و توجه به جزئیات<br>مهارت‌های ارتباطی و گزارش‌دهی شفاف</li></ol><ul><li>- کارآموز حسابداری آشنا “به نرم افزار سپیدار” پذیرفته می شود.</li></ul>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'حداقل 5 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'سپیدار', 'خیلی خوب', 'خیلی خوب', 'خوب', 'خوب', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-12-09 15:52:10', '2026-01-08 20:30:02'),
