(6710, 1018, 1123, 'کمک حسابدار', NULL, 'دیان إرامهر', NULL, NULL, NULL, NULL, '09371904078', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '20 تا 25 میلیون تومان', 5, 'بیمه,پاداش و هدایا,وام سازمانی', NULL, '<p>آشنایی با <strong>اصول حسابداری و مبانی حسابداری فروش</strong></p><p>تسلط اولیه به نرم‌افزارهای حسابداری (آشنایی با همکاران سیستم یا ورانگر امزیت محسوب میشود)</p><p>آشنا به کاردکس مشتریان و مغایرت گیری صورتحساب&nbsp;</p><p>آشنا به وصول و مطالبات&nbsp;</p><p>آشنایی متوسط با <strong>Excel</strong></p><p>دقت، نظم، مسئولیت‌پذیری و توانایی کار تیمی</p><p>مهارت در ارتباط عمومی و فن بیان خوب&nbsp;</p><p>حداقل ۱–۲ سال سابقه مرتبط در واحدهای فروش یا حسابداری (امتیاز محسوب می‌شود)</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '1 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'ورانگر', 'متوسط', 'کم', 'نیاز نیست', 'کم', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 0, 0, 1, 1, 1, NULL, NULL, '2025-12-11 17:02:55', '2026-01-10 20:30:02'),
