(6723, 1022, 1127, 'کمک حسابدار', NULL, 'تابران', NULL, NULL, NULL, NULL, '09152600036', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'قانون کار', 0, 'بیمه,بیمه تکمیلی,سرویس رفت و برگشت,ناهار,پاداش و هدایا', NULL, '<p><strong>شرایط احراز :</strong><br>شرکت صنعتی و تولیدی تابران جهت بخش حسابداری خود به یک نفر حسابدار با شرایط زیر نیازمند است<br>آشنایی با حداقل یک نرم افزار مالی&nbsp;<br><br><strong>حقوق :&nbsp;</strong><br>قانون کار و قابل بررسی برای مبلغ بیشتر<br><br><strong>ساعت کاری :</strong>&nbsp;<br>07:00 الی 14:45<br>تعطیلات و مرخصی و …طبق قانون کار<br><br><strong>&nbsp;آدرس</strong> :شهرک صنعتی فناوری برتر ، صنعت 4 &nbsp;<br><br>در صورت دارا بودن شرایط آگهی جهت مصاحبه حضوری در ساعات 8 الی 13 به واحد حسابداری تابران مراجعه نمایید .</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '1 سال', NULL, 'خانم', 'کارشناسی', NULL, NULL, 'متوسط', 'کم', 'کم', 'متوسط', NULL, NULL, '', NULL, NULL, NULL, 1, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-12-14 10:39:02', '2026-01-13 20:30:01'),
(6725, 1023, 1129, 'حسابدار', NULL, 'شریف تریپ', NULL, NULL, NULL, NULL, '09301923861', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '30 تا 35 میلیون تومان', 7, 'بیمه,بیمه تکمیلی,پاداش و هدایا', NULL, '<p><strong>شرایط احراز:</strong><br>انجام فعالیت‌های حسابداری به شکل روزانه، ماهانه، فصلی و سالیانه شامل تلفیق حساب‌های بانکی و کارت‌های اعتباری، تکمیل و هماهنگی حسابرسی سالانه و بازبینی گزارش‌های مالی و اقتصادی؛<br>تحلیل و گزارش وضعیت اقتصادی شامل شرح واریانس درآمد، مکاتبه با مدیریت برای نتایج مالی، آماده‌سازی بودجه و بررسی فعالیت‌های متفاوت اقتصادی؛<br>ثبت اسناد معاملات اقتصادی و تجاری؛<br>اصلاح فعالیت‌های سازمان به وسیله ارتقای سیستم مالی و پروسه‌های مختلف؛<br>آشنایی با اصول حسابداری و استانداردهای مالی<br>مهارت در مدیریت حساب‌ها و پیگیری پرداخت‌ها<br><strong>حقوق دریافتی برای فارغ التحصیلان دانشگاه تهران و دانشگاه شهید بهشتی تا 40 درصد بیشتر خواهد بود</strong></p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 تا 5 سال', NULL, 'مهم نیست', 'کارشناسی ارشد', NULL, NULL, 'خوب', 'متوسط', 'خوب', 'خوب', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-12-14 12:16:48', '2026-01-13 20:30:01'),
(6726, 1026, 1130, 'حسابدار', NULL, 'بازرگانی سپهری', NULL, NULL, NULL, NULL, '09153200049', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', 1, 'بیمه,بیمه تکمیلی,پاداش و هدایا', NULL, '<p>حداقل مدرک تحصیلی کارشناس حسابداری ،علوم اقتصادی&nbsp;</p><p>دارای حداقل سه سال سابقه کار در شرکت های بازرگانی&nbsp;</p><p>آشنا به سیستم های حسابداری ترجیحا همکاران سیستم&nbsp;</p><p>آشنایی خوب و مفید به اکسل و وورد&nbsp;</p><p>آشنا به حسابداری انبار ، بهای تمام شده ، اسناد و ثبت خزانه&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 تا 5 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'همکاران سیستم', 'خوب', 'نیاز نیست', 'نیاز نیست', 'خوب', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-12-14 14:15:17', '2026-01-13 20:30:01'),
