(6730, 697, 1134, 'حسابدار', NULL, 'فناوران هوشمند نیکان', NULL, NULL, NULL, NULL, '09153089733', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'قانون کار', 0, 'بیمه,بیمه تکمیلی,سرویس رفت و برگشت,پاداش و هدایا,وام سازمانی,سرانه آموزشی', NULL, '<p>نیازمند حسابدار - آقا یا خانم با مشخصات ذیل :<br>حداقل داشتن مدرک کارشناسی حسابداری مرتبط<br>نیازمند 3 سال سابقه کاری بعد از اخذ لیسانس&nbsp;<br>داشتن مهارت کار با اکسل&nbsp;<br>آشنا به نرم افزار های پایا و رایسیس<br>مسلط به امور قانونی بیمه و مالیات&nbsp;<br>پیگیر و متعهد<br>در شرکت نیروگاهی فناوران هوشمند نیکان با شرایط و مزایا&nbsp;<br>بیمه تامین اجتماعی<br>بیمه تکمیل درمان دانا&nbsp;<br>حقوق ماهیانه نسبت به توانایی شما تا سقف 30 میلیون تومن<br>سرویس دارد<br>مکان شرکت در جاده مشهد - فریمان&nbsp;<br>شرکت دارای مدیرمالی و مشاور مالی و مالیاتی می باشد<br>نیازمندیم.<br>جهت مصاحبه حضوری اول فایل رزومه خود را ارسال کنید&nbsp;<br>این شرکت بعد از مصاحبه تعهدی برای جذب و استخدام شما ندارد</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 سال و کمتر', NULL, 'آقا', 'مهم نیست', NULL, 'پایا', 'خوب', 'خوب', 'خوب', 'خوب', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 0, 0, 1, 1, 1, NULL, NULL, '2025-12-15 17:50:49', '2026-01-14 20:30:01'),
