(6769, 1052, 1153, 'حسابدار', NULL, 'گروه آرمان', NULL, NULL, NULL, NULL, '09157733767', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', 1, 'بیمه,بیمه تکمیلی,پاداش و هدایا', NULL, '<p>شرایط احراز :</p><p>دارای سابقه کار مرتبط</p><p>مسلط به اکسل و نرم افزار سپیدار&nbsp;</p><p>مسلط به سامانه های مالیاتی و تامین اجتماعی و حقوق و دستمزد</p><p>آشنایی با سامانه جامع تجارت&nbsp;</p><p>مسلط به سامانه مودیان&nbsp;</p><p>دارای نظم و تعهد کاری&nbsp;</p><p>ساعت کاری شنبه تا چهارشنبه &nbsp;08:30-17:30</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 تا 5 سال', NULL, 'خانم', 'کارشناسی', NULL, 'سپیدار', 'خیلی خوب', 'خیلی خوب', 'خیلی خوب', 'خیلی خوب', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 1, NULL, NULL, '2025-12-28 16:08:25', '2026-01-27 20:30:01'),
(6770, 1055, 1154, 'حسابدار', NULL, 'مجتمع فولاد سهند آذر آسیا', NULL, NULL, NULL, NULL, '09144100023', NULL, '19', 'بستان آباد', '1', 'آذربایجان شرقی', 'تمام وقت', 'توافقی', 1, 'بیمه,بیمه تکمیلی,سرویس رفت و برگشت,صبحانه,ناهار,پاداش و هدایا', NULL, '<p>استخدام صرفا خانم</p><p>تسلط به نرم افزار حسابداری&nbsp;</p><p>تسلط به نرم افزارهای آفیس&nbsp;</p><p>عدم سوء پیشینه&nbsp;</p><p>حداقل دو سال سابقه کار&nbsp;</p><p>مدرک تحصیلی صرفاً حسابداری ترجیحا کارشناسی به بالاتر</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'خانم', 'کارشناسی', NULL, NULL, 'خوب', 'خوب', 'متوسط', 'متوسط', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-27 20:30:01', '2026-01-28 20:30:01'),
(6797, 1061, 1156, 'حسابدار', NULL, 'شرکت پدیده پارسیان توس', NULL, NULL, NULL, NULL, '09383214619', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', '12 تا 15 میلیون تومان', 3, 'بیمه,بیمه تکمیلی,صبحانه,ناهار,پاداش و هدایا', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'حداقل 5 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, NULL, 'خیلی خوب', 'خوب', 'خوب', 'خوب', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 0, 0, 1, 1, 1, NULL, NULL, '2026-01-01 08:01:56', '2026-01-31 20:30:02'),
(6799, 1062, 1158, 'کمک حسابدار', NULL, 'ملیوان', NULL, NULL, NULL, NULL, '09197477972', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', 1, 'بیمه,پاداش و هدایا,وام سازمانی', NULL, '<p>مادر این مجموعه به یک کمک حسابدار منظم و منضبط با دقت بالا نیاز داریم تا با شرح اسناد و سرفصل ها آشنا باشه بتواند کارهای ثبت سند را انجام بدهد مانند دریافت پرداخت، بانک، تنخواه و فاکتور زدن و …&nbsp;</p><p>در صورت برخورداری از شرایط مورد نظر این جایگاه، از شما دعوت می‌کنیم رزومه خود را جهت بررسی ارسال فرمایید.</p><p><strong>ساعت کاری:</strong><br>&nbsp;۸ تا ۱۷ / پنجشنبه ها ۸تا۱۲&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 سال و کمتر', NULL, 'خانم', NULL, NULL, NULL, 'متوسط', 'نیاز نیست', 'نیاز نیست', 'نیاز نیست', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-27 11:27:47', '2026-01-04 07:42:35'),
(6802, 1, NULL, 'حسابدار', 'karbarg-public.png', 'صنایع وفایی', 'اصفهان، اصفهان، منطقه ۳، شهشهان', NULL, NULL, '<p>مجموعه صنایع برودتی مهدی وفایی با مدیریت آقای مهدی وفایی از سال ۱۳۵۰ فعالیت خود را در زمینه ی تجهیزات صنعتی از جمله (یخچال های ویترینی، فروشگاهی، قنادی و قصابی انواع سردخانه های ثابت و متحرک جهت نگهداری موادپروتئینی، سبزیجات ومیوه جات، سردخانه های بیمارستانی، تجهیزات سرمایشی رستوران، کافی شاپ، آبمیوه وبستنی فروشی و هایپرمارکت ها، فروش انواع آبسردکن های استیل جهت مصارف عمومی وآبسردکن های دو منظوره جهت مصرف دفاتر اداری، انواع فریزرهای ایستاده، خوابیده با درب های شیشه ای و درب های توپر درابعادمختلف و غیره) آغاز نموده است.<br>&nbsp;</p>', NULL, NULL, '60', 'اصفهان', '4', 'اصفهان', 'تمام وقت', '30 تا 35 میلیون تومان', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>دعوت به همکاری از یک نفر حسابدار با اخلاق و مسئولیت‌پذیر<br>به صورت تمام وقت<br>با حداقل 3 سال سابقه کار<br>مسلط به امور مالی و آشنا به امور مالیاتی<br>مسلط به نرم‌افزار پارسیان<br><br><strong>ساعات کاری:</strong><br>9 الی 16<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه /پاداش/ فضای استراحت<br><br><strong>محل کار:</strong><br>اصفهان، اصفهان، منطقه ۳، شهشهان</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس &nbsp;۰۹۱۳۱۱۱۶۵۴۵ / ۰۹۱۳۸۱۱۵۵۶۵ حاصل فرمائید.<br>&nbsp;</p>', '3 سال و کمتر', NULL, 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-04 13:53:28', 'یکشنبه 14 دی', '2026-01-04 10:23:28', '2026-01-04 10:23:28'),
(6803, 1, NULL, 'حسابدار', 'karbarg-public.png', 'شرکت صنعتی آموت سپهر', 'تهران، منطقه ۷، عباس آباد', NULL, NULL, '<p>شركت صنعتی آموت سپهر (سهامی خاص) در سال 1381 با هدف اجرای پروژه هاى اجرايى و مشاوره مهندسى در حوزه هاى صنعت، نفت و گاز و پتروشيمى، ساختمان، آب ، راه آهن و مترو &nbsp;تاسيس گرديد.این شركت با پشتوانه ى سالها تجربه در پروژه هاى صنعتى، پژوهشى و راه آهن و با انگيزه ى ارائه خدمات به صنعت كشور و ارتقاء دانش فنى پايه گذارى گرديده است. پايه گذاران اين شركت ايمان دارند تنها با پشتكار و فعاليت سخت در كنار برنامه ريزى مى توان راه هاى توسعه و پيشرفت را براى كشور عزيزمان هموار نمود.</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>آشنایی به اصول حسابداری<br>آشنایی به سیستم سپیدار<br>شرایط سن 22 الی 27<br>مهارت در تهیه گزارش‌های مالی<br>توانایی انجام عملیات بانکی<br>قابلیت کار با اعداد و ارقام<br>آشنایی با نرم‌افزارهای حسابداری<br><br><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه 8 الی 17 - پنجشنبه‌ها 8 الی 13<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه<br><br><strong>سایر مزایا:</strong><br>بیمه از شروع کار<br><br><strong>محل کار:</strong><br>تهران، منطقه ۷، عباس آباد</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس &nbsp;۰۲۱۸۸۵۰۳۵۱۳ - 02188521714 حاصل فرمائید.<br>&nbsp;</p>', NULL, '27', 'آقا', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-04 14:01:22', 'یکشنبه 14 دی', '2026-01-04 10:31:22', '2026-01-04 10:31:22'),
(6804, 1, NULL, 'حسابدار', 'karbarg-public.png', 'همراه طلایی ارتباط ایرانیان', 'تهران، منطقه ۱۲، فردوسی', NULL, NULL, '<p>شرکت گارانتی همراه طلایی ارتباط ایرانیان با تاسیس در سال 1400 شمسی به پشتوانه سال‌ها حضور در زمینه فروش تلفن همراه و ارائه خدمات پس از فروش و تعمیرات تخصصی ، شروع به فعالیت رسمی در این حوزه نمود.</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>استخدام حسابدار با سابقه کار مفید<br>آشنا به اصول و استانداردهای حسابداری و ثبت اسناد جاری و مغایرت‌گیری حساب‌ها و مغایرت‌گیری بانکی و کلیه امورات جاری در حسابداری<br>مسلط به مبحث انبار و ثبت ورود و خروجی و کنترل ماهیانه انبار<br>آشنا به حسابداری فروش و صدور رسید و حواله و فاکتورهای فروش<br>آشنا به مبحث ارزش افزوده و ارسال گزارشات فصلی 169<br>مسلط به سامانه مودیان و کنترل لحظه‌ای فاکتورهای خرید و فروش در سامانه مودیان<br>مسلط به حسابداری خزانه و سیستم خزانه‌داری (دریافت و پرداخت)<br>آشنا به نرم‌افزار حسابداری ترجیحا (سایان)<br>آشنا به قوانین بیمه و مالیات<br>آشنا به مبحث قیمت تمام شده (بازرگانی و تولید)<br>مسئولیت‌پذیری بالا و اخلاق حرفه‌ای<br>توانایی کار تیمی و دقت و توجه به جزئیات<br><br><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه 9 الی 17<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه<br><br><strong>محل کار:</strong><br>تهران، منطقه ۱۲، فردوسی</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 09916414113 حاصل فرمائید.<br>&nbsp;</p>', NULL, NULL, 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-04 14:21:29', 'یکشنبه 14 دی', '2026-01-04 10:51:29', '2026-01-04 10:51:29'),
(6805, 1, NULL, 'حسابدار', 'karbarg-public.png', 'تخم مرغ مروارید', 'تهران، منطقه ۴، شمس آباد', NULL, NULL, '<p>طی چند سال گذشته پرورش دهندگان با هدف تولید حداکثر وزن یا توده تخم مرغ (Egg-mass) با حداقل هزینه، تغییراتی در مرغ تخمگذار ایجاد کرده اند. تغییرات قابل ذکر شامل کاهش در سن شروع تولید، وزن مرغ بالغ و میزان دان مصرفی میباشد. چنانچه این تغییرات با یک برنامه تغذیه ای که به شکل مناسب طراحی و فرموله شده باشد همراه شوند، باعث تولید تخم مرغ با حداقل قیمت خواهد شد. در عین حال جدا شدن از مدیریت و برنامه های تغذیه ای سنتی که برای انواع نژادهای تخمگذار طراحی شده بود بدون سختی و مشکلات نبوده است. آنچه که برای تولید موفق تخم مرغ مهم است. طراحی دقیق برنامه های تغذیه ای مرغهای تخمگذار جدید براساس مقدار مصرف روزانه دان میباشد. بطوری که مطمئن شویم ضمن در نظر گرفته شدن قیمت تمام شده دان، مواد مغذی مورد نیاز مرغ جهت بهبود و یا بهینه سازی عملکرد گله بر اساس مقدار مصرف روزانه دان در حد کافی و لازم تامین شده است.</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '25 تا 30 میلیون تومان', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>مسلط به نرم‌افزار سپیدار<br>منظم و منعطف و دارای روحیه انجام کار تیمی<br>دارای حداقل 3 سال سابقه کاری در زمینه حسابداری<br><br><strong>ساعات کاری:</strong><br>44 ساعت در هفته به صورت شناور<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه<br><br><strong>محل کار:</strong><br>تهران، منطقه ۴، شمس آباد</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 021-65239222 حاصل فرمائید.<br>&nbsp;</p>', '3 سال و کمتر', NULL, 'خانم', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-04 14:37:22', 'یکشنبه 14 دی', '2026-01-04 11:07:22', '2026-01-04 11:07:22'),
(6807, 841, 1162, 'سرپرست حسابداری', NULL, 'میراب لوله طوس', NULL, NULL, NULL, NULL, '09151155963', NULL, '167', 'چناران', '11', 'خراسان رضوی', 'تمام وقت', '20 تا 25 میلیون تومان', 5, 'بیمه,سرویس رفت و برگشت,پاداش و هدایا,سرانه آموزشی', NULL, '<p><strong>شرایط احراز :</strong><br><br>آگاهی از قوانین و مهارت کار با سامانه های مالیاتی وتأمین اجتماعی<br>آشنایی باتهیه و تدوین اظهارنامه‌های مالیاتی اشخاص حقوقی<br>درک مفاهیم تحلیل صورت‌های مالی<br>آشنایی با حسابداری صنعتی وبهای تمام شده<br>فقط ساکنین گلبهار یا چناران</p><p>معاینات پزشکی سالیانه رایگان<br>شرکت در آموزشهای تخصصی<br><br><strong>آدرس:</strong><br>شهرک صنعتی چناران صنعت ۱۷</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 تا 5 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'انعکاس', 'خوب', 'متوسط', 'متوسط', 'خوب', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-26 11:41:40', '2026-01-04 11:43:02'),
(6808, 975, 1163, 'حسابدار صنعتی', NULL, 'تکلان بیلان پارس', NULL, NULL, NULL, NULL, '09158008200', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', '25 تا 30 میلیون تومان', 6, 'بیمه,سرویس رفت و برگشت,صبحانه', NULL, '<p><strong>شرایط احراز:</strong><br>استخدام کارشناسی حسابدار آقا&nbsp;<br>سابقه کاری 7 الی 10 سال &nbsp;<br><br><strong>ساعت کاری:</strong><br>8:00 الی 16:00<br><br><strong>آدرس:</strong><br>شهرک صنعتی کلات</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '7 تا 10 سال', NULL, 'آقا', 'کارشناسی', NULL, 'پایا', 'متوسط', 'متوسط', 'متوسط', 'متوسط', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-26 14:44:54', '2026-01-05 06:43:06'),
(6810, 990, 1165, 'رییس حسابداری', NULL, 'شرکت روغن نباتی سه گل خراسان', NULL, NULL, NULL, NULL, '09151510091', NULL, '154', 'نیشابور', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', 1, 'بیمه,سرویس رفت و برگشت', NULL, '<p><strong>شرایط احراز:</strong><br><br>آشنایی به نرم افزار پایا<br><br><strong>ساعت کاری:</strong></p><p>شنبه تا پنجشنبه 7:30 الی 14:30<br><br><strong>آدرس:</strong></p><p>کیلومتر 27 جاده نیشابور مشهد ابتدای جاده روستای محسن آباد</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 تا 5 سال', NULL, 'آقا', 'کارشناسی', NULL, 'پایا', 'خوب', 'خوب', 'خوب', 'خوب', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-28 12:17:53', '2026-01-05 12:17:53'),
(6811, 1, NULL, 'حسابدار', 'karbarg-public.png', 'آروین بنیان تجهیز', 'تهران، منطقه ۷، عباس آباد', NULL, NULL, '<p>شرکت آروین بنیان تجهیز با اتکاء به سال­ها تجربه و توانمندی علمی و فنی نفرات تشکیل دهنده آن در زمینه ارائه خدمات مشاوره، تامین تجهیزات و قطعات، نصب و راه اندازی، آموزش اپراتوری، سرویس و کالیبراسیون دوره­ ای تجهیزات تحقیقاتی، آزمایشگاهی و آنالایزرهای صنعتی مشغول به فعالیت می­باشد.</p><p>امروزه در بسیاری از مراکز علمی، تحقیقاتی و صنعتی کشور عزیزمان با تجهیزات آزمایشگاهی و اندازه گیری زیادی مواجه می ­شویم که به دلیل عدم ارائه خدمات مناسب از سوی نمایندگی­ های رسمی و انحصاری و فروشندگان کالاها، غیر قابل استفاده و خارج از سرویس می­باشند که از جمله این خدمات می ­توان به عدم تامین به موقع قطعات یدکی، اجرای صحیح کالیبراسیون ­های دوره­ای، تنظیمات دقیقا ادوات اندازه گیری، برگزاری دوره های آموزشی مناسب­، عیب یابی و تعمیر تجهیزات معیوب اشاره نمود ،در چنین شرایطی پتانسیل مراکز مذکور­، جهت اجرای امور محوله کاهش یافته و در نهایت شاخص­های بهره وری پایین خواهد آمد و در نتیجه چاره جویی و یافتن روش­ هایی جهت حل مشکلات ذکر شده همواره از دغدغه­ های مدیران این مراکز می­باشد.</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>مهارت در ارتباطات کتبی و شفاهی<br>آشنایی با اصول و استانداردهای حسابداری<br>توانایی کار به صورت تیمی<br>اخلاق حرفه‌ای بالا<br>آشنایی با قوانین مالیاتی<br>آشنایی با نرم‌افزارهای حسابداری (ترجیحا سپیدار)<br>دقت و توجه به جزئیات<br>توانایی انجام عملیات بانکی<br>قابلیت کار با اعداد و ارقام<br><br><strong>محل کار:</strong><br>تهران، منطقه ۷، عباس آباد</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس ۰۹۰۲۸۶۰۲۷۸۹ حاصل فرمائید.<br>&nbsp;</p>', NULL, NULL, 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-07 12:11:39', 'چهارشنبه 17 دی', '2026-01-07 08:41:39', '2026-01-07 08:41:39'),
(6812, 1, NULL, 'حسابدار', 'karbarg-public.png', 'رخشان پلیمر صنعت', 'تهران، منطقه ۲۱، وردآورد', NULL, NULL, '<p>شرکت دانش بنیان رخشان پلیمر صنعت در سال ۱۳۹۷ با استقرار در مرکز رشد فناوری پلیمر پژوهشگاه پلیمر و پتروشیمی ایران و با تکیه بر دانش فنی کادری متخصص و مجرب، فعالیت خود را در حوزه طراحی و تولید کامپاندهای پلیمری آغاز نمود و در حال حاضر در زمینه طراحی و تولید کامپاند های پلیمری مهندسی، کامپاند PP جهت پارچه ملت بلون (Meltblown) و همچنین طراحی و تولید مستربچ های افزودنی مورد استفاده در صنایع مختلف (خودرویی، الکتریکی و کشاورزی و …) فعالیت دارد. این شرکت در سال ۱۳۹۹ موفق به اخذ تاییدیه “دانش بنیان تولیدی” در تولید “کامپاند PP جهت پارچه ملت بلون” از سوی معاونت علمی ریاست جمهوری گردید.</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '30 تا 35 میلیون تومان', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>حسابدار مسلط به نرم‌افزار سپیدار، آشنا با سامانه مودیان، سامانه معاملات فصلی، ارزش افزوده و بیمه تامین اجتماعی<br>علاقه‌مند و پیگیر<br>دقت و توجه به جزئیات<br>مهارت در تهیه گزارش‌های مالی<br>توانایی کار به صورت تیمی<br>مهارت در مدیریت سوابق مالی<br>آشنایی با قوانین مالیاتی<br>توانایی حل مسئله<br><br><strong>ساعات کاری:</strong><br>8 الی 17<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه /پاداش /هدایای مناسبتی /کمک هزینه آموزشی<br><br><strong>محل کار:</strong><br>تهران، منطقه ۲۱، وردآورد</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس۴۴۷۸۷۰۶۴- ۰۲۱ &nbsp;حاصل فرمائید.<br>&nbsp;</p>', NULL, NULL, 'خانم', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-07 12:14:02', 'چهارشنبه 17 دی', '2026-01-07 08:44:02', '2026-01-07 08:44:02'),
(6813, 1, NULL, 'حسابدار', 'karbarg-public.png', 'گروه صنعتی تهویه آبسال نو', 'استان اصفهان ، شهرک صنعتی جی، خیابان یکم، فرعی 9، پلاک 144', NULL, NULL, '<p>گروه صنعتی آبسال نو، بزرگ‌ترین تولید کننده دریچه کولر و تهویه مطبوع با بیش از دو دهه تجربه در تولید و توزیع انواع دریچه های تنظیم هوا، دمپرهای صنعتی، کلاهک های پشت بامی، سایلنسرها و سایر محصولات در طرح، سایز و رنگ های متنوع با بهره گیری از استاندارد CE اروپا و سیستم مدیریت کیفیت ISO 9001 و دارنده نشان استاندارد ملی ایران، در کارخانه ای به مساحت 4000 متر مربع در شهرک صنعتی جی اصفهان واقع است.</p>', NULL, NULL, '60', 'اصفهان', '4', 'اصفهان', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>آشنایی با نرم‌افزارهای حسابداری نوآوران<br>آشنایی با اصول حسابداری و استانداردهای مالی<br>مهارت در مدیریت حساب‌ها و پیگیری پرداخت‌ها<br>مهارت در خزانه‌داری و بانک<br>دقت و توجه به جزئیات و تمرکز بالا<br>قابلیت کار تیمی<br><br><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه 8 الی 17 و پنجشنبه‌ها 8 الی 14<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه/ بیمه تکمیلی /پاداش /پورسانت/ وام /سرویس رفت و برگشت/ هدایای مناسبتی<br><br><strong>محل کار:</strong><br>استان اصفهان ، شهرک صنعتی جی، خیابان یکم، فرعی 9، پلاک 144</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس031۳۵۷۲۳۳۲۲ حاصل فرمائید.<br>&nbsp;</p><p>&nbsp;</p>', NULL, NULL, 'خانم', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-07 12:18:24', 'چهارشنبه 17 دی', '2026-01-07 08:48:24', '2026-01-07 08:48:24'),
(6814, 1, NULL, 'حسابدار', 'karbarg-public.png', 'توسعه راهکار هوشمند سرو', 'تهران، منطقه ۵، کوی بیمه', NULL, NULL, '<p>شرکت داده پرداز سرو هوشمند (سهامی خاص) با هدف ارائه راهکارهای نوآورانه و هوشمند برای کسب و کارها تاسیس شد. ما با تکیه بر دانش فنی و تخصص در زمینه هوش مصنوعی و یادگیری ماشین، مسیر موفقیت را برای مشتریان خود هموار می‌کنیم.</p><p>آنچه به عنوان یک ایده کوچک آغاز شد، امروز به مجموعه‌ای از متخصصان خلاق و نوآور تبدیل شده است که با اشتیاق به دنبال ارائه بهترین راهکارهای فناوری برای کسب و کارهای ایرانی هستند. در طول مسیر رشد خود، همواره به ارزش‌های اصلی خود یعنی نوآوری، کیفیت و رضایت مشتری پایبند بوده‌ایم.</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>تسلط بر اصول حسابداری<br>آشنایی با نرم‌افزارها و ابزارهای مالی<br>آشنایی کامل با قوانین بیمه و مالیات<br>دقت، مسئولیت‌پذیری و توانایی مدیریت امور مالی<br>آشنایی با قوانین مالیاتی مربوطه<br><br><strong>ساعات کاری:</strong><br>شنبه تا پنجشنبه 12 الی 20<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه/ ساعات کاری منعطف<br><br><strong>محل کار:</strong><br>تهران، منطقه ۵، کوی بیمه</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس ۰۲۱-۷۱۰۵۷۶۱۰ حاصل فرمائید.<br>&nbsp;</p>', NULL, NULL, 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-07 12:41:55', 'چهارشنبه 17 دی', '2026-01-07 09:11:55', '2026-01-07 09:11:55'),
(6816, 1066, 1167, 'حسابدار', NULL, 'سامانه صنعت پاژ', NULL, NULL, NULL, NULL, '09932196818', NULL, '167', 'چناران', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', 1, 'بیمه,سرویس رفت و برگشت,صبحانه,ناهار,پاداش و هدایا', NULL, '<p><strong>شرایط احراز:</strong><br>&nbsp;فعال و پویا<br>اخلاق حرفه‌ای بالا<br>دقت و توجه به جزئیات<br>آشنایی با نرم‌افزارهای حسابداری<br><br><strong>سابقه:</strong><br>&nbsp;5 سال سابقه کاری در زمینه حسابداری و مالیاتی<br>&nbsp;</p><p><strong>ساعات کاری:</strong><br>شنبه تا پنجشنبه - 8 الی 16<br><br><strong>مزایا:</strong><br>&nbsp;بیمه، سرویس رفت و برگشت، صبحانه، ناهار، هدایای مناسبتی<br>سرویس ایاب و ذهاب در محدوده وکیل آباد و قاسم آباد<br>محیط کاملا سالم و تمامی پرسنل اداری خانم می‌باشند<br>&nbsp;<br>**توجه**داشتن حداقل مدرک کارشناسی حسابداری الزامی می‌باشد.**</p><p><strong>حقوق :</strong><br>&nbsp;مبلغ بالا<br><br><strong>محل کار:</strong><br>شاندیز-شهرک صنعتی توس-فاز یک</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'حداقل 5 سال', NULL, 'خانم', 'کارشناسی', NULL, 'ایلیا', 'عالی', 'عالی', 'عالی', 'عالی', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-27 12:16:54', '2026-01-07 12:27:19'),
(6817, 1028, 1168, 'حسابدار', NULL, 'مرینو', NULL, NULL, NULL, NULL, '09120379207', NULL, '130', 'چهاردانگه', '8', 'تهران', 'تمام وقت', 'قانون کار', 0, 'بیمه,سرویس رفت و برگشت', NULL, '<p>مجموعه ما نیاز به یک حسابدار تمام وقت میباشد البته برای دانشجویان هم امکان استخدام فراهم است.دارای محیطی پویا و امکان رشد بسیار زیاد میباشد.نرم افزار مورد استفاده راهکاران بوده و امکان آموزش حین کار فراهم میباشد با تیمی حرفه ای و مجرب.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '1 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'راهکاران', 'کم', NULL, 'کم', NULL, NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-28 10:47:35', '2026-01-08 11:16:47'),
(6818, 1, NULL, 'حسابدار', 'karbarg-public.png', 'هدفمند ماشین', 'استان اصفهان، خیابان امام خمینی، خیابان 12 بهمن، خیابان سپاس پلاک 36', NULL, NULL, '<p>شرکت هدفمند ماشین با دو دهه تجربه در طراحی، تولید و تأمین تجهیزات پیشرفته صنعت طلا و جواهر، به عنوان یکی از پیشگامان این حوزه در ایران شناخته می‌شود. تخصص ما ارائه‌ی راهکارهای هوشمند و تجهیزات مدرن برای کارگاه‌های طلاسازی و ریخته‌گری است.</p><p>ما با تکیه بر دانش فنی، تیم متخصص، و همکاری با برندهای معتبر جهانی، تلاش کرده‌ایم تا به نیازهای روز صنایع طلا و جواهر پاسخ دهیم و کیفیت و بهره‌وری را در کارگاه‌های مشتریانمان ارتقا بخشیم.</p>', NULL, NULL, '60', 'اصفهان', '4', 'اصفهان', 'تمام وقت', '25 تا 30 میلیون تومان', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>حداقل 3 سال سابقه کار حسابداری در محیط صنعتی و تولیدی ، حقوق و دست مزد ، کنترل و حسابداری انبار، بیمه و مالیات<br>مدرک تحصیلی لیسانس حسابداری<br>آشنایی و تجربه کار با نرم افزارهای پارسیان<br>توانایی تحلیل و تفسیر داده های مالی با دقت به جزئیات<br>مهارت در مدیریت سوابق مالی<br>باهوش و متمرکز و وظیفه شناس<br>حقوق توافقی + بیمه + پاداش<br>آقا یا خانم ( آقا پایان خدمت الزامی)<br>ساکن شهر اصفهان<br><br><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه 8 الی 17 - پنجشنبه‌ها 8 الی 13<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه<br><br><strong>محل کار:</strong><br>استان اصفهان، خیابان امام خمینی، خیابان 12 بهمن، خیابان سپاس پلاک 36</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 09132044624 حاصل فرمائید.<br>&nbsp;</p>', '3 سال و کمتر', NULL, 'مهم نیست', 'کارشناسی', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-28 15:16:15', 'چهارشنبه 08 بهمن', '2026-01-28 11:46:15', '2026-01-28 11:46:15'),
(6819, 1, NULL, 'حسابدار', 'karbarg-public.png', 'شرکت وب تجارت رایمون', 'اصفهان،وحید،بلوار کشاورز،خ علامه جعفری', NULL, NULL, NULL, NULL, NULL, '60', 'اصفهان', '4', 'اصفهان', 'پاره وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>نوع همکاری: پاره وقت یا تمام وقت<br>نوع کار: ترکیبی (دورکاری و حضوری)<br>حقوق: توافقی<br>تحصیلات: حداقل کارشناس حسابداری<br>سابقه کار: بیش از 5 سال<br>ثبت و مدیریت کلیه اسناد و وقایع مالی و انجام فرآیندهای روتین حسابداری به صورت صفر تا صد<br>آشنایی با حق بیمه فروش‌های خدماتی و تسلط به پروسه دریافت مفاصا حساب تامین اجتماعی آن‌ها<br>تجربه حداقل 3 ساله در تحریر دفاتر قانونی، تهیه اظهارنامه مالیات بر عملکرد و دفاع از آن‌ها در دارایی<br>تسلط به مباحث حقوق و دستمزد و فرآیندهای مالی، قانونی و تکلیفی آن نظیر ارسال مالیات حقوق و لیست ماهانه بیمه<br>توانایی مدیریت مدارک، رسیدها و ضمانت‌های پرسنلی (نظیر سفته، رسیدهای دریافت انواع دستمزد، مرخصی و ...)<br>تسلط به آخرین قوانین مالیاتی، تامین اجتماعی و اداره کار<br>تسلط به امور مرتبط با مالیات بر ارزش افزوده و سامانه مودیان (معاملات فصلی)<br>توانایی ارائه گزارشات مالی مورد نیاز کارفرما (تراز، درآمد/هزینه، نقدینگی و ...)<br>تجربه حسابداری و امور مالیاتی رسانه‌ها و یا سایر کسب‌وکارهای دارای معافیت امتیاز محسوب می‌شود<br>تسلط نسبی به مایکروسافت Word و Excel<br>اشخاصی که در دوره گذشته افتخار همکاری با آن‌ها را نداشتیم نیز می‌توانند مجدد رزومه ارسال کنند.<br><br><strong>تسهیلات و مزایا:</strong><br>ساعات کاری منعطف/ امکان دورکاری/ بیمه تکمیلی /بیمه<br><br><strong>سایر مزایا:</strong><br>ساعت کاری منعطف<br>امکان دورکاری<br>بیمه تامین اجتماعی (در صورت همکاری تمام‌وقت)<br>بیمه تکمیلی و ...<br><br><strong>محل کار:</strong><br>اصفهان،وحید،بلوار کشاورز،خ علامه جعفری</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 09166802558 حاصل فرمائید.<br>&nbsp;</p>', 'حداقل 5 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-28 15:20:29', 'چهارشنبه 08 بهمن', '2026-01-28 11:50:29', '2026-01-28 11:50:29'),
(6820, 1, NULL, 'حسابدار', 'karbarg-public.png', 'وایب', 'تهران', NULL, NULL, '<p>وایب یک پلتفرم در حوزه فناوری‌های مالی (فین‌تک) است که با هدف تسهیل ارائه خدمات خرید اقساطی به کاربران فعالیت می‌کند و مأموریت خود را بر ایجاد دسترسی ساده، شفاف و بدون دغدغه به خرید اقساطی کالا و خدمات متمرکز کرده‌است.</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>ما در شرکت وایب، برای موقعیت کارشناس مالی و حسابداری مشتاق همکاری با شما هستیم.<br>فعالیت شرکت وایب در زمینه فناوری‌های مالی (فین‌تک) بوده و با هدف تسهیل ارائه خدمات خرید اقساطی، ماموریت ایجاد دسترسی ساده، شفاف و بدون دغدغه به خرید اقساطی کالا و خدمات را برای مشتریان دنبال می‌کند.<br>سابقه کار: حداقل 4 سال<br>حداکثر سن: 30 سال<br>تحصیلات: کارشناسی حسابداری و مالی<br>نوع همکاری: حضوری - تمام وقت<br><br><strong>شرح وظایف:</strong><br>ثبت روزانه اسناد حسابداری مطابق با فعالیت‌های مالی انجام شده.<br>ثبت فاکتورهای فروش، برگشت از فروش و رسیدهای دریافت به صورت روزانه<br>کنترل و ثبت گردش حساب‌های بانکی و رفع مغایرت‌ها<br>تهیه فایل حقوق و دستمزد ماهانه و ثبت اسناد حسابداری حقوق و دستمزد<br>تهیه و ارسال لیست بیمه و مالیات حقوق.<br>تهیه و آماده‌سازی فایل اظهارنامه ارزش افزوده شرکت مطابق با دفاتر حسابداری<br>تهیه و آماده‌سازی فایل گزارش فصلی شرکت مطابق با دفاتر حسابداری<br>رعایت استانداردها و مقررات مرتبط با حسابداری عمومی و اطمینان از تطابق با آن‌ها<br>ردگیری هزینه‌ها و گردآوری گزارشات هزینه‌های مالی ماهانه<br>انجام فرآیند مغایرت‌گیری هزینه‌های مالی با بخش‌ها و واحدهای مرتبط<br>پردازش و پیگیری درخواست‌های پرداخت<br>همکاری فعالانه با تیم حسابرسی در زمینه ارائه اسناد مالی و تجزیه و تحلیل مالی در مواقع بازرسی<br>توانایی گزارش‌دهی از امورات محوله در دوره‌های زمانی مشخص<br>مهارت پیشرفته در اکسل و ترجیحا آشنا به نرم‌افزار همکاران سیستم<br>آشنایی با قوانین مالیاتی، بیمه و گزارشات درون سازمانی<br>آشنایی با حسابداری اموال و انبار<br><br><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه ساعت 8:30 الی 17:00 + یک پنجشنبه در ماه ساعت 9 تا 13</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 021 9100 9442 حاصل فرمائید.<br>&nbsp;</p>', '3 تا 5 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-28 15:42:52', 'چهارشنبه 08 بهمن', '2026-01-28 12:12:52', '2026-01-28 12:12:52'),
(6821, 1, NULL, 'حسابدار', 'karbarg-public.png', 'نوید رنگ پدرام', 'تهران، منطقه ۳، امانیه', NULL, NULL, '<p>شرکت نوید رنگ پدرام (گروه مهندسی پدرام ) فعالیت خویش را از سال 1379 آغاز نمود. این شرکت که توسط دکتر قراویسکی اداره می شود، در زمینه رنگ های ساختمانی و رنگ های ضد حریق و پوشش های ضد حریق فعالیت می کند . در حال حاضر شرکت نوید رنگ پدرام یکی از قوی ترین شرکت های فعال در زمینه پوشش های ضد حریق می باشد و در لیست یا وندور آتش نشانی نیز حضور دارد.</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '30 تا 35 میلیون تومان', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>آشنایی با اصول و استانداردهای مالی و حسابداری<br>آشنایی با محاسبه حقوق و دستمزد و بیمه مالیات مربوطه<br>آشنایی با بهای تمام شده و گردش انبار<br>آشنایی با نحوه ثبت و کنترل ممیزی اسناد<br>آشنایی با نحوه محاسبات و اجرای بستن اسناد و محاسبه سود و زیان<br>آشنایی بانحوه تهیه اظهارنامه های مالیاتی ارزش افزوده و عملکرد<br>آشنایی با سامانه های مالیاتی و مالی<br>آشنایی با نرم افزار حسابداری<br>آشنایی با قوانین مالی و تجارت<br>دقت بالا در محاسبات<br>سیرت منظم و دقیق<br>توانایی حل مساله<br>مواظبت کامل در حفظ اسناد مالی<br>آشنایی با انواع گزارشات مالی<br>قابلیت برقراری ارتباط موثر<br>توجه به جزئیات<br>مدیریت زمان<br>توانایی کار گروهی<br><br><strong>ساعات کاری:</strong><br>شنبه الی چهارشنبه 8 تا 17 - پنج شنبه 8 تا 12 اضافه کار<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه<br><br><strong>محل کار:</strong><br>تهران، منطقه ۳، امانیه</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 1481825 - 0938 حاصل فرمائید.<br>&nbsp;</p>', NULL, NULL, 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-28 15:57:22', 'چهارشنبه 08 بهمن', '2026-01-28 12:27:22', '2026-01-28 12:27:22'),
(6822, 952, 1169, 'مدیر مالی', NULL, 'خدمات آوا گستر اندیشان', NULL, NULL, NULL, NULL, '09339735828', NULL, '418', 'همدان', '30', 'همدان', 'تمام وقت', 'توافقی', 1, '', NULL, '<p><strong>شرایط احراز:</strong><br>منظم و دقیق<br>متعهد به کار<br><br><strong>آشنا به :</strong><br>نرم افزار حسابداری لیام<br>سامانه مودیان<br>دفاتر پلمپ<br>بیمه-مالیات حقوق<br>امور مالیاتی-فاکتور رسمی-گزارشات مالی-انبار-اظهارنامه<br>سامانه جامع تجارت<br><br><strong>ساعت کاری:</strong><br>شنبه تا چهارشنبه 8 الی 17 - پنجشنبه‌ها 8 الی 15:30</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 سال و کمتر', NULL, NULL, NULL, NULL, 'لیام', 'خوب', 'خوب', 'کم', 'نیاز نیست', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-31 12:40:41', '2026-01-31 09:06:50'),
(6823, 1, NULL, 'حسابدار', 'karbarg-public.png', 'شرکت آرین رشد افزا', 'تهران، منطقه ۶، شهرک والفجر', NULL, NULL, '<p>شرکت آرین رشدافزا (آرا) در سال ۱۳۷۹ با هدفی روشن و نگاهی رو به آینده پا به عرصه گذاشت؛ هدفی بر پایه ارتقای صنعت دام، طیور و آبزیان کشور.</p><p>از ابتدا آرا کوشیده است به‌عنوان پلی مطمئن میان دانش روز جهانی و نیازهای صنعت ایران نقش‌آفرینی نماید؛ پلی که مسیر رشد، نوآوری و کیفیت را هموار می‌سازد.</p><p>امروز، آرا مجموعه‌ای است پویا، ریشه‌دار و حرفه‌ای که دامنه گسترده‌ای از فعالیت‌های تولیدی، وارداتی و خدمات علمی را عرضه می نماید. تولید کنسانتره‌ و مکمل‌های باکیفیت، واردات معتبرترین افزودنی‌های خوراک دام، طیور و آبزیان و ارائه پشتیبانی علمی تخصصی برای محصولات تولیدی و وارداتی همگی بازتاب تعهدی است که آرا از نخستین روز بر آن استوار بوده است: تعهد به کیفیت، دانش و اعتماد.</p><p>پشتوانه این مجموعه، تیمی از متخصصان کارآزموده در حوزه‌های تحقیق و توسعه، تولید، بازرگانی خارجی، مالی، فروش، تبلیغات و پشتیبانی است؛ نیروهایی که با هم‌افزایی تجربه و دانش خود، نقشی مؤثر در تأمین نیازهای بازار داخلی ایفا می‌کنند. حضور فعال در نمایشگاه‌های تخصصی، برگزاری همایش‌های علمی و اعزام کارشناسان به سراسر کشور برای بازدید از واحدهای تولیدی و ارائه مشاوره‌های فنی، بخشی از تعهد آرا به ارتقای سطح دانش و بهره‌وری صنعت است.</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '35 تا 40 میلیون تومان', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>دارا بودن سابقه کار (حداقل 3 سال) در موقعیت شغلی سرپرست، رئیس، مدیر مالی و حسابداری<br>دارا بودن مدرک حسابداری حداقل در مقطع کارشناسی<br>تسلط به سیستم قیمت گذاری و بهای تمام شده<br>تسلط کامل به مجموعه نرم افزاری آفیس (ICDL)<br>تسلط به اسناد انبار و مفاهیم انبار<br>تسلط کامل به نرم افزارهای حسابداری (و نرم افزارهای راهکاران سیستم)<br>آشنایی به مفاهیم و اصول حسابداری صنعتی<br>روابط عمومی و مهارتهای ارتباطی بالا با ذینفعان داخل و خارج سازمان<br>سابقه کار رسته مالی در صنعت دام و طیور و تامین نهاده و خوراک مزیت محسوب می شود.<br><br><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه 8 الی 17<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه/ بیمه تکمیلی/ پاداش/ وام /ناهار/ هدایای مناسبتی<br><br><strong>محل کار:</strong><br>تهران، منطقه ۶، شهرک والفجر</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس &nbsp;(30 خط)۴۲۹۱۸۰۰۰-۰۲۱ &nbsp;حاصل فرمائید.<br>&nbsp;</p>', '3 سال و کمتر', NULL, 'مهم نیست', 'کارشناسی', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-28 16:11:57', 'چهارشنبه 08 بهمن', '2026-01-28 12:41:57', '2026-01-28 12:41:57'),
(6824, 918, 1170, 'حسابدار', NULL, 'نکا پلاستیک', NULL, NULL, NULL, NULL, '09021101435', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'قانون کار', 0, 'بیمه,بیمه تکمیلی,سرویس رفت و برگشت', NULL, '<p>شرایط احراز :<br>کارشناسی حسابداری /کارشناسی بازرگانی /کارشناسی اقتصاد<br><br>مسلط به ثبت فاکتور&nbsp;<br>مسلط به حقوق و دستمزد&nbsp;<br>مسلط به ثبت سند حسابداری&nbsp;<br><br>نرم افزار حسابداری نیکان&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '1 سال', NULL, 'خانم', NULL, NULL, NULL, 'کم', 'کم', 'کم', 'نیاز نیست', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-29 07:43:37', '2026-01-29 07:43:37'),
(6825, 918, 1171, 'رییس حسابداری', NULL, 'نکا پلاستیک', NULL, NULL, NULL, NULL, '09021101435', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '45 تا 50 میلیون تومان', 10, 'بیمه,بیمه تکمیلی,سرویس رفت و برگشت', NULL, '<p>شرایط احراز:<br>مسلط به گزارش حسابرسی&nbsp;<br>مسلط به بهای تمام شده&nbsp;<br>مسلط به سامانه مودیان&nbsp;<br>مسلط به ارسال اظهارنامه&nbsp;<br>مسلط به مالیات&nbsp;<br><br>ساعت کاری:<br>8 الی 16:20<br><br>نرم افزار حسابداری نیکان&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 تا 5 سال', NULL, 'خانم', 'کارشناسی', NULL, NULL, 'خوب', 'خوب', 'خوب', 'خوب', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-29 07:43:58', '2026-01-29 07:43:58'),
(6826, 1039, 1172, 'سرپرست حسابداری', NULL, 'رامپکو', NULL, NULL, NULL, NULL, '09126876608', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '40 تا 45 میلیون تومان', 9, 'بیمه,بیمه تکمیلی,پاداش و هدایا,وام سازمانی,پزشک سازمانی', NULL, '<p>آشنا به حسابداری پیمانکاری و سامانه مودیان الزامی است.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'حداقل 5 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'همکاران سیستم', 'خوب', 'خوب', 'متوسط', 'نیاز نیست', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-29 07:46:11', '2026-01-29 07:46:11'),
(6827, 1041, 1173, 'حسابدار', NULL, 'گالری پارچه فلامینگو', NULL, NULL, NULL, NULL, '09153125889', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', 1, 'بیمه,پاداش و هدایا', NULL, '<p>آشنایی کامل به انبار بازرگانی&nbsp;</p><p>آشنایی به حقوق و دستمزد</p><p>توان کار با اکسل</p><p>داشتن نظم در کار و علاقه مند به کار تیمی و صداقت در کار</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2 سال', NULL, 'آقا', 'کاردانی', NULL, 'محک', 'خوب', 'کم', 'متوسط', 'نیاز نیست', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-29 07:47:22', '2026-01-29 07:47:22'),
(6828, 1040, 1174, 'حسابدار', NULL, 'ناوگان گستر کرانه', NULL, NULL, NULL, NULL, '09371109457', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', 1, 'بیمه', NULL, '<p><strong>شرح شغل و وظایف:</strong><br>ثبت و صدور اسناد حسابداری (دریافت، پرداخت و هزینه ها)<br>مغایرت گیری حساب و بانک‌ها<br>پیگیری مطالبات<br>صدور و کنترل فاکتورها</p><p><strong>شرایط استخدامی:</strong><br>آشنایی با نرم افزار سپیدار<br>آشنایی با حقوق و دستمزد (بیمه و مالیات)<br>آشنایی به امور مالیاتی (ارزش افزوده، سامانه ودیان و عملکرد)<br>دقیق / مسئولیت پذیر / قابل اعتماد<br>اولویت با افراد دارای آشنایی/سابقه حمل و نقل بین المللی</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 سال و کمتر', NULL, 'مهم نیست', 'مهم نیست', NULL, 'سپیدار', 'خوب', 'خوب', 'خوب', 'خوب', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-29 07:48:22', '2026-01-29 07:48:22'),
(6829, 1032, 1175, 'حسابدار', NULL, 'دیدگاه نوین', NULL, NULL, NULL, NULL, '09122908810', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '25 تا 30 میلیون تومان', 6, 'بیمه,سرویس رفت و برگشت,پاداش و هدایا', NULL, '<p><strong>شرایط احراز:</strong><br>استخدام حسابدار جهت ثبت اسناد حسابداری<br>مسلط به نرم افزار هلو و اکسل<br>چنانچه به مباحث بیمه ، مالیات و بهای تمام شده تسلط داشته باشید،<br>مبلغ حقوق افزایش خواهد داشت.<br><br><strong>آدرس:</strong><br>اتوبان آزادگان ، بعد از پل صنیع خانی ، بازار مرکزی آهن (آهن مکان) ، فاز دوم مرکزی ، پلاک 320 و321<br><br><strong>ساعت کاری:</strong><br>شنبه تا چهارشنبه 09:00 الی 17:30<br>پنجشنبه نیمه وقت<br><br><br><br><br>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 سال و کمتر', NULL, 'مهم نیست', NULL, NULL, 'هلو', 'خیلی خوب', NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-29 07:49:30', '2026-01-29 07:49:30'),
(6830, 1035, 1176, 'حسابدار', NULL, 'سانیکث', NULL, NULL, NULL, NULL, '09196011645', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '20 تا 25 میلیون تومان', 5, 'بیمه,پاداش و هدایا', NULL, '<p><strong>شرایط احراز:</strong><br>مدرک حسابداری یا امور مالی<br>سن : حداکثر 35 سال<br>کنترل روزانه حساب‌های بانکی شرکت و صدور اسناد<br>ثبت روزانه اسناد حسابداری عمومی اعم از هزینه‌های جاری، تنخواه و...<br>آشنایی به محاسبه حقوق و ارسال لیست بیمه و مالیات حقوق<br>آشنایی به نرم‌افزار سپیدار و حسابداری پیمانکاری مزیت می‌باشد.<br><strong>ساعت کاری:</strong><br>شنبه تا چهارشنبه 9 الی 17.30 پنج شنبه ها 9 الی 13<br><strong>محل کار:</strong><br>محدوده شهرک غرب نزدیک به مترو دادمان</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 سال و کمتر', NULL, 'مهم نیست', 'کارشناسی', NULL, 'سپیدار', 'خیلی خوب', 'متوسط', 'متوسط', 'نیاز نیست', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-29 07:53:56', '2026-01-29 07:53:56'),
(6831, 1028, 1177, 'حسابدار', NULL, 'مرینو', NULL, NULL, NULL, NULL, '09120379207', NULL, '130', 'چهاردانگه', '8', 'تهران', 'تمام وقت', '20 تا 25 میلیون تومان', 5, 'سرویس رفت و برگشت', NULL, '<p><strong>&nbsp;شرایط احراز :</strong><br>مسئولیت پذیر-پیگیر-با تعهد<br>ثبت کلیه حساب ها (بعد از آموزش کافی)<br>فرصت عالی برای رشد&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '1 سال', NULL, 'آقا', 'کارشناسی', NULL, 'راهکاران', 'کم', 'کم', 'متوسط', 'نیاز نیست', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-29 08:34:02', '2026-01-29 08:34:02'),
(6832, 1023, 1178, 'حسابدار', NULL, 'شریف تریپ', NULL, NULL, NULL, NULL, '09301923861', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '30 تا 35 میلیون تومان', 7, 'بیمه,بیمه تکمیلی,پاداش و هدایا', NULL, '<p><strong>شرایط احراز:</strong><br>انجام فعالیت‌های حسابداری به شکل روزانه، ماهانه، فصلی و سالیانه شامل تلفیق حساب‌های بانکی و کارت‌های اعتباری، تکمیل و هماهنگی حسابرسی سالانه و بازبینی گزارش‌های مالی و اقتصادی؛<br>تحلیل و گزارش وضعیت اقتصادی شامل شرح واریانس درآمد، مکاتبه با مدیریت برای نتایج مالی، آماده‌سازی بودجه و بررسی فعالیت‌های متفاوت اقتصادی؛<br>ثبت اسناد معاملات اقتصادی و تجاری؛<br>اصلاح فعالیت‌های سازمان به وسیله ارتقای سیستم مالی و پروسه‌های مختلف؛<br>آشنایی با اصول حسابداری و استانداردهای مالی<br>مهارت در مدیریت حساب‌ها و پیگیری پرداخت‌ها<br><strong>حقوق دریافتی برای فارغ التحصیلان دانشگاه تهران و دانشگاه شهید بهشتی تا 40 درصد بیشتر خواهد بود</strong></p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 تا 5 سال', NULL, 'مهم نیست', 'کارشناسی ارشد', NULL, NULL, 'خوب', 'متوسط', 'خوب', 'خوب', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-29 08:35:28', '2026-01-29 08:35:28'),
(6833, 1015, 1179, 'رییس حسابداری', NULL, 'آبتین تجارت فولاد ونداد', NULL, NULL, NULL, NULL, '09121541161', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', '45 تا 50 میلیون تومان', 10, 'بیمه', NULL, '<p><strong>شرایط احراز :</strong></p><ol><li>نظارت بر فعالیت‌های روزانه حسابداری: کنترل ثبت اسناد مالی، بررسی صحت دفاتر و اطمینان از رعایت استانداردهای حسابداری&nbsp;</li><li>&nbsp;</li><li>تهیه و ارائه گزارش‌های مالی: تدوین صورت‌های مالی، گزارش سود و زیان، ترازنامه و ارائه آن به مدیر مالی یا مدیرعامل&nbsp;</li><li>&nbsp;</li><li>اجرای سیاست‌ها و کنترل‌های داخلی: پیاده‌سازی سیستم‌های جدید حسابداری، به‌روزرسانی کنترل‌های داخلی و پایش هزینه‌ها&nbsp;</li><li>&nbsp;</li><li>تحلیل و بررسی داده‌های مالی: انجام تحلیل‌های مالی برای تصمیم‌گیری‌های مدیریتی و ارائه پیشنهادهای بهبود روند کار&nbsp;</li><li>&nbsp;</li><li>مدیریت تیم حسابداری: هدایت، آموزش و ارزیابی عملکرد کارکنان حسابداری و تقسیم وظایف بین اعضای تیم&nbsp;</li><li>&nbsp;</li><li>همکاری با سایر بخش‌ها: ارتباط با واحدهای فروش، تولید یا پیمانکاری برای هماهنگی امور مالی و حسابداری&nbsp;</li><li>&nbsp;</li><li>اطمینان از رعایت قوانین و مقررات مالیاتی: بررسی و کنترل اظهارنامه‌های مالیاتی و تطابق با قوانین جاری&nbsp;</li><li><strong>&nbsp;</strong><br><strong>مهارت‌های مورد نیاز :</strong><br>تسلط بر نرم‌افزارهای حسابداری (سپیدار، هلو، راهکاران)<br>دانش قوانین مالیاتی و بیمه‌ای<br>توانایی مدیریت تیم و مهارت‌های رهبری<br>دقت بالا و توجه به جزئیات<br>مهارت‌های ارتباطی و گزارش‌دهی شفاف</li></ol><ul><li>- کارآموز حسابداری آشنا “به نرم افزار سپیدار” پذیرفته می شود.</li></ul>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'حداقل 5 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'سپیدار', 'خیلی خوب', 'خیلی خوب', 'خوب', 'خوب', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-29 08:39:31', '2026-01-29 08:39:31'),
(6834, 1012, 1180, 'حسابدار', NULL, 'نیمه دولتی', NULL, NULL, NULL, NULL, '09399940612', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '35 تا 40 میلیون تومان', 8, 'بیمه,بیمه تکمیلی,ناهار,وام سازمانی,پزشک سازمانی,سرانه آموزشی', NULL, '<p><strong>شرایط &nbsp;احراز:</strong><br>یک شرکت معتبر تولیدی و &nbsp;جهت تکمیل کادر مالی خود از افراد واجد شرایط زیر در تهران دعوت به همکاری می‌نماید.<br>آشنایی با اصول حسابداری و توانایی ثبت اسناد روزانه<br>توانایی تهیه و ارسال گزارشات فصلی<br>تسلط به نرم‌افزارهای office&nbsp;<br>دارای سابقه کار مرتبط (اولویت محسوب می‌شود)<br>دارای ویژگی‌های شخصیتی: دقیق، منضبط، مسئولیت‌پذیر، علاقه‌مند به یادگیری و پیشرفت و &nbsp;و بدون حاشیه<br>جنسیت :آقا<br>نوع همکاری: تمام وقت<br>ساعات کاری :<br>شنبه تا چهارشنبه 7 الی 17 - پنجشنبه‌ها همیشگی نیست در صورت نیاز به صورت اضافه کار&nbsp;<br>محیط کاری پویا و حرفه‌ای<br>امنیت شغلی<br>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'نیاز نیست', NULL, 'آقا', 'کارشناسی', NULL, 'راهکاران', 'خیلی خوب', 'متوسط', 'متوسط', 'متوسط', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-29 08:41:04', '2026-01-29 08:41:04'),
(6835, 1007, 1181, 'حسابدار', NULL, 'لوازم یدکی رشیدیان', NULL, NULL, NULL, NULL, '09158946889', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', '15 تا 20 میلیون تومان', 4, 'صبحانه,ناهار,پاداش و هدایا', NULL, '<p><strong>شرایط احراز:</strong><br>به یک حسابدار جهت فعالیت در فروشگاه رشیدیان با شرایط زیر نیازمندیم :<br>متعهد و امانت دار&nbsp;<br>توانایی فعالیت گروهی&nbsp;<br>مسلط به نرم افزار حسابداری محک&nbsp;<br>مسلط به افیس&nbsp;<br>شرکت در کلاس های آموزشی مورد تایید مجموعه&nbsp;<br>خلاق و پویا بودن&nbsp;<br>پایه حقوق 15 میلیون تومان که باتوجه به تسلط و توانایی قابل افزایش است&nbsp;<br><br><strong>ساعت کاری:</strong><br>شنبه تا چهارشنبه از 8 الی 18 وپنج شنبه ها 8 الی 15<br><br><strong>آدرس محل کار:</strong><br>خیابان امام رضا (علیه اسلام) 38، چهارراه اول سمت چپ، فروشگاه رشیدیان<br>&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '1 سال', NULL, 'آقا', NULL, NULL, 'محک', 'متوسط', 'متوسط', 'متوسط', 'متوسط', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-01-29 08:41:51', '2026-01-29 08:41:51'),
(6837, 1, NULL, 'حسابدار', 'karbarg-public.png', 'بازرگانی سرو خراسان', 'خیابان گاراژدارها - نبش کوشش 27 - پلاک 2 الی 8 بازرگانی سرو خراسان', NULL, NULL, '<p>واردات الکترود جوشکاری با برند توحید و sh از کشور چین در سایزهای 2/5 - 3 - 4 واردات سنگهای فرز با برند توحید ( ساب - مینی ساب - برش - مینی برش و پروفیل بر ) واردات ابزارآلات آرماتوربندی ( آرماتور قطع کن ( تا 25 ) - آرماتور خم کن و خاموت زن( تا32 )</p>', NULL, NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>حداقل 4 سال سابقه کار<br>آشنا به امور مالیاتی<br><br><strong>ساعات کاری:</strong><br>8 الی 16<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه<br><br><strong>سایر مزایا:</strong><br>حقوق بالاتر از قانون کار با مزایا و بیمه<br><br><strong>محل کار :</strong><br>خیابان گاراژدارها - نبش کوشش 27 - پلاک 2 الی 8 بازرگانی سرو خراسان<br>&nbsp;</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس۰۹۳۷۱۸۷۰۱۴۹ &nbsp;حاصل فرمائید.<br>&nbsp;</p>', '3 تا 5 سال', NULL, 'خانم', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-29 12:24:10', 'پنج شنبه 09 بهمن', '2026-01-29 08:54:10', '2026-01-29 08:54:10'),
(6838, 1, NULL, 'حسابدار', 'karbarg-public.png', 'طلای ناب کیهان', 'اصفهان، اصفهان، منطقه ۵، کوی امام جعفر صادق', NULL, NULL, '<p>&nbsp;شرکت طلای ناب کیهان با برند زرناب از سال ۱۳۷۶، با هدف تولید محصولات لبنی سالم، طبیعی و با کیفیت آغاز به کار کرد و به‌سرعت در میان مصرف‌کنندگان ایرانی جایگاهی ویژه پیدا کرد. زرناب، نماد اصالت و نوآوری در صنعت لبنیات ایران، با تکیه بر دانش فنی روز دنیا و استفاده از مواد اولیه مرغوب، مجموعه‌ای کامل از محصولات لبنی از جمله ماست سنتی، شیر تازه، پنیر و خامه را تولید و عرضه می‌کند. با افتخار، زرناب با رعایت استانداردهای بین‌المللی و بهره‌گیری از فناوری‌های نوین، علاوه بر بازار داخلی، در بازارهای صادراتی نیز حضور موفقی دارد.</p>', NULL, NULL, '60', 'اصفهان', '4', 'اصفهان', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>دارای حداقل مدرک کارشناسی در رشته‌های حسابداری، مدیریت و مهندسی<br>آشنایی و تسلط به اکسل (فرمول‌نویسی) و ورد<br>قدرت تجزیه و تحلیل<br>روابط عمومی بالا<br>توانایی کار تیمی<br>مسئولیت‌پذیری<br><br><strong>ساعات کاری:</strong><br>شنبه تا پنجشنبه از ساعت 08:00 الی 17:00<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه /بیمه تکمیلی<br><br><strong>محل کار:</strong><br>اصفهان، اصفهان، منطقه ۵، کوی امام جعفر صادق</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 03152374596 حاصل فرمائید.<br>&nbsp;</p>', NULL, NULL, 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-29 12:31:42', 'پنج شنبه 09 بهمن', '2026-01-29 09:01:42', '2026-01-29 09:01:42'),
(6839, 1, NULL, 'حسابدار', 'karbarg-public.png', 'شرکت صنعتی آموت سپهر', 'تهران، منطقه ۷، عباس آباد', NULL, NULL, '<p>شركت صنعتی آموت سپهر (سهامی خاص) در سال 1381 با هدف اجرای پروژه هاى اجرايى و مشاوره مهندسى در حوزه هاى صنعت، نفت و گاز و پتروشيمى، ساختمان، آب ، راه آهن و مترو &nbsp;تاسيس گرديد.این شركت با پشتوانه ى سالها تجربه در پروژه هاى صنعتى، پژوهشى و راه آهن و با انگيزه ى ارائه خدمات به صنعت كشور و ارتقاء دانش فنى پايه گذارى گرديده است. پايه گذاران اين شركت ايمان دارند تنها با پشتكار و فعاليت سخت در كنار برنامه ريزى مى توان راه هاى توسعه و پيشرفت را براى كشور عزيزمان هموار نمود.</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>آشنایی به اصول حسابداری<br>آشنایی به سیستم سپیدار<br>شرایط سن 22 الی 27<br>مهارت در تهیه گزارش‌های مالی<br>توانایی انجام عملیات بانکی<br>قابلیت کار با اعداد و ارقام<br>آشنایی با نرم‌افزارهای حسابداری<br><br><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه 8 الی 17 - پنجشنبه‌ها 8 الی 13<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه<br><br><strong>سایر مزایا:</strong><br>بیمه از شروع کار<br><br><strong>محل کار:</strong><br>تهران، منطقه ۷، عباس آباد</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس ۰۲۱۸۸۵۰۳۵۱۳ - 02188521714 حاصل فرمائید.<br>&nbsp;</p>', NULL, '27', 'آقا', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-29 12:35:40', 'پنج شنبه 09 بهمن', '2026-01-29 09:05:40', '2026-01-29 09:05:40');
INSERT INTO `ads` (`id`, `company_id`, `order_id`, `title`, `company_logo`, `company_name`, `company_address`, `company_type`, `company_size`, `company_description`, `owner_cellphone`, `category`, `city`, `city_name`, `province`, `province_name`, `employment_type`, `salary`, `salary_range`, `company_advantages`, `job_hours`, `job_description`, `job_terms`, `skills_required`, `job_tasks`, `job_benefits`, `positives`, `negatives`, `resume_terms`, `minimum_work_experience`, `max_age`, `gender`, `minimum_degree`, `military_service_status`, `company_software`, `excel_skill`, `maliat_skill`, `bimeh_skill`, `baha_skill`, `sorat_skill`, `bazargani_skill`, `hesabdar`, `onsite_days`, `onsite_hours`, `status`, `hired`, `type`, `paid`, `refunded`, `refundable`, `verified`, `expired`, `publish_date`, `publish_date_fa`, `created_at`, `updated_at`) VALUES
(6840, 1, NULL, 'حسابدار', 'karbarg-public.png', 'لبنیات و بستنی دومینو', 'استان تهران، چهاردانگه', NULL, NULL, '<p>شرکت دومینو فعالیت رسمی خود را در بازار بستنی و لبنیات ایران از سال ۱۳۹۰ آغاز کرد. این برند با پشتوانه‌ی بیش از ۳۰ سال تجربه بنیان‌گذاران خود در صنعت بستنی و لبنیات، توانست رویکردی نوآورانه و متمایز را در بازارهای داخلی و بین‌المللی ارائه دهد. در دهه نخست فعالیت، دومینو با تمرکز بر تولید محصولات متنوع و متناسب با ذائقه مصرف‌کنندگان، جایگاه ویژه‌ای در این صنعت به دست آورد.</p><p>دومینو امروز به عنوان یکی از بازیگران اصلی و پیشگامان این صنعت در ایران شناخته می‌شود و توانسته است با ارائه جدیدترین طعم‌ها و متنوع‌ترین سبد بستنی، نقش مهمی در بازار ایفا کند. شعار «برای رشد و شادی»، بازتابی از تعهد این مجموعه به خلق تجربه‌های لذت‌بخش و سالم برای مصرف‌کنندگان است.</p><p>استفاده از بهترین و مرغوب‌ترین مواد اولیه، احداث بزرگ‌ترین واحد تحقیق و توسعه صنعت لبنیات و بستنی در ایران، راه‌اندازی مدرن‌ترین آزمایشگاه‌ شیر کشور و برقراری ارتباطی سازنده و صمیمانه با مصرف‌کنندگان، بخشی از اقداماتی است که دومینو در راستای تحقق این هدف دنبال می‌کند.</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرح وظایف:</strong><br>ثبت و صدور فاکتور فروش و اسناد حسابداری فروش<br>کنترل اسناد حسابداری فروش<br>کنترل محاسبات مرتبط با جشنواره های فروش<br>کنترل محاسبات مرتبط با پورسانت فروش<br>ثبت و کنترل اسناد مرتبط با تسویه فروش<br>بررسی و رفع مغایرت های احتمالی در حسابداری فروش<br>تهیه گزارشات دوره ای<br><br><strong>شرایط شغلی:</strong><br>مسلط به راهکاران (ماژول فروش)<br>مسلط به کدینگ حسابداری مرتبط با فروش<br>مسلط به اکسل<br>مسلط به اصطلاحات مرتبط با فروش<br>آشنایی با سامانه مودیان و اظهارنامه ارزش افزوده<br><br><strong>ویژگی های شخصیتی:</strong><br>روحیه کار تیمی و انعطاف پذیر<br>دارای اخلاق حرفه ای<br>مدیریت زمان مسئولیت پذیر<br>منظم<br>خلاق<br>سازگاری با محیط کاری پرتحرک<br>انجام محاسبات مالی مربوط به فروش<br>تهیه گزارشات فروش<br><br><strong>تسهیلات و مزایا:</strong><br>وام/ پاداش /بیمه تکمیلی/ ناهار /پزشک سازمانی /صبحانه/هدایای مناسبتی<br><br><strong>سایر مزایا:</strong><br>وام<br>پاداش<br>بیمه درمان تکمیلی<br>ناهار<br>پزشک سازمانی<br>صبحانه<br>بسته ها و هدایای مناسبتی<br><br><strong>محل کار:</strong><br>استان تهران، چهاردانگه</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 982155243111+ حاصل فرمائید.<br>&nbsp;</p>', NULL, NULL, 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-29 12:42:37', 'پنج شنبه 09 بهمن', '2026-01-29 09:12:37', '2026-01-29 09:12:37'),
(6841, 1, NULL, 'حسابدار', 'karbarg-public.png', 'گروه صنعتی و معدنی زرین خاورمیانه', 'تهران، منطقه ۲، سعادت آباد', NULL, NULL, '<p>گروه صنعتی و معدنی زرین یکی از بزرگترین و پیشروترین شرکت‌های تولیدکننده کنسانتره و شمش سرب و روی در ایران و خاورمیانه است. این گروه با بهره‌گیری از فناوری‌های پیشرفته و نیروی کار متخصص، در اکتشاف، استخراج، فرآوری و تغلیظ مواد معدنی فعالیت می‌کند و از طریق تولید محصولات استراتژیک، ارزش افزوده بالایی ایجاد می‌کند.</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>دارای حداقل 3 سال سابقه کار در انبار و اموال و بهای تمام شده، گزارشات فصلی و اظهارنامه ارزش افزوده و سامانه مودیان<br>آشنایی با قوانین مالیاتی، سامانه مودیان و پایانه‌های فروشگاهی و قانون تجارت<br>آشنایی با راهکاران سیستم<br>مسلط به مایکروسافت آفیس<br>دارای مدرک کارشناسی حسابداری و بالاتر<br>دارای حداکثر 30 سال سن<br>تسلط به خزانه داری<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه تکمیلی پاداش<br><br><strong>سایر مزایا:</strong><br>بن کارت<br>پاداش<br>بیمه تکمیلی<br><br><strong>محل کار:</strong><br>تهران، منطقه ۲، سعادت آباد</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس02125902000حاصل فرمائید.<br>&nbsp;</p>', '3 سال و کمتر', '30', 'آقا', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-29 12:49:16', 'پنج شنبه 09 بهمن', '2026-01-29 09:19:16', '2026-01-29 09:19:16'),
(6842, 1, NULL, 'حسابدار', 'karbarg-public.png', 'هولدینگ رهصان', 'خراسان رضوی، مشهد، منطقه ۹، محله هنرستان', NULL, NULL, '<p>شرکت دانش بنیان رهیافت های هوشمند صدری ایرانیان (رهصان)، عضو پارک علم و فناوری خراسان، ارائه دهنده خدمات متنوعی شامل مشاوره، طراحی، تامین کالا، بازرگانی و واردات، ساخت استراکچر خورشیدی و تابلوبرق حفاظتی و نصب و راه اندازی &nbsp;و بهره برداری و نگهداری نیروگاه های خورشیدی میباشد. این مجموعه به عنوان یک شرکت با تجربه و مورد تایید شرکت‌های توزیع در زمینه پیمانکاری نیروگاه خورشیدی در سطح کشور شناخته می‌شود.</p>', NULL, NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', '20 تا 25 میلیون تومان', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>آشنایی با نرم افزارهای حسابداری<br>آشنایی با اصول حسابداری<br>انجام محاسبات با سرعت و دقت<br>آشنایی با نرم افزار تدبیر و اکسل<br>توانایی کار در تیمی<br><br><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه از ساعت 08:00 تا 16:00 پنج‌شنبه از ساعت 08:00 تا 14:30<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه<br><br><strong>سایر مزایا:</strong><br>دارای بیمه<br>حقوق از 20 میلیون تومان (بسته به توانمندی قابل افزایش)<br>دارای شرایط پیشرفت کاری<br>مزایا عالی<br><br><strong>محل کار:</strong><br>خراسان رضوی، مشهد، منطقه ۹، محله هنرستان</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 09120223305حاصل فرمائید.<br>&nbsp;</p>', NULL, NULL, 'خانم', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-29 12:52:15', 'پنج شنبه 09 بهمن', '2026-01-29 09:22:15', '2026-01-29 09:22:15'),
(6843, 1, NULL, 'حسابدار', 'karbarg-public.png', 'صنایع فلزی کاوش کام آسیا', 'تهران، منطقه ۳، اختیاریه', NULL, NULL, '<p>شرکت صنایع فلزی کاوشکام آسیا (KVC) در سال 1384 تاسیس شد و با به کارگیری کارشناسان متخصص در تولید دکل های مخابراتی، این شرکت توانست سرعت، دقت و کیفیت خود را در این صنعت به اثبات برساند. این شرکت پس از بیش از یک دهه فعالیت موفق شد بخش زیادی از نیc ازهای داخلی کشور را تامین کرده و رضایت مشتریان بین المللی را نیز جلب نماید. KVC در حال حاضر با بیش از 100 پرسنل مجرب مشغول به فعالیت بوده و دارای مجوز از شرکت ارتباطات سیار ایران (MCI) و شرکت ایرانسل (MTN) و اتحادیه مجریان و مشاوران خدمات مهندسی پیمانکاران مخابرات در ایران می باشد.</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>ترجیحا آشنا به امور حسابرسی بیمه شرکت‌ها<br><br><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه 8 الی 17<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه ناهار<br><br><strong>محل کار:</strong><br>تهران، منطقه ۳، اختیاریه</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس (۰۲۱)۲۶۷۴۹۰۱۱داخلی ۱۲۱ حاصل فرمائید.<br>&nbsp;</p>', NULL, NULL, 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-29 12:54:42', 'پنج شنبه 09 بهمن', '2026-01-29 09:24:42', '2026-01-29 09:24:42'),
(6844, 1, NULL, 'حسابدار', 'karbarg-public.png', 'آسا صنعت ساتیا', 'تهران، منطقه ۳، قلهک - خیابان سیمای شمالی - انتهای بن بست میرزاتاراج پلاک 31', NULL, NULL, '<p>شرکت آسا صنعت ساتیا به عنوان یکی از معتبرترین شرکت های واردکننده و تأمین کننده مواد اولیه لاستیک مانند کائوچوی طبیعی، کائوچوی مصنوعی، سیلیکون رابر HTV، دوده صنعتی، مواد پخت لاستیک، شتاب دهنده، آنتی اکسیدان &nbsp;فروش و ساخت انواع کامپاند لاستیک، با سابقه و تجربه طولانی در امر خرید و فروش آمادگی دارد تا خدمات خود را بهترین شیوه ممکن به شما عزیزان ارائه دهد.<br>در ادامه می توانید با انواع محصولات مواد اولیه قابل عرضه توسط این مجموعه و مزایای خرید از ما آشنا شوید.</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>دقیق، منظم، مسئولیت‌پذیر و پیگیر<br>مسلط به امور حسابداری مالی و مالیاتی<br>تسلط کامل با سامانه مودیان مالیاتی، اظهارنامه ارزش افزوده، ارسال معاملات فصلی، سامانه حقوق و دستمزد سازمان امور مالیاتی و سازمان تامین اجتماعی<br>تسلط کامل به حسابداری بازرگانی (خرید، انبار...)<br>تسلط کامل به برنامه آفیس بالاخص اکسل<br>آشنایی با قوانین مالیاتی و بیمه<br>آشنایی با نرم‌افزارهای مالیاتی<br>آشنایی به امور حسابداری مربوط به واردات و صادرات<br>آشنایی با نحوه و تهیه صورت‌های مالی<br><br><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه 7 الی 16:30 - پنجشنبه‌ها 8 الی 12:30 (بصورت شیفتی)<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه/ بیمه تکمیلی/ پاداش/ وام /صبحانه/ هدایای مناسبتی/ تسهیلات گردشگری<br><br><strong>محل کار:</strong><br>تهران، منطقه ۳، قلهک - خیابان سیمای شمالی - انتهای بن بست میرزاتاراج پلاک 31</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 031-33687194 حاصل فرمائید.<br>&nbsp;</p>', NULL, NULL, 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-29 13:07:54', 'پنج شنبه 09 بهمن', '2026-01-29 09:37:54', '2026-01-29 09:37:54'),
(6845, 1, NULL, 'حسابدار', 'karbarg-public.png', 'سحاب', 'تهران، منطقه ۳، قبا', NULL, NULL, '<p>به منظور رسیدگی به امور رفاهی بسیجیان و بر اساس بند ث ماده 3 اساسنامه صندوق ذخیره بسیجیان، سامانه حمایتی، اجتماعی بسیجیان (سحاب) ایجاد گردید. بسیجیان دارای شرایط عضویت در صندوق می توانند پس از ثبت نام و تایید عضویت،از خدمات این سامانه استفاده نمایند.</p><p>&nbsp;</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>حداقل 3 سال تجربه‌ی کاری در حوزه‌ی حسابداری<br>دارای مدرک کارشناسی حسابداری<br>تسلط به ثبت اسناد حسابداری و آشنایی با مفاهیم پایه‌ی حسابداری مالی<br>تجربه‌ی کار با سامانه مودیان و ارسال صورت‌حساب‌های الکترونیکی<br>آشنایی با فرآیند ثبت اسناد تنخواه، بانک و خزانه<br>آشنایی مناسب با قوانین بیمه و مالیات و اثر آن‌ها روی ثبت اسناد<br>دقت بالا، نظم شخصی و توجه به جزئیات در ثبت و کنترل اطلاعات مالی<br><br><strong>وظایف و مسئولیت‌ها:</strong><br>ثبت روزانه‌ی اسناد حسابداری در سرفصل‌های مربوطه و اطمینان از کامل بودن مدارک<br>ثبت و کنترل تنخواه‌ها، تسویه به‌موقع و تطبیق آن با اسناد و گزارش‌ها<br>ثبت عملیات بانک و خزانه، شامل دریافت و پرداخت‌ها، چک‌ها و تطبیق مانده‌ها با صورت‌حساب بانکی<br>همراهی در اجرای قوانین بیمه و مالیات در ثبت اسناد مرتبط با حقوق، خرید، فروش و سایر هزینه‌ها<br>همکاری در اجرای الزامات سامانه مودیان و ثبت و کنترل صورت‌حساب‌های الکترونیکی<br>تهیه گزارش‌های ساده مالی (مانده حساب‌ها، گزارش تنخواه، وضعیت بانک و خزانه) برای استفاده‌ی تیم مالی<br>همکاری نزدیک با سایر اعضای تیم مالی برای بستن ماهانه‌ی حساب‌ها و رفع مغایرت‌ها<br><br><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه 8 الی 17 به همراه شناوری<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه /بیمه تکمیلی /وام /ساعات کاری منعطف/ صبحانه/ ناهار/ میان‌وعده /هدایای مناسبتی/ فضای استراحت<br><br><strong>حقوق ثابت ماهانه:</strong><br>۳۰ تا ۵۰ میلیون تومان<br><br><strong>محل کار:</strong><br>تهران، منطقه ۳، قبا</p>', NULL, NULL, NULL, NULL, '', '', '<p><span style=\"background-color:rgb(255,255,255);color:rgb(63,66,84);\">ب</span>رای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 02141013000 حاصل فرمائید.<br>&nbsp;</p>', '3 سال و کمتر', NULL, 'مهم نیست', 'کارشناسی', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-31 15:36:24', 'شنبه 11 بهمن', '2026-01-31 12:06:24', '2026-01-31 12:06:24'),
(6846, 1, NULL, 'حسابدار', 'karbarg-public.png', 'صنایع آرنیکا نساج آرمان', 'استان تهران، چهاردانگه', NULL, NULL, '<p>&nbsp;حوزه فعالیت پارچه رومبلی و تکمیل پارچه گردباف است .</p><p>&nbsp;</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>ثبت فاکتور خرید و فروش<br>دریافت و پرداخت، امور خزانه‌داری<br>ثبت کلیه هزینه‌های جاری و کدینگ حسابداری<br>حقوق، بیمه، مالیات بر حقوق<br>امور انبار (رسید و حواله)، انبارگردانی<br>پیگیری مطالبات و مغایرت‌گیری صورت‌حساب اشخاص<br>ثبت سفارش تلفنی و حضوری<br>انجام وظایف به موقع<br>دقت و صراحت در کار<br>توانایی انجام محاسبات دقیق<br>آشنا به نرم افزارهای حسابداری (سپیدار)<br><br><strong>ساعات کاری:</strong><br>شنبه تا پنجشنبه 9:30 الی 18:30<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه/صبحانه /هدایای مناسبتی<br><br><strong>محل کار:</strong><br>استان تهران، چهاردانگه</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 66301004-66301005 حاصل فرمائید.<br>&nbsp;</p>', NULL, NULL, 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-31 15:38:39', 'شنبه 11 بهمن', '2026-01-31 12:08:39', '2026-01-31 12:08:39'),
(6847, 1, NULL, 'حسابدار', 'karbarg-public.png', 'کیمیا اکسیر شرق', 'خراسان رضوی، مشهد، منطقه ۱۱، فرهنگ', NULL, NULL, '<p style=\"margin-right:0px;\">&nbsp;بزرگ ترین تولید کننده&nbsp; انواع کودهای آلی وشیمیایی کشاورزی با ۲۰سال سابقه فعالیت و با تنوع گسترده وبسته بندی های لمینت شده صادراتی&nbsp; که از لحاظ کیفیت بسته بندی و قیمت قابل رقابت با محصولات خارجی می باشد.</p><p style=\"margin-right:0px;\">دارای تفاهم نامه با شرکت خدمات حمایتی کشاورزی کل کشور.</p><p style=\"margin-right:0px;\">مجهز به آزمایشگاه آب وخاک.</p><p style=\"margin-right:0px;\">تمامی محصولات دارای تاییدیه و ثبت کودی و مجوز آب و خاک می باشند.</p><p style=\"margin-right:0px;\">قابل عرضه به تمامی نقاط کشور</p>', NULL, NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>حسابداری خزانه<br>توانایی کار با اسناد مالی<br>دانش از قوانین مالیاتی ایران<br>آشنایی با نرم‌افزار حسابداری<br>تسلط به اصول و مبانی حسابداری<br>انجام کارهای روزمره به صورت مستقل<br>دقت بالا در انجام محاسبات<br>آشنایی با سیستم‌های بانکی<br><br><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه 8 الی 16 - پنج شنبه ها 8 الی 15<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه /بیمه تکمیلی/ فضای استراحت<br><br><strong>محل کار:</strong><br>خراسان رضوی، مشهد، منطقه ۱۱، فرهنگ</p>', NULL, NULL, NULL, NULL, '', '', '<p>.برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس ۰۹۱۵۳۰۸۸۵۸۸ حاصل فرمائید.<br>&nbsp;</p>', NULL, NULL, 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-31 15:43:40', 'شنبه 11 بهمن', '2026-01-31 12:13:40', '2026-01-31 12:13:40'),
(6848, 1, NULL, 'حسابدار', 'karbarg-public.png', 'شادی ژرف ایرانیان', 'تهران، منطقه ۶، نصرت', NULL, NULL, '<p>مفتخریم که ما اولین، معتبرترین و بزرگترین شرکت پخش کننده اقلام و لوازم قنادی در سطح کشور هستیم. چون سعی کرده ایم بهترین ها را گرد هم آوریم و در این راه لطف خدا، تلاش همه جانبه کلیه همکاران متعهد و متخصص موجبات این امر را فراهم آورده است.<br>در این شرکت بر آن شدیم تا در کنار هم و با هم، با شش &nbsp;\"ه \" عالی (همراهی، همنوردی، هم چراغی، همدلی، همکاری و هم افزایی) از تجربیات افراد خبره و با تجربه در راستای بهبود مستمر شرکت خود بهره ببریم، چون هدف ما ممتاز ماندن است.</p><p>افزایش دانش، بهره وری و توانمند سازی &nbsp;و همچنین حفظ روحیه و انگیزه سرمایه های انسانی که والاترین دارایی سازمان میباشند از اهداف اصلی سازمان میباشد زیرا معتقدیم بقای ما در گروه رشد و شکوفایی و بالندگی همکارانمان میباشد</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>شرکت آسان پخش شادی (محل: غرب تهران)<br>ما در تیم مالی خود یک نفر کارشناس حسابداری نیازمندیم.<br>مقطع تحصیلی: حداقل لیسانس حسابداری یا رشته‌های مرتبط<br>سابقه کاری : حداقل 7 سال در زمینه حسابداری مالیاتی<br><br><strong>مهارت تخصصی :</strong><br>تسلط کامل بر قوانین و مقررات مالیاتی<br>مهارت تهیه و تنظیم اظهارنامه‌های قابل دفاع<br>تسلط بر مستندسازی و بایگانی دفاعی<br>توانایی کامل دفاع در رسیدگی مالیاتی<br>تسلط بر حسابداری مالیاتی<br>آشنایی عملی و تسلط کامل بر سامانه‌های مالیاتی<br>مهارت تحلیل ریسک مالیاتی<br>توانایی تعامل حرفه‌ای با ممیز و هیات<br>آشنایی کامل با بیمه و ارتباط آن با مالیات<br><br><strong>ویژگی‌های شخصیتی حیاتی :</strong><br>دقت وسواس‌گونه<br>اخلاق حرفه‌ای و محرمانگی<br>قدرت یادگیری بخشنامه‌های جدید<br>مقاومت در برابر فشار رسیدگی<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه/ بیمه تکمیلی/ پاداش/ وام /ناهار/ هدایای مناسبتی<br><br><strong>سایر مزایا:</strong><br>حقوق و مزایا طبق توافق و شایستگی<br>محیط کاری پویا و حرفه‌ای<br>پرداخت منظم حقوق و مزایا<br>بیمه تامین اجتماعی از روز اول<br>نهار<br>وام پرسنلی<br>محل شرکت: غرب تهران (دسترسی مناسب به مترو و حمل‌ونقل عمومی)<br><br><strong>محل کار:</strong><br>تهران، منطقه ۶، نصرت</p>', NULL, NULL, NULL, NULL, '', '', '<p>.برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 88447203 – 02188447201 حاصل فرمائید.<br>&nbsp;</p>', '7 تا 10 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-31 15:47:57', 'شنبه 11 بهمن', '2026-01-31 12:17:57', '2026-01-31 12:17:57'),
(6849, 1, NULL, 'حسابدار', 'karbarg-public.png', 'لاران صنعت پویا', 'تهران، منطقه ۱، قیطریه', NULL, NULL, '<p>«شرکت مهندسي -بازرگاني لاران صنعت» فعاليت خود را در زمينه خدمات و فروش اقلام هيدروليک و پنوماتيک را در سال 1369 آغاز نموده است. پیرو فعالیت در زمینه های یاد شده شرکت پا به عرصه آسانسور گذاشت و سعی بر این داشت بتواند رسالت خود مبنی بر ارائه اصالت و بهترین کیفیت را در این عرصه هم انجام دهد.<br>تجربه گسترده و مشارکت مداوم با کمپاني هاي جهاني و کادر متخصص شرکت اين امکان را فراهم ساخته تا گستره وسيعي از کاربرها بتوانند با ما ارتباط داشته و از خدمات ما بهره مند شوند.</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>مسلط به اکسل<br>مسلط به امور حسابداری و خزانه<br>تسلط بر خزانه‌داری و صندوق<br>مسلط در صدور اسناد حسابداری انواع رویدادهای مالی<br>تهیه و تحلیل گزارشات مدیریتی و صورت‌های مالی<br>آشنا با سیستم مودیان<br><br><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه 9:15 الی 17 - پنجشنبه‌ها تا 13<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه /بیمه تکمیلی/ پاداش/ وام /هدایای مناسبتی/ فضای استراحت<br><br><strong>سایر مزایا:</strong><br>حقوق ثابت<br>اضافه کاری<br>دسترسی آسان به مترو<br><br><strong>محل کار:</strong><br>تهران، منطقه ۱، قیطریه</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 02138954 حاصل فرمائید.<br>&nbsp;</p>', NULL, NULL, 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-01-31 15:51:28', 'شنبه 11 بهمن', '2026-01-31 12:21:28', '2026-01-31 12:21:28'),
(6850, 1, NULL, 'حسابدار', 'karbarg-public.png', 'صافی ضمیر پلاست', 'خراسان رضوی، مشهد، منطقه ۳، خواجه ربیع', NULL, NULL, '<p>شرکت ما با سابقه‌ای درخشان در تولید انواع ظروف و محصولات بسته‌بندی پلاستیکی، به عنوان تنها تولیدکننده تخصصی در شمال شرق کشور شناخته می‌شود. ما طیف گسترده‌ای از محصولات با کیفیت بالا را از مواد پلی‌پروپیلن (PP)، پلی‌استایرن مقاوم و سبک (HIPS)، پلی‌اتیلن سنگین تزریقی (HDPE) و پلی‌اتیلن سنگین بادی (HDPE Blow) تولید می‌کنیم تا نیازهای صنایع غذایی، لبنی و بسته‌بندی را با بالاترین استانداردها برآورده سازیم.</p>', NULL, NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', '25 تا 30 میلیون تومان', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>توانایی مدیریت بودجه و کنترل هزینه‌ها<br>دقت و توجه به جزئیات در انجام محاسبات مالی<br>مهارت در مدیریت حساب‌ها و پیگیری پرداخت‌ها<br>مهارت در تهیه و تنظیم گزارش‌های مالی<br>توانایی در انجام ترازنامه و مدیریت دارایی‌ها<br>توانایی اجرای کنترل‌های داخلی مالی<br>آشنایی با اصول حسابداری و استانداردهای مالی<br>توانایی کار تیمی و همکاری با دیگر بخش‌ها<br>مهارت در استفاده از نرم‌افزارهای مدیریت مالی<br>مهارت در ارزیابی ریسک‌های مالی<br>آشنایی با قوانین و مقررات مالیاتی<br>موفقیت در حل مسائل مالی پیچیده<br>آشنایی با نرم‌افزار حسابداری (پایا)<br>توانایی تحلیل و تفسیر صورت‌های مالی<br><br><strong>ساعات کاری:</strong><br>7:30 تا 14:30<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه/ سرویس رفت و برگشت<br><br><strong>محل کار:</strong><br>خراسان رضوی، مشهد، منطقه ۳، خواجه ربیع</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 051-32454347-8 حاصل فرمائید.<br>&nbsp;</p>', NULL, NULL, 'آقا', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-02-01 11:48:34', 'یکشنبه 12 بهمن', '2026-02-01 08:18:34', '2026-02-01 08:18:34'),
(6851, 1, NULL, 'حسابدار', 'karbarg-public.png', 'آرامش تجهیز درمان', 'تهران، منطقه ۳، میرداماد', NULL, NULL, '<p>مرکز ایمپلنت آرامش مجموعه‌ای تخصصی در زمینه کاشت و ترمیم دندان است که با بهره‌گیری از جدیدترین تکنولوژی‌های روز ت که با بهره‌گیری از جدیدترین تکنولوژی‌های روز دنیا و همکاری پزشکان مجرب، خدماتی ایمن، دقیق و ماندگار ارائه می‌دهد.</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>صرفا ساکن تهران<br>سن 23 تا 33 سال<br>حداقل 3 سال سابقه کار<br>مسلط به Office به خصوص Excel<br>آشنایی با نرم‌افزار مالی سپیدار<br>آشنایی با اصول و اسناد حسابداری<br>دقیق و منظم، پیگیر و مسئولیت‌پذیر<br>دارای اخلاق حرفه‌ای، توانمند در کار تیمی و امین<br>امکان جذب نیروی دانشجو و پاره‌وقت نیست<br>فاصله کلینیک تا مترو 5 دقیقه است<br><br><strong>وظایف و مسئولیت‌ها:</strong><br>ثبت و کنترل کلیه اسناد مالی (دریافت، پرداخت، خرید، فروش، افتتاحیه، اختتامیه و ...)<br>تهیه و تنظیم گزارش‌های مالی<br>بررسی و کنترل فاکتور‌ها و اسناد حسابداری<br>تهیه صورت مغایرت بانکی و کنترل حساب‌ها<br>آشنایی با امور چک<br>در صورتی که فردی با تجربه، مسئولیت‌پذیر و دارای روحیه کار تیمی هستید، رزومه خود را ارسال نمایید.<br><br><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه 09:00 الی 17:30 - پنج‌شنبه‌ها 09:00 الی 13:30<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه/ پاداش /هدایای مناسبتی/ پزشک سازمانی<br><br><strong>سایر مزایا:</strong><br>پرداخت حقوق به موقع<br>محیطی آرام و سالم، صمیمانه، پویا، مناسب خانم‌ها<br>تخفیف خدمات دندانپزشکی برای شما و خانواده درجه یک<br>آموزش‌های تخصصی مورد نیاز حین کار (امور آموزش رایگان است)<br><br><strong>محل کار:</strong><br>تهران، منطقه ۳، میرداماد</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس۰۲۱۹۱۰۰۶۶۶۱ / 09125142254 حاصل فرمائید.<br>&nbsp;</p>', '3 سال و کمتر', '33', 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-02-01 11:51:07', 'یکشنبه 12 بهمن',