(6852, 1, NULL, 'سرپرست حسابداری', 'karbarg-public.png', 'به سازان صادق پارسا', 'استان تهران، شهر جدید اندیشه', NULL, NULL, '<p>شرکت بهسازان صادق پارسا در سال ۱۳۸۹ به جهت کمک به عمران و آباداني کشور تأسيس و در طي اين مدت در رشته هاي راه ،ابنيه و تأسيسات فعاليت موثر و مستمر داشته و پروژه هاي مختلف را با موفقيت به بهره برداري رسانيده است تا علاوه بر ايجاد اشتغال، سهم بسزايي در توسعه راهها و عمران و آباداني کشور داشته باشد</p><p>&nbsp;</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '40 تا 45 میلیون تومان', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>دارای حداقل مدرک کارشناسی و یا کارشناسی ارشد در رشته های حسابداری، مدیریت مالی و اقتصاد.<br>دارای 7 سال تجربه در حوزه مالی و حسابداری که حداقل 3سال آن در سمت رئیس حسابداری بوده باشد.<br>آشنایی با روشها و استانداردهای حسابداری و همچنین تجربه کاری در شرکتهای پیمانکاری اولویت محسوب میگردد.<br>تسلط بر نرم افزارهای حسابداری و همچنین excel Microsoft و Word و غیره.<br>تسلط کامل بر فرایندهای تنظیم بودجه سالیانه و پیش بینی مالی و همچنین انواع گزارشات مالی مورد نیاز مدیریت.<br>آشنایی کامل با انواع اظهارنامه های مالیاتی، سامانه مودیان، مالیاتهای تکلیفی و همچنین فرایند رسیدگی و دادرسی<br>مالیاتی در ارتباط با پرونده های عملکرد و ارزش افزوده و حضور در هیئتهای مربوطه.<br>آشنایی با قوانین بیمه تامین اجتماعی در امور پیمانکاری و قوانین کار و بخشنامه های مربوطه. تسلط بر نرم افزارهای مالی و حسابداری.<br>آشنایی کامل با تهیه صورتهای مالی سالیانه طبق استانداردهای حسابداری و ارائه آن به حسابرسان مستقل.<br>تسلط بر روشها و استانداردهای حسابداری در ارتباط با امور خزانه، انبار، خرید و فروش، حقوق و دستمزد، کنترل اسناد و همچنین ثبت و ضبط بموقع رویدادهای مالی در حسابهای مربوطه.<br>توانایی در کار تیمی، داشتن تعهد و مسئولیت پذیری، دقیق و قابل اعتماد.<br><br><strong>ساعات کاری:</strong><br>8 الی 17<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه/ پاداش/ ناهار /هدایای مناسبتی<br><br><strong>محل کار:</strong><br>استان تهران، شهر جدید اندیشه</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 021-65547865 حاصل فرمائید.<br>&nbsp;</p>', '3 سال و کمتر', NULL, 'مهم نیست', 'کارشناسی', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-02-01 11:53:13', 'یکشنبه 12 بهمن', '2026-02-01 08:23:13', '2026-02-01 08:23:13'),
(6853, 1, NULL, 'حسابدار', 'karbarg-public.png', 'مرمر بتن', 'استان خراسان رضوی، شهرک صنعتی کاویان', NULL, NULL, '<p>ساخت سایرمحصولات کانی غیرفلزی طبقه بندی نشده درجای دیگر</p>', NULL, NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', '25 تا 30 میلیون تومان', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>مدرک معتبر<br>حداقل 5 سال سابقه مرتبط<br><br><strong>ساعات کاری:</strong><br>7 الی 16<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه/ ناهار/سرویس رفت و برگشت<br><br><strong>محل کار:</strong><br>استان خراسان رضوی، شهرک صنعتی کاویان</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس ۰۹۳۷۰۹۳۷۷۲۹ &nbsp;حاصل فرمائید.<br>&nbsp;</p>', 'حداقل 5 سال', NULL, 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-02-01 11:56:24', 'یکشنبه 12 بهمن', '2026-02-01 08:26:24', '2026-02-01 08:26:24'),
(6854, 1, NULL, 'کمک حسابدار', 'karbarg-public.png', 'گروه صنعتی بازرگانی لبفا', 'تهران، منطقه ۱۱، قلمستان', NULL, NULL, '<p>به عقیده من داستان شکل گیری لبفا یک داستان هیجان انگیز است.<br>من هم مثل بقیه بعد از دانشگاه به خدمت سربازی رفتم و بعد از اتمام دوران خدمت باید وارد بازار کار می شدم.مثل بسیاری از پسران من هم در بازار کار پدرم مشغول به کار شدم.پدرم سال ها در بازار اصلی موتور سیکلت و دوچرخه پایتخت ایران مشغول به کار بود و اعتبار و تجربه او در این بازار می توانست راهگشای من باشد.<br>من کارم را با فروش ماشین های شارژی شروع کردم.در ابتدای کار یک مغازه ۹ متری داشتم که ماشین شارژی ها به خاطر ابعاد بزرگش سخت در مغازه جا میگرفت.از طرف دیگر به دنبال محصولی بودم که با توجه به وضعیت اقتصادی ایران بچه های بیشتری بتوانند از آن استفاده کنند و البته همیشه میترسیدم که ماشین شارژی های ما بچه های نسل آینده ایران را تنبل کند. این شد که ذهنم به سمت واردات اسکوتر رفت.در آن زمان اسکوتر کمتر در بین مردم شناخته شده بود . اسکوتر محصولی بود که هم می توانست در مغازه کوچک من جای بگیرد و هم به خاطر قیمت می توانست جامعه بیشتری از کودکان را خوشحال کند.بازی با اسکوتر نوعی ورزش بوده و هست. بدین شکل \"لبفا\" متولد شد.</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '20 تا 25 میلیون تومان', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>آشنایی با نرم افزارهای مالی و اصول حسابداری<br>متعهد و با انگیزه<br>روحیه کار گروهی<br>دقت و توجه به جزئیات<br>داشتن میل به پیشرفت و یادگیری<br>اخلاق حرفه‌ای بالا<br>شرایط سنی از 22 تا 26 سال<br><br><strong>اولویت استخدام:</strong><br>آشنایی با نرم افزار حسابداری سپیدار<br>آشنایی با اکسل<br>فارغ التحصیل رشته حسابداری (کارشناسی و بالاتر )<br>در صورتی که خودتان مناسب این موقعیت نیستید، خوشحال می‌شویم این آگهی را با دوستان حسابدار خود به اشتراک بگذارید.<br><br><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه 9 الی 18 و پنجشنبه‌ها تعطیل<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه /پاداش /هدایای مناسبتی<br><br><strong>سایر مزایا:</strong><br>پنجشنبه‌ها تعطیل — فرصتی برای خانواده و استراحت!<br>حقوق منصفانه و توافقی<br>بیمه<br>مزایای تکمیلی<br>محیط کاری آرام، حرفه‌ای و مبتنی بر احترام متقابل<br><br><strong>محل کار:</strong><br>تهران، منطقه ۱۱، قلمستان</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس ۰۹۹۶۶۱۵۹۸۱۱ حاصل فرمائید.<br>&nbsp;</p>', NULL, '26', 'مهم نیست', 'کارشناسی', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-02-01 11:58:55', 'یکشنبه 12 بهمن', '2026-02-01 08:28:55', '2026-02-01 08:28:55'),
(6855, 1, NULL, 'حسابدار', 'karbarg-public.png', 'گروه نرم افزار حسابداری سیبا', 'خراسان رضوی، مشهد، منطقه ۱۱، آزادشهر', NULL, NULL, '<p>در دنیای امروز که کسب‌وکارها با چالش‌های پیچیده‌تری روبه‌رو هستند، وجود ابزارهای هوشمند و ساده برای مدیریت مالی، دیگر یک انتخاب نیست، بلکه یک ضرورت است. از همین نیاز بود که سیبا متولد شد؛ با هدف ارائه راه‌حلی بومی، دقیق و قابل اعتماد برای صاحبان مشاغل ایرانی.</p>', NULL, NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>آشنایی با قوانین امور بیمه و مالیات کشور<br>آشنایی با قوانین و نحوه محاسبه حقوق و دستمزد<br>اطلاع از قوانین بانکی<br>تسلط بر مفاهیم و اصول حسابداری<br>تسلط بر نرم‌افزارهای مالی و حسابداری<br>مدیریت مالی و تحلیل داده‌ها<br><br><strong>وظایف و مسئولیت‌ها:</strong><br>ثبت و پردازش اسناد مالی<br>نظارت بر حساب های پرداختنی و دریافتنی<br>تهیه و تنظیم گزارش های مالی دوره ای<br>تهیه گزارش های مالی مانند ترازنامه و سود زیان<br>کنترل و نظارت بر هزینه ها و اجرای بودجه<br>تهیه و ارسال اظهارنامه های مالیاتی<br>تنظیم فیش های حقوقی و پرداخت حقوق<br>محاسبه بیمه تامین اجتماعی و رد کردن لیست بیمه<br>انجام امور مربوط به حساب های بانکی، پرداخت ها و دریافت ها<br>همکاری با حسابرسان و سازمان‌های مالی<br>کار با نرم افزارهای حسابداری و مالی برای ثبت و پردازش داده ها<br>بهبود سیستم مالی و حسابداری سازمان<br><br><strong>محل کار:</strong><br>خراسان رضوی، مشهد، منطقه ۱۱، آزادشهر</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 051-31676 | &nbsp;051-91005130 حاصل فرمائید.<br>&nbsp;</p>', NULL, NULL, 'خانم', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-02-01 12:02:02', 'یکشنبه 12 بهمن', '2026-02-01 08:32:02', '2026-02-01 08:32:02'),
(6856, 1, NULL, 'حسابدار', 'karbarg-public.png', 'اطلس طلایی ایرانیان پویا', 'استان البرز، گرمدره', NULL, NULL, '<p>از آنجایی که شما مهمترین و تاثیرگذارترین افراد در راستای تحقق اهداف سازمان اطلس طلایی محسوب می شوید لذا سخن مان را با “درباره شما” شروع می کنیم: زیرا شما هستید که ما هستیم و حمایتها و پشتیبانی های شما موجب رشد و رونق این مجموعه و دلگرمی و پیشرفت ما می باشد. نام مشتری زیباترین و دلنشین ترین آهنگ مجموعه ما می باشد. شما سرمایه و اعتبار ما هستید و ما به وجود گرم شما افتخار می کنیم و در جای جای میهن پهناورمان به پشتوانه شما سعی بر خدمتگذاری به تمام ایرانیان عزیز را داریم. شما امروز مهمترین تاثیر را در رشد و شکوفایی کشور عزیزمان داشته اید زیرا به برکت وجود و حمایتهای شما خانواده های زیادی بصورت مستقیم و غیر مستقیم بر سر سفره پربرکت اطلس طلایی ایرانیان پویا نشسته اند. هر چه بخواهیم از بزرگی و ارزش شما بنویسیم زبانمان قاصر است لذا خواستار این هستیم که تشکر و سپاس صمیمانه ما را پذیرا باشید.</p>', NULL, NULL, '283', 'کرج', '5', 'البرز', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>تنظیم و بررسی قراردادهای کاری کارکنان<br>پیگیری و ثبت اطلاعات پرسنلی و سوابق کاری<br>تسلط به سیستم‌های محاسبات حقوق و دستمزد<br>تسلط به محاسبه و ضوابط پرداخت پورسانت‌ها بر اساس عملکرد و فروش<br>نظارت بر ساعت کار، اضافه‌کار و سایر مزایا<br>تسلط بر امور بیمه و مالیات کارکنان<br>ارزیابی و تنظیم گزارش‌های ماهانه حقوق و دستمزد<br><br><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه 8 الی 17 - پنجشنبه‌ها 8 الی 13<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه/ بیمه تکمیلی /هدایای مناسبتی/ کمک هزینه آموزشی<br><br><strong>محل کار:</strong><br>استان البرز، گرمدره<br>&nbsp;</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 026-32120 حاصل فرمائید.<br>&nbsp;</p>', NULL, NULL, 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-02-01 12:09:45', 'یکشنبه 12 بهمن', '2026-02-01 08:39:45', '2026-02-01 08:39:45'),
(6857, 1, NULL, 'حسابدار', 'karbarg-public.png', 'مهتا توس', 'مشهد، جاده سنتو، بعد از پل گلبهار و جاده سرآسیاب، حاشیه جاده سمت راست', NULL, NULL, '<p>&nbsp;صنایع نساجی مهتاتوس با هدف تولید انواع نخ و بافت انواع پارچه، در سال 1358 آغاز به کار نمود و در ادامه، ضمن توسعه فعالیت ها، با ایجاد کارخانه رنگرزی و راه اندازی خطوط تولید پوشاک، به مجموعه ای فاخر در صنعت نساجی و پوشاک کشور تبدیل شده است.<br>مهتاتوس با استفاده از سیستم های نوین مدیریتی و بهره گیری از مهندسان نساجی و تکنسین های فنی، ضمن بهره مندی از نظام جامع پیشنهادات، واحد تحقیق و توسعه و آزمایشگاه مدرن کنترل کیفی، در پی آن است تا رسالت سازمانی خویش را در راستای ارتقای کیفی محصولات ایرانی برای رقابت با تولیدکنندگان خارجی ایفا نموده و رضایت بیش از پیش مشتریان را کسب نماید.</p>', NULL, NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>آشنایی با اصول و استانداردهای حسابداری<br>آشنایی با نرم‌افزارهای حسابداری<br>دقت و توجه به جزئیات<br>مهارت در تهیه گزارش‌های مالی<br>سابقه کار در انبار و حسابداری انبار<br>محل سکونت حتما در گلبهار یا چناران<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه<br><br><strong>سایر مزایا:</strong><br>بیمه<br>بیمه درمان<br><br><strong>محل کار:</strong><br>مشهد، جاده سنتو، بعد از پل گلبهار و جاده سرآسیاب، حاشیه جاده سمت راست</p>', NULL, NULL, NULL, NULL, '', '', '<p>.برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 09912284492 حاصل فرمائید.<br>&nbsp;</p>', NULL, NULL, 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-02-01 12:16:59', 'یکشنبه 12 بهمن', '2026-02-01 08:46:59', '2026-02-01 08:46:59'),
(6858, 1, NULL, 'حسابدار', 'karbarg-public.png', 'ذوب و نورد خلیج فارس', 'تهران، منطقه ۳، جردن', NULL, NULL, '<p>شرکت ذوب و نورد خلیج فارس یکی از مجموعه‌های مهم در صنعت فولاد ایران است که نقش بسزایی در تأمین نیاز‌های داخلی و بازار‌های صادراتی ایفا می‌کند. این شرکت با بهره‌گیری از فناوری‌های پیشرفته و استاندارد‌های بین‌المللی، تولید محصولات فولادی باکیفیت را در دستور کار خود قرار داده است. موقعیت استراتژیک، ظرفیت تولید بالا و تنوع محصولات از جمله عواملی هستند که این مجموعه را به یکی از بازیگران کلیدی در صنعت فولاد کشور تبدیل کرده‌اند. در این مقاله به بررسی تاریخچه، محصولات، فرایند‌های تولید و جایگاه این شرکت در بازار فولاد ایران خواهیم پرداخت.</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>آشنایی با اصول و مفاهیم حسابداری<br>مسلط به اکسل<br>توانایی مغایرت گیری حساب<br>توانایی کار به صورت تیمی<br>مسئولیت پذیر و دقیق<br>حداکثر سن 35 سال<br>دارای کارت پایان خدمت<br><br><strong>ساعات کاری:</strong><br>شنبه الی چهارشنبه از ساعت 09:00 الی 17:00 پنجشنبه 09:00 الی 13:00<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه<br><br><strong>سایر مزایا:</strong><br>بیمه از روز اول همکاری<br><br><strong>محل کار:</strong><br>تهران، منطقه ۳، جردن</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 02425284041 حاصل فرمائید.<br>&nbsp;</p>', NULL, '35', 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-02-01 12:20:16', 'یکشنبه 12 بهمن', '2026-02-01 08:50:16', '2026-02-01 08:50:16'),
(6859, 1, NULL, 'کمک حسابدار', 'karbarg-public.png', 'نرم‌افزار حسابداری تیپ', 'تهران، منطقه ۲، توحید،ستارخان، جنب پمپ بنزین بهبودی، پلاک 168، واحد 6', NULL, NULL, '<p>گروه شرکتهای کوشا کاربرگ تاسیس ۱۳۸۷ (سهامی خاص) پس از سال ها فعالیت در زمینه خدمات مالی و حسابداری و در نتیجه شناسایی و واکاوی نیازهای مدیران شرکتها و کارخانجات و صاحبان مشاغل بنگاههای اقتصادی درخصوص فرایندهای حسابداری مدیریت و جلوگیری از خطاهای احتمالی در محاسبات توسط کاربران از سال ۹۱ اقدام به طراحی و تهیه نرم افزار حسابداری یکپارچه و جامعی نمود که در آبان ماه ۹۷ به پایان رسید. نرم افزار طی سال ۹۷ و ۹۸ &nbsp;مراحل تست عملی و فشار کاری خود را با موفقیت پشت سر نهاد و از آن به بعد به بهره‌برداری تجاری رسید. به منظور بهبود مشکلات و رفع کمبود نرم افزارهای موجود در بازار از ایده ها و مشاوره کارشناسان حسابداری مطرح کشور استفاده و در نتیجه نرم افزار حسابداری تیپ طراحی شد. به منظور ارائه و فروش نرم افزار خود شرکتی را در سال ۹۵ به نام تراز ایده پرداز در اداره ثبت شرکتهای تهران در شهر تهران تحت شماره ۵۰۴۶۰۷ به ثبت رسانید و اولین محصول نرم افزاری خود را با نام اختصاری تیپ (TIP) ارائه نمود.&nbsp;</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>به تعدادی کارآموز خانم و آقا به صورت تمام وقت نیازمندیم.<br>کارآموزان تمام وقت در اولویت می‌باشند.<br>فارغ‌التحصیلان با معدل بالاتر در اولویت انتخاب می‌باشند.<br>آشنایی با اکسل<br>آشنایی با اصول و مفاهیم حسابداری<br>توانایی کار تیمی<br>دقت بالا<br>خوش برخورد و خوش اخلاق<br>گواهی سابقه کار پس از اتمام دوره کارآموزی<br><br><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه 8 الی 17:15 - پنجشنبه‌ها 8 الی 13<br><br><strong>محل کار:</strong><br>تهران، منطقه ۲، توحید،ستارخان، جنب پمپ بنزین بهبودی، پلاک 168، واحد 6</p>', NULL, NULL, NULL, NULL, '', '', '<p>.برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس ۰۹۳۰۰۵۳۵۶۸۵ حاصل فرمائید.<br>&nbsp;</p>', NULL, NULL, 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-02-01 12:22:42', 'یکشنبه 12 بهمن', '2026-02-01 08:52:42', '2026-02-01 08:52:42'),
(6860, 1, NULL, 'حسابرس', 'karbarg-public.png', 'گروه صنعتی زر', 'استان البرز ، کرج ، چهارباغ، خیابان صنعت 5(مرغک)، کارخانه زرماکارون', NULL, NULL, '<p><span style=\"color:rgb(15,23,42);\">گروه زر با اتکا بر تجربه خود، دانش جهانی و بومی در حوزه‌های تولید، توسعه محصول، بازرگانی، خدماتی، سرمایه‌گذاری و... با رویکرد کارآفرینی مبتنی بر دانش، نوآوری و با تخصص در کسب و کارهای B2B و B2C در پاسخ به نیازهای جامعه و ارزش‌آفرینی، فعالیت می‌نماید. هدف نهایی گروه زر، ورود به صنعت‌های جدید جهت بهبود سبک و کیفیت زندگی جامعه بشری است.</span></p>', NULL, NULL, '283', 'کرج', '5', 'البرز', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>دارای مدرک تحصیلی کارشناسی حسابداری<br>سن: حداکثر 30<br>تسلط به نرم افزارهای مالی و Excel و Word و SAP<br>وظایف و مسئولیت‌ها<br>اجرای آزمون های کنترل تحت نظارت سرپرست حسابرسی<br>تهیه گزارش های حسابرسی اولیه<br>همکاری با سایر اعضای تیم حسابرسی در انجام ماموریت‌ها<br>پیگیری اجرای پیشنهادات ارائه شده در گزارش های حسابرسی<br>ارائه گزارش های دوره ای به سرپرست<br>نظارت بر انبارگردانی<br>نظارت بر شمارش صندوق<br>شایستگی های رفتاری<br>آشنایی کامل با اصول اقتصاد و حسابداری<br>توانایی کار تیمی و حل مسئله و توجه به جزییات<br>مدیریت زمان و اولویت‌بندی<br>با دقت ، منظم و پیگیر<br>قابل اعتماد و امین<br>آشنایی نسبی با قوانین حقوقی مرتبط<br><br><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه 8 الی 17( پنجشنبه ها در صورت نیاز اضافه کاری)<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه/بیمه تکمیلی /ناهار /سرویس رفت و برگشت /هدایای مناسبتی /پزشک سازمانی<br><br><strong>محل کار:</strong><br>استان البرز ، کرج ، چهارباغ، خیابان صنعت 5(مرغک)، کارخانه زرماکارون</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس ۰۲۶۴۳۲۱۲۰۰۰ حاصل فرمائید.<br>&nbsp;</p>', 'نیاز نیست', '30', 'مهم نیست', 'کارشناسی', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-02-01 12:28:15', 'یکشنبه 12 بهمن', '2026-02-01 08:58:15', '2026-02-01 08:58:15'),
(6861, 1, NULL, 'حسابدار', 'karbarg-public.png', 'کشت و صنعت آوین دشت', 'تهران، منطقه ۶، بلوار کشاورز', NULL, NULL, '<p>شرکت کشت و صنعت آوین دشت در 22 کیلومتری جنوب غربی شهرستان تاکستان و در حاشیه جاده آسفالته خرمدشت به ضیاء آباد و در 30 کیلومتری شهر ابهر واقع شده است. کشت و صنعت آوین دشت در سال 1381 با هدف ایجاد یک مجموعه بزرگ تولیدی شیر و گوشت در منطقه ای محروم و در محدوده ای دیوارکشی شده به وسعت 40 هکتار راه اندازی شده است.<br>&nbsp;</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>متعهد و مسئولیت‌پذیر<br>با حداقل 2 تا 3 سال سابقه کار<br>دارای روحیه تیمی و با هوش<br>مسلط به امور بانکی، خزانه داری و پرداخت<br>مسلط به اکسل<br><br><strong>ساعات کاری:</strong><br>8 الی 17<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه<br><br><strong>محل کار:</strong><br>تهران، منطقه ۶، بلوار کشاورز</p>', NULL, NULL, NULL, NULL, '', '', '<p>.برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس 88959086-88959087 (021) حاصل فرمائید.<br>&nbsp;</p>', '3 سال و کمتر', NULL, 'خانم', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-02-01 12:30:13', 'یکشنبه 12 بهمن', '2026-02-01 09:00:13', '2026-02-01 09:00:13'),
(6862, 1, NULL, 'حسابدار', 'karbarg-public.png', 'شرکت نیلا پخش بردیا', 'تهران، منطقه ۹، سرآسیاب مهرآباد', NULL, NULL, '<p>شرکت نیلا پخش بردیا، عضو گروه شرکت‌های میعاد، در سال ۱۳۹۶ با هدف توزیع اختصاصی محصولات غذایی تأسیس شد. گروه مواد غذایی میعاد، که از سال ۱۹۷۸ فعالیت خود را آغاز کرده، همواره بر ارائه محصولات باکیفیت و در دسترس تأکید داشته است. نیلا پخش بردیا با بهره‌گیری از تجربه میعاد، نقش مهمی در زنجیره تأمین و توزیع مواد غذایی ایفا می‌کند.</p>', NULL, NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>مسلط به نرم‌افزار Excel<br>2 سال سابقه کار در سمت مشابه<br>حداقل مدرک تحصیلی کارشناسی حسابداری<br>متقاضیان نزدیک به محدوده شرکت رزومه خود را ارسال نمایند.<br><br><strong>ساعات کاری:</strong><br>شنبه تا چهارشنبه 8 الی 17 - پنجشنبه‌ها 8 الی 12<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه /پاداش/ هدایای مناسبتی/ کمک هزینه آموزشی<br><br><strong>سایر مزایا:</strong><br>بیمه از روز اول<br>حقوق توافقی<br>حق جذب<br>محیط کاری امن و آرام<br>بسته‌های مناسبتی و تشویقی<br><br><strong>محل کار:</strong><br>تهران، منطقه ۹، سرآسیاب مهرآباد</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس02167485000 حاصل فرمائید.<br>&nbsp;</p>', '2 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-02-01 12:34:36', 'یکشنبه 12 بهمن', '2026-02-01 09:04:36', '2026-02-01 09:04:36'),
(6863, 1, NULL, 'حسابدار', 'karbarg-public.png', 'کاشی و سرامیک مرادبیگی', 'استان البرز ، قزلحصار، نبش میثم یک', NULL, NULL, '<p>مفتخریم که با 15 سال سابقه فعالیت در زمینه پخش و توزیع کاشی، سرامیک، گرانیت، شیرآلات، چینی آلات بهداشتی، مصالح ساختمانی، هود، سینک و گاز در سطح استان البرز(کرج) و تهران، به لطف پروردگار و با تکیه بر شعار \"زیبا، بادوام، مقرون به صرفه\" و نیز به کارگیری تجربه و پشتکار کادر پرسنلی توانمند خود، همواره سعی داشته ایم بیش از پیش رضایت بازدید کنندگان، مشتریان گرامی و همچنین همکاران عزیز را جلب نماییم.</p>', NULL, NULL, '283', 'کرج', '5', 'البرز', 'تمام وقت', 'توافقی', NULL, NULL, NULL, '<p><strong>شرایط احراز:</strong><br>آشنایی با نرم‌افزارهای حسابداری<br>آشنایی با اصول حسابداری فروش<br>دقت بالا و توجه به جزئیات<br>مسئولیت‌پذیری و توانایی کار تیمی<br>آشنایی با مفاهیم مالی<br>توانایی تحلیل داده ها<br>آشنایی با امور مالیاتی و بیمه تامین اجتماعی<br>رزومه خود را داخل واتس اپ ارسال نمایید<br><br><strong>ساعات کاری:</strong><br>شنبه تا پنجشنبه 8 تا 17 و تعطیلات 8 تا 13<br><br><strong>تسهیلات و مزایا:</strong><br>بیمه /میان‌وعده/ ساعات کاری منعطف /هدایای مناسبتی/ فضای استراحت<br><br><strong>محل کار:</strong><br>استان البرز ، قزلحصار، نبش میثم یک</p>', NULL, NULL, NULL, NULL, '', '', '<p>برای اطلاعات بیشتر دررابطه با نحوه همکاری و یا ارسال رزومه با &nbsp;شماره تماس ۰۹۱۲۵۶۰۲۰۵۰ حاصل فرمائید.<br>&nbsp;</p>', NULL, NULL, 'مهم نیست', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 'karbarg-public', 1, 0, 1, 1, 0, '2026-02-01 12:39:02', 'یکشنبه 12 بهمن', '2026-02-01 09:09:02', '2026-02-01 09:09:02'),
(6864, 1073, 1183, 'حسابدار', NULL, 'راین رویش ماندگار', NULL, NULL, NULL, NULL, '09127470093', NULL, '117', 'تهران', '8', 'تهران', 'تمام وقت', '20 تا 25 میلیون تومان', 5, 'بیمه,صبحانه', NULL, '<p>شرایط احراز:</p><p>ما به‌دنبال حسابداری با سابقه کم اما باهوش و آینده‌دار هستیم که ویژگی‌های زیر را داشته باشد:</p><p>دقت بالا و حساسیت به جزئیات</p><p>منظم و مسئولیت‌پذیر</p><p>متعهد به انجام کامل امور و عدم رها کردن کارها به‌صورت نیمه‌تمام</p><p>پرانرژی، پرتلاش و علاقه‌مند به یادگیری سریع</p><p>علاقه‌مند به فعالیت در محیطی حرفه‌ای و رو‌به‌رشد</p><p>اگر به‌دنبال پیشرفت شغلی هستید و دوست دارید قدم‌به‌قدم به سطوح بالاتر حرفه‌ای برسید، این موقعیت شغلی می‌تواند فرصت مناسبی برای شما باشد.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '3 سال و کمتر', NULL, 'مهم نیست', 'کارشناسی', NULL, 'راهکاران', 'خوب', 'متوسط', 'متوسط', 'کم', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 1, 0, 1, 1, 0, NULL, NULL, '2026-02-01 10:23:28', '2026-02-01 10:58:40'),
(6865, 858, 1184, 'سرپرست حسابداری', NULL, 'مهند', NULL, NULL, NULL, NULL, '09155119470', NULL, '153', 'مشهد', '11', 'خراسان رضوی', 'تمام وقت', 'قانون کار', 0, 'بیمه,پاداش و هدایا,وام سازمانی', NULL, '<p>استخدام حسابدار در شرکت تولیدی<br>یک شرکت تولیدی معتبر با سابقه 40 سال جهت تکمیل و ارتقا تیم مالی خود استخدام مینماید.</p><p>*وظایف و مسئولیت‌ها:<br>- ثبت و کنترل اسناد مالی، تهیه گزارش‌های دوره ای<br>- انجام امور مالیاتی، بیمه و پاسخگویی به حسابرسان مستقل<br>- همکاری با واحد تولید و انبار برای کنترل بهای تمام‌شده و موجودی ها</p><p>- تهیه گزارش‌های مدیریتی و تحلیلی</p><p>*اولویت های احراز:<br>- مدرک کارشناسی حسابداری یا رشته‌های مرتبط<br>- حداقل یک سال سابقه کار مفید، ترجیحاً در حسابداری تولیدی یا مالیاتی<br>- تسلط به Excel و آشنایی با نرم‌افزارهای پایا و Odoo ERP<br>- مهارت‌های ارتباطی، کار تیمی و توانایی حل مسئله<br>- تعهد به یادگیری مستمر و رعایت اصول اخلاقی و محرمانگی<br>- داشتن روحیه خوداصلاحی و ارائه گزارش‌های منظم و دقیق</p><p>*مزایا:<br>- حقوق و مزایای پایه بر اساس قانون کار است (برای افراد باتجربه تر و دارای مهارت سرپرستی، تا &nbsp;30 میلیون تومان، قابل پرداخت خواهد بود)<br>- ارزیابی عملکرد دوره ای و امکان پیشرفت در یک محیط پویا<br>- پرداخت منظم حقوق و امکان اضافه‌کار با ضریب ۲۱۰٪<br>- محیط کاری مثبت و فرصـت‌های آموزشی<br>- زمان صبحانه و ناهار متعارف، در صورت فعالیت در دفتر شهر، از زمان حضور شما کاسته نخواهد شد.<br>شماره تماس:<br>09159156297</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '1 سال', NULL, 'مهم نیست', 'کارشناسی', NULL, 'پایا', 'خیلی خوب', 'خوب', 'خیلی خوب', 'عالی', NULL, NULL, '', NULL, NULL, NULL, 0, 'employer', 0, 0, 1, 1, 0, NULL, NULL, '2026-02-02 07:32:47', '2026-02-02 07:32:47'),
